#[derive(Debug, Clone, Copy, Deserialize, Serialize, PartialEq, Eq)]
#[serde(rename_all = "kebab-case")]
pub enum AuthoringLoopEvidenceBundleArtifactKind {
    LoopPlan,
    StepOutput,
    Run,
    Comparison,
    Proposal,
    ReviewDecision,
    Transaction,
    RegressionPromotion,
    MatrixSnapshot,
    JournalSummary,
}

impl AuthoringLoopEvidenceBundleStatus {
    pub fn as_str(self) -> &'static str {
        match self {
            AuthoringLoopEvidenceBundleStatus::Completed => "completed",
            AuthoringLoopEvidenceBundleStatus::Partial => "partial",
            AuthoringLoopEvidenceBundleStatus::Failed => "failed",
        }
    }
}

impl AuthoringLoopEvidenceBundle {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let bundle: AuthoringLoopEvidenceBundle = serde_json::from_str(input)
            .context("failed to parse Authoring Loop Evidence Bundle JSON")?;
        bundle.validate_schema()?;
        Ok(bundle)
    }

    pub fn from_json_str_with_base(input: &str, base_dir: impl AsRef<Path>) -> Result<Self> {
        let bundle = Self::from_json_str(input)?;
        bundle.validate_references(base_dir)?;
        Ok(bundle)
    }

    pub fn validate_schema(&self) -> Result<()> {
        if self.schema_version != AUTHORING_LOOP_EVIDENCE_BUNDLE_SCHEMA_VERSION {
            return Err(anyhow!(
                "authoring loop evidence bundle schemaVersion must be {AUTHORING_LOOP_EVIDENCE_BUNDLE_SCHEMA_VERSION}"
            ));
        }
        validate_path_component("authoring loop evidence bundle loopId", &self.loop_id)?;
        require_text("authoring loop evidence bundle boundary", &self.boundary)?;
        self.generated_state.validate()?;
        for (index, missing_ref) in self.missing_refs.iter().enumerate() {
            require_text(
                &format!("authoring loop evidence bundle missingRefs[{index}]"),
                missing_ref,
            )?;
        }

        let mut ids = BTreeSet::new();
        self.plan.validate(
            "authoring loop evidence bundle plan",
            &self.generated_state.roots,
            &mut ids,
        )?;
        self.validate_refs("authoring loop evidence bundle runs", &self.runs, &mut ids)?;
        self.validate_refs(
            "authoring loop evidence bundle comparisons",
            &self.comparisons,
            &mut ids,
        )?;
        self.validate_refs(
            "authoring loop evidence bundle proposals",
            &self.proposals,
            &mut ids,
        )?;
        self.validate_refs(
            "authoring loop evidence bundle reviewDecisions",
            &self.review_decisions,
            &mut ids,
        )?;
        self.validate_refs(
            "authoring loop evidence bundle transactions",
            &self.transactions,
            &mut ids,
        )?;
        self.validate_refs(
            "authoring loop evidence bundle regressionPromotions",
            &self.regression_promotions,
            &mut ids,
        )?;
        self.validate_refs(
            "authoring loop evidence bundle matrixSnapshots",
            &self.matrix_snapshots,
            &mut ids,
        )?;
        self.validate_refs(
            "authoring loop evidence bundle journalSummaries",
            &self.journal_summaries,
            &mut ids,
        )?;
        for (index, step) in self.steps.iter().enumerate() {
            step.validate(index, &self.generated_state.roots, &mut ids)?;
        }
        if self.status == AuthoringLoopEvidenceBundleStatus::Completed
            && !self.missing_refs.is_empty()
        {
            return Err(anyhow!(
                "completed authoring loop evidence bundle must not include missingRefs"
            ));
        }
        if self.status == AuthoringLoopEvidenceBundleStatus::Completed
            && self.steps.iter().any(|step| !step.missing_refs.is_empty())
        {
            return Err(anyhow!(
                "completed authoring loop evidence bundle must not include step missingRefs"
            ));
        }
        Ok(())
    }

    pub fn validate_references(&self, base_dir: impl AsRef<Path>) -> Result<()> {
        self.validate_schema()?;
        let base_dir = base_dir.as_ref();
        let known_missing_paths = self.known_missing_paths();
        let missing = self
            .all_artifact_refs()
            .into_iter()
            .filter(|artifact| {
                !known_missing_paths.contains(&artifact.path)
                    && !base_dir.join(&artifact.path).exists()
            })
            .map(|artifact| format!("{}:{}", artifact.id, artifact.path))
            .collect::<Vec<_>>();
        if missing.is_empty() {
            Ok(())
        } else {
            Err(anyhow!(
                "stale authoring loop evidence bundle references: {}",
                missing.join(", ")
            ))
        }
    }

    fn known_missing_paths(&self) -> BTreeSet<String> {
        let mut paths = BTreeSet::new();
        for missing_ref in self
            .missing_refs
            .iter()
            .chain(self.steps.iter().flat_map(|step| step.missing_refs.iter()))
        {
            if let Some((_, path)) = missing_ref.split_once(':') {
                paths.insert(path.to_string());
            }
        }
        paths
    }

    fn validate_refs(
        &self,
        field: &str,
        refs: &[AuthoringLoopEvidenceBundleArtifactRef],
        ids: &mut BTreeSet<String>,
    ) -> Result<()> {
        for (index, artifact) in refs.iter().enumerate() {
            artifact.validate(
                &format!("{field}[{index}]"),
                &self.generated_state.roots,
                ids,
            )?;
        }
        Ok(())
    }

    fn all_artifact_refs(&self) -> Vec<&AuthoringLoopEvidenceBundleArtifactRef> {
        let mut refs = vec![&self.plan];
        refs.extend(self.runs.iter());
        refs.extend(self.comparisons.iter());
        refs.extend(self.proposals.iter());
        refs.extend(self.review_decisions.iter());
        refs.extend(self.transactions.iter());
        refs.extend(self.regression_promotions.iter());
        refs.extend(self.matrix_snapshots.iter());
        refs.extend(self.journal_summaries.iter());
        for step in &self.steps {
            refs.extend(step.outputs.iter());
        }
        refs
    }
}

impl AuthoringLoopEvidenceBundleStep {
    fn validate(
        &self,
        index: usize,
        generated_roots: &[String],
        ids: &mut BTreeSet<String>,
    ) -> Result<()> {
        validate_path_component(
            &format!("authoring loop evidence bundle steps[{index}].stepId"),
            &self.step_id,
        )?;
        require_text(
            &format!("authoring loop evidence bundle steps[{index}].kind"),
            &self.kind,
        )?;
        require_text(
            &format!("authoring loop evidence bundle steps[{index}].status"),
            &self.status,
        )?;
        for (missing_index, missing_ref) in self.missing_refs.iter().enumerate() {
            require_text(
                &format!(
                    "authoring loop evidence bundle steps[{index}].missingRefs[{missing_index}]"
                ),
                missing_ref,
            )?;
        }
        for (output_index, output) in self.outputs.iter().enumerate() {
            output.validate(
                &format!("authoring loop evidence bundle steps[{index}].outputs[{output_index}]"),
                generated_roots,
                ids,
            )?;
        }
        Ok(())
    }
}

impl AuthoringLoopEvidenceBundleArtifactRef {
    fn validate(
        &self,
        field: &str,
        generated_roots: &[String],
        ids: &mut BTreeSet<String>,
    ) -> Result<()> {
        validate_path_component(&format!("{field}.id"), &self.id)?;
        validate_authoring_loop_bundle_ref_path(
            &format!("{field}.path"),
            self.kind,
            &self.path,
            generated_roots,
        )?;
        if let Some(step_id) = &self.step_id {
            validate_path_component(&format!("{field}.stepId"), step_id)?;
        }
        if let Some(description) = &self.description {
            require_text(&format!("{field}.description"), description)?;
        }
        if !ids.insert(self.id.clone()) {
            return Err(anyhow!(
                "duplicate authoring loop evidence bundle artifact id: {}",
                self.id
            ));
        }
        Ok(())
    }
}

fn validate_authoring_loop_bundle_ref_path(
    field: &str,
    kind: AuthoringLoopEvidenceBundleArtifactKind,
    value: &str,
    generated_roots: &[String],
) -> Result<()> {
    if kind == AuthoringLoopEvidenceBundleArtifactKind::LoopPlan {
        // The loop plan itself may live under an allowed generated local root
        // (e.g. .omx/loop-plan.json), which execute_authoring_loop_step_from_path
        // already accepts. Use the generated-root validator so bundle generation
        // does not reject a plan location the runner just executed against.
        return validate_authoring_loop_generated_root(field, value);
    }
    validate_authoring_loop_generated_artifact_path(field, Path::new(value), generated_roots)
}

fn validate_authoring_loop_generated_artifact_path(
    field: &str,
    path: &Path,
    generated_roots: &[String],
) -> Result<()> {
    let value = path.to_string_lossy();
    validate_authoring_loop_generated_root(field, &value)?;
    let under_generated_root = generated_roots.iter().any(|root| {
        let root = Path::new(root);
        path == root || path.starts_with(root)
    });
    if !under_generated_root && !is_documented_generated_artifact_path(path) {
        return Err(anyhow!(
            "{field} must stay within configured generated roots"
        ));
    }
    Ok(())
}

pub const STUDIO_LOOP_COCKPIT_SCHEMA_VERSION: &str = "studio-loop-cockpit-v1";

#[derive(Debug, Clone, Serialize, PartialEq, Eq)]
pub struct StudioLoopCockpitReadModel {
    #[serde(rename = "schemaVersion")]
    pub schema_version: String,
    pub loops: Vec<StudioLoopCockpitLoop>,
    pub boundary: String,
}

#[derive(Debug, Clone, Serialize, PartialEq, Eq, Default)]
pub struct StudioLoopCockpitLoop {
    #[serde(rename = "loopId")]
    pub loop_id: String,
    pub status: String,
    #[serde(rename = "planPath", skip_serializing_if = "Option::is_none")]
    pub plan_path: Option<String>,
    #[serde(rename = "currentStep", skip_serializing_if = "Option::is_none")]
    pub current_step: Option<AgentHandoffStep>,
    pub steps: Vec<AuthoringLoopEvidenceBundleStep>,
    #[serde(rename = "nextSafeAction", skip_serializing_if = "Option::is_none")]
    pub next_safe_action: Option<String>,
    pub blockers: Vec<String>,
    #[serde(rename = "requiredDecisions")]
    pub required_decisions: Vec<AuthoringLoopDecisionRef>,
    #[serde(rename = "allowedCommands")]
    pub allowed_commands: Vec<AuthoringLoopResumeCommandContext>,
    #[serde(rename = "forbiddenActions")]
    pub forbidden_actions: Vec<String>,
    #[serde(rename = "evidenceRefs")]
    pub evidence_refs: Vec<AuthoringLoopArtifactRef>,
    #[serde(rename = "bundleStatus", skip_serializing_if = "Option::is_none")]
    pub bundle_status: Option<String>,
    #[serde(rename = "bundleMissingRefs")]
    pub bundle_missing_refs: Vec<String>,
    #[serde(rename = "handoffStatus", skip_serializing_if = "Option::is_none")]
    pub handoff_status: Option<String>,
    #[serde(rename = "driftGuardrails")]
    pub drift_guardrails: Vec<String>,
    pub boundary: String,
}

pub fn build_studio_loop_cockpit_read_model(
    bundles: &[AuthoringLoopEvidenceBundle],
    handoffs: &[AgentHandoffContract],
) -> StudioLoopCockpitReadModel {
    let mut loops = BTreeMap::<String, StudioLoopCockpitLoop>::new();
    for bundle in bundles {
        let entry = loops.entry(bundle.loop_id.clone()).or_insert_with(|| StudioLoopCockpitLoop {
            loop_id: bundle.loop_id.clone(),
            status: bundle.status.as_str().to_string(),
            boundary: "Read-only Studio loop cockpit data; browser displays only and does not execute commands or write files.".to_string(),
            ..StudioLoopCockpitLoop::default()
        });
        entry.status = bundle.status.as_str().to_string();
        entry.plan_path = Some(bundle.plan.path.clone());
        entry.steps = bundle.steps.clone();
        entry.bundle_status = Some(bundle.status.as_str().to_string());
        entry.bundle_missing_refs = bundle.missing_refs.clone();
        entry.boundary = format!("{} {}", entry.boundary, bundle.boundary);
    }
    for handoff in handoffs {
        let entry = loops.entry(handoff.loop_id.clone()).or_insert_with(|| StudioLoopCockpitLoop {
            loop_id: handoff.loop_id.clone(),
            status: handoff.status.as_str().to_string(),
            boundary: "Read-only Studio loop cockpit data; browser displays only and does not execute commands or write files.".to_string(),
            ..StudioLoopCockpitLoop::default()
        });
        entry.status = handoff.status.as_str().to_string();
        entry.current_step = handoff.current_step.clone();
        entry.next_safe_action = Some(handoff.next_safe_action.clone());
        entry.blockers = handoff.blockers.clone();
        entry.required_decisions = handoff.required_decisions.clone();
        entry.allowed_commands = handoff.allowed_commands.clone();
        entry.forbidden_actions = handoff.forbidden_actions.clone();
        entry.evidence_refs = handoff.evidence_refs.clone();
        if entry.plan_path.is_none() {
            entry.plan_path = handoff
                .evidence_refs
                .iter()
                .find(|reference| reference.id == "loop-plan")
                .map(|reference| reference.path.clone());
        }
        entry.handoff_status = Some(handoff.status.as_str().to_string());
        entry.drift_guardrails = handoff.drift_guardrails.clone();
        entry.boundary = format!("{} {}", entry.boundary, handoff.boundary);
    }
    StudioLoopCockpitReadModel {
        schema_version: STUDIO_LOOP_COCKPIT_SCHEMA_VERSION.to_string(),
        loops: loops.into_values().collect(),
        boundary: "Read-only normalized loop cockpit read model; it does not execute commands, write files, apply mutations, promote regressions, or bridge browser UI to local CLI.".to_string(),
    }
}

pub const AUTHORING_LOOP_EVIDENCE_BUNDLE_FILE_NAME: &str = "bundle.json";

pub fn write_authoring_loop_evidence_bundle_from_path(
    plan_path: impl AsRef<Path>,
) -> Result<AuthoringLoopEvidenceBundle> {
    let plan_path = plan_path.as_ref();
    let input = fs::read_to_string(plan_path)
        .with_context(|| format!("failed to read authoring loop plan {}", plan_path.display()))?;
    let plan = AuthoringLoopPlan::from_json_str(&input).with_context(|| {
        format!(
            "failed to parse authoring loop plan {}",
            plan_path.display()
        )
    })?;
    let base_dir = plan_path
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
        .unwrap_or_else(|| Path::new("."));
    write_authoring_loop_evidence_bundle(&plan, base_dir, plan_path)
}

pub fn write_authoring_loop_evidence_bundle(
    plan: &AuthoringLoopPlan,
    base_dir: impl AsRef<Path>,
    plan_path: impl AsRef<Path>,
) -> Result<AuthoringLoopEvidenceBundle> {
    let base_dir = base_dir.as_ref();
    let bundle = build_authoring_loop_evidence_bundle(plan, base_dir, plan_path)?;
    let bundle_path = authoring_loop_evidence_bundle_path(base_dir, &bundle.loop_id)?;
    if let Some(parent) = bundle_path.parent() {
        fs::create_dir_all(parent).with_context(|| {
            format!(
                "failed to create authoring loop evidence bundle dir {}",
                parent.display()
            )
        })?;
    }
    write_json_atomic(&bundle_path, &json!(bundle))?;
    Ok(bundle)
}

pub fn build_authoring_loop_evidence_bundle(
    plan: &AuthoringLoopPlan,
    base_dir: impl AsRef<Path>,
    plan_path: impl AsRef<Path>,
) -> Result<AuthoringLoopEvidenceBundle> {
    plan.validate_schema()?;
    let base_dir = base_dir.as_ref();
    let plan_path = plan_path.as_ref();
    let plan_ref_path = relative_path_string(base_dir, plan_path)?;
    let mut steps = Vec::new();
    let mut runs = Vec::new();
    let mut comparisons = Vec::new();
    let mut proposals = Vec::new();
    let mut review_decisions = Vec::new();
    let mut transactions = Vec::new();
    let mut regression_promotions = Vec::new();
    let mut matrix_snapshots = Vec::new();
    let mut journal_summaries = Vec::new();
    let mut missing_refs = Vec::new();

    for step in &plan.steps {
        let mut outputs = Vec::new();
        let mut step_missing_refs = Vec::new();
        for artifact in &step.expected_artifacts {
            let kind = bundle_artifact_kind_for_step(step.kind, artifact);
            let missing = !base_dir.join(&artifact.path).exists();
            if missing {
                let missing_ref = format!("{}:{}", artifact.id, artifact.path);
                missing_refs.push(missing_ref.clone());
                step_missing_refs.push(missing_ref);
            }
            let category_ref = AuthoringLoopEvidenceBundleArtifactRef {
                id: artifact.id.clone(),
                kind,
                path: artifact.path.clone(),
                step_id: Some(step.id.clone()),
                description: artifact.description.clone(),
            };
            let step_ref = AuthoringLoopEvidenceBundleArtifactRef {
                id: format!("{}-{}", step.id, artifact.id),
                kind: AuthoringLoopEvidenceBundleArtifactKind::StepOutput,
                path: artifact.path.clone(),
                step_id: Some(step.id.clone()),
                description: artifact.description.clone(),
            };
            outputs.push(step_ref);
            match kind {
                AuthoringLoopEvidenceBundleArtifactKind::Run => runs.push(category_ref),
                AuthoringLoopEvidenceBundleArtifactKind::Comparison => {
                    comparisons.push(category_ref)
                }
                AuthoringLoopEvidenceBundleArtifactKind::Proposal => proposals.push(category_ref),
                AuthoringLoopEvidenceBundleArtifactKind::ReviewDecision => {
                    review_decisions.push(category_ref)
                }
                AuthoringLoopEvidenceBundleArtifactKind::Transaction => {
                    transactions.push(category_ref)
                }
                AuthoringLoopEvidenceBundleArtifactKind::RegressionPromotion => {
                    regression_promotions.push(category_ref)
                }
                AuthoringLoopEvidenceBundleArtifactKind::MatrixSnapshot => {
                    matrix_snapshots.push(category_ref)
                }
                AuthoringLoopEvidenceBundleArtifactKind::JournalSummary => {
                    journal_summaries.push(category_ref)
                }
                AuthoringLoopEvidenceBundleArtifactKind::LoopPlan
                | AuthoringLoopEvidenceBundleArtifactKind::StepOutput => {}
            }
        }
        steps.push(AuthoringLoopEvidenceBundleStep {
            step_id: step.id.clone(),
            kind: step.kind.as_str().to_string(),
            status: step.status.as_str().to_string(),
            outputs,
            missing_refs: step_missing_refs,
        });
    }

    missing_refs.sort();
    missing_refs.dedup();
    let status = if plan
        .steps
        .iter()
        .any(|step| step.status == AuthoringLoopStepStatus::Failed)
    {
        AuthoringLoopEvidenceBundleStatus::Failed
    } else if !missing_refs.is_empty()
        || !plan
            .steps
            .iter()
            .all(|step| step.status == AuthoringLoopStepStatus::Completed)
    {
        AuthoringLoopEvidenceBundleStatus::Partial
    } else {
        AuthoringLoopEvidenceBundleStatus::Completed
    };

    let bundle = AuthoringLoopEvidenceBundle {
        schema_version: AUTHORING_LOOP_EVIDENCE_BUNDLE_SCHEMA_VERSION.to_string(),
        loop_id: plan.loop_id.clone(),
        status,
        plan: AuthoringLoopEvidenceBundleArtifactRef {
            id: "loop-plan".to_string(),
            kind: AuthoringLoopEvidenceBundleArtifactKind::LoopPlan,
            path: plan_ref_path,
            step_id: None,
            description: Some("validated authoring loop plan".to_string()),
        },
        steps,
        runs,
        comparisons,
        proposals,
        review_decisions,
        transactions,
        regression_promotions,
        matrix_snapshots,
        journal_summaries,
        missing_refs,
        generated_state: plan.generated_state.clone(),
        boundary: "Generated local evidence index only; does not move artifacts, mutate source state, serve files, add browser writes, or package/export artifacts.".to_string(),
    };
    bundle.validate_schema()?;
    Ok(bundle)
}

pub fn list_agent_handoff_contracts(
    runs_root: impl AsRef<Path>,
) -> Result<Vec<AgentHandoffContract>> {
    let runs_root = runs_root.as_ref();
    let handoff_root = runs_root.join("agent-handoffs");
    if !handoff_root.exists() {
        return Ok(Vec::new());
    }
    let mut handoffs = Vec::new();
    for entry in fs::read_dir(&handoff_root).with_context(|| {
        format!(
            "failed to read agent handoff root {}",
            handoff_root.display()
        )
    })? {
        let entry = entry.context("failed to read agent handoff root entry")?;
        let path = entry.path().join("handoff.json");
        if !path.is_file() {
            continue;
        }
        let body = fs::read_to_string(&path)
            .with_context(|| format!("failed to read agent handoff {}", path.display()))?;
        let handoff = AgentHandoffContract::from_json_str(&body)
            .with_context(|| format!("failed to validate agent handoff {}", path.display()))?;
        handoffs.push(handoff);
    }
    handoffs.sort_by(|left, right| left.loop_id.cmp(&right.loop_id));
    Ok(handoffs)
}

pub fn list_authoring_loop_evidence_bundles(
    runs_root: impl AsRef<Path>,
) -> Result<Vec<AuthoringLoopEvidenceBundle>> {
    let runs_root = runs_root.as_ref();
    let bundle_root = runs_root.join("authoring-loop-bundles");
    if !bundle_root.exists() {
        return Ok(Vec::new());
    }
    let base_dir = runs_root
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
        .unwrap_or_else(|| Path::new("."));
    let mut bundles = Vec::new();
    for entry in fs::read_dir(&bundle_root)
        .with_context(|| format!("failed to read bundle root {}", bundle_root.display()))?
    {
        let entry = entry.context("failed to read bundle root entry")?;
        let path = entry.path().join(AUTHORING_LOOP_EVIDENCE_BUNDLE_FILE_NAME);
        if !path.is_file() {
            continue;
        }
        let body = fs::read_to_string(&path)
            .with_context(|| format!("failed to read bundle {}", path.display()))?;
        let bundle = AuthoringLoopEvidenceBundle::from_json_str_with_base(&body, base_dir)
            .with_context(|| format!("failed to validate bundle {}", path.display()))?;
        bundles.push(bundle);
    }
    bundles.sort_by(|left, right| left.loop_id.cmp(&right.loop_id));
    Ok(bundles)
}

fn authoring_loop_evidence_bundle_path(base_dir: &Path, loop_id: &str) -> Result<PathBuf> {
    validate_path_component("authoring loop id", loop_id)?;
    Ok(base_dir
        .join("runs/authoring-loop-bundles")
        .join(loop_id)
        .join(AUTHORING_LOOP_EVIDENCE_BUNDLE_FILE_NAME))
}

fn relative_path_string(base_dir: &Path, path: &Path) -> Result<String> {
    let relative = path.strip_prefix(base_dir).unwrap_or(path);
    let value = relative.to_string_lossy().to_string();
    validate_project_manifest_path("authoring loop evidence bundle relative path", &value)?;
    Ok(value)
}

fn bundle_artifact_kind_for_step(
    step_kind: AuthoringLoopStepKind,
    artifact: &AuthoringLoopArtifactRef,
) -> AuthoringLoopEvidenceBundleArtifactKind {
    let id = artifact.id.as_str();
    let path = artifact.path.as_str();
    if id.contains("matrix") || path.contains("matrix") {
        return AuthoringLoopEvidenceBundleArtifactKind::MatrixSnapshot;
    }
    if id.contains("journal")
        || id.contains("summary")
        || path.contains("journal")
        || path.contains("summary")
    {
        return AuthoringLoopEvidenceBundleArtifactKind::JournalSummary;
    }
    match step_kind {
        AuthoringLoopStepKind::RunScenarioPack | AuthoringLoopStepKind::Rerun => {
            AuthoringLoopEvidenceBundleArtifactKind::Run
        }
        AuthoringLoopStepKind::CompareRuns => AuthoringLoopEvidenceBundleArtifactKind::Comparison,
        AuthoringLoopStepKind::GenerateProposal => {
            AuthoringLoopEvidenceBundleArtifactKind::Proposal
        }
        AuthoringLoopStepKind::RecordReviewDecision => {
            AuthoringLoopEvidenceBundleArtifactKind::ReviewDecision
        }
        AuthoringLoopStepKind::ApplyAcceptedSceneMutation => {
            AuthoringLoopEvidenceBundleArtifactKind::Transaction
        }
        AuthoringLoopStepKind::PromoteRegression => {
            AuthoringLoopEvidenceBundleArtifactKind::RegressionPromotion
        }
        AuthoringLoopStepKind::Summarize => AuthoringLoopEvidenceBundleArtifactKind::JournalSummary,
    }
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct AuthoringLoopArtifactRef {
    pub id: String,
    pub path: String,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub description: Option<String>,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct AuthoringLoopDecisionRef {
    pub id: String,
    pub kind: AuthoringLoopDecisionKind,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub description: Option<String>,
}

#[derive(Debug, Clone, Copy, Deserialize, Serialize, PartialEq, Eq)]
#[serde(rename_all = "kebab-case")]
pub enum AuthoringLoopDecisionKind {
    HumanReview,
    AgentReview,
    AcceptedMutation,
    RegressionPromotion,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct AuthoringLoopGeneratedStatePolicy {
    pub roots: Vec<String>,
    #[serde(rename = "trackedFixtureOnly")]
    pub tracked_fixture_only: bool,
}

impl AuthoringLoopPlan {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let plan: AuthoringLoopPlan =
            serde_json::from_str(input).context("failed to parse Authoring Loop Plan JSON")?;
        plan.validate_schema()?;
        Ok(plan)
    }

    pub fn validate_schema(&self) -> Result<()> {
        if self.schema_version != AUTHORING_LOOP_PLAN_SCHEMA_VERSION {
            return Err(anyhow!(
                "authoring loop plan schemaVersion must be {AUTHORING_LOOP_PLAN_SCHEMA_VERSION}"
            ));
        }
        validate_path_component("authoring loop plan loopId", &self.loop_id)?;
        self.project.validate()?;
        self.seed.validate("authoring loop plan seed")?;
        self.scenario_pack
            .validate("authoring loop plan scenarioPack")?;
        if self.steps.is_empty() {
            return Err(anyhow!("authoring loop plan steps must not be empty"));
        }
        for (index, step) in self.steps.iter().enumerate() {
            step.validate_schema(index)?;
        }
        self.generated_state.validate()?;
        self.validate_step_rules()?;
        Ok(())
    }

    fn validate_step_rules(&self) -> Result<()> {
        let mut step_ids = BTreeSet::new();
        let mut produced_artifacts = BTreeSet::new();
        let mut completed_artifacts = BTreeSet::new();
        let mut previous_rank = None;
        let mut completed_steps = BTreeSet::new();

        for step in &self.steps {
            if !step_ids.insert(step.id.clone()) {
                return Err(anyhow!(
                    "duplicate authoring loop plan step id: {}",
                    step.id
                ));
            }

            let rank = step.kind.order_rank();
            if previous_rank.is_some_and(|previous| rank < previous) {
                return Err(anyhow!(
                    "authoring loop plan step {} kind {:?} is out of order",
                    step.id,
                    step.kind
                ));
            }
            previous_rank = Some(rank);

            for dependency in &step.depends_on {
                if !step_ids.contains(dependency) {
                    return Err(anyhow!(
                        "authoring loop plan step {} dependsOn {} must reference an earlier step",
                        step.id,
                        dependency
                    ));
                }
                if matches!(
                    step.status,
                    AuthoringLoopStepStatus::Running | AuthoringLoopStepStatus::Completed
                ) && !completed_steps.contains(dependency)
                {
                    return Err(anyhow!(
                        "authoring loop plan step {} cannot be {:?} before dependency {} is completed",
                        step.id,
                        step.status,
                        dependency
                    ));
                }
            }

            if step.kind.requires_input_artifact() && step.inputs.is_empty() {
                return Err(anyhow!(
                    "authoring loop plan step {} kind {:?} requires at least one input artifact",
                    step.id,
                    step.kind
                ));
            }
            if step.kind.requires_decision() && step.required_decisions.is_empty() {
                return Err(anyhow!(
                    "authoring loop plan step {} kind {:?} requires at least one decision reference",
                    step.id,
                    step.kind
                ));
            }
            if step.kind == AuthoringLoopStepKind::ApplyAcceptedSceneMutation
                && step.rollback_refs.is_empty()
            {
                return Err(anyhow!(
                    "authoring loop plan step {} kind {:?} requires rollbackRefs",
                    step.id,
                    step.kind
                ));
            }

            for input in &step.inputs {
                if !produced_artifacts.contains(&input.id) {
                    return Err(anyhow!(
                        "authoring loop plan step {} input {} must reference an earlier expected artifact",
                        step.id,
                        input.id
                    ));
                }
                // A running or completed step consumes real input artifacts, so
                // each input must have been produced by a step that actually
                // completed. Otherwise a plan could mark compare-runs completed
                // while consuming a baseline-run artifact whose producer failed.
                if matches!(
                    step.status,
                    AuthoringLoopStepStatus::Running | AuthoringLoopStepStatus::Completed
                ) && !completed_artifacts.contains(&input.id)
                {
                    return Err(anyhow!(
                        "authoring loop plan step {} cannot be {:?} while input {} is not produced by a completed step",
                        step.id,
                        step.status,
                        input.id
                    ));
                }
            }

            if let Some(transition) = &step.status_transition {
                transition.validate(&step.id, step.status)?;
            }

            for artifact in &step.expected_artifacts {
                if !produced_artifacts.insert(artifact.id.clone()) {
                    return Err(anyhow!(
                        "duplicate authoring loop plan artifact id: {}",
                        artifact.id
                    ));
                }
            }
            if step.status == AuthoringLoopStepStatus::Completed {
                completed_steps.insert(step.id.clone());
                for artifact in &step.expected_artifacts {
                    completed_artifacts.insert(artifact.id.clone());
                }
            }
        }
        Ok(())
    }

    pub fn update_step_status(
        &self,
        step_id: &str,
        next_status: AuthoringLoopStepStatus,
    ) -> Result<(Self, AuthoringLoopStepStatusUpdate)> {
        validate_path_component("authoring loop step id", step_id)?;
        let step_index = self
            .steps
            .iter()
            .position(|step| step.id == step_id)
            .ok_or_else(|| anyhow!("authoring loop plan step not found: {step_id}"))?;
        let current_status = self.steps[step_index].status;
        if !current_status.can_transition_to(next_status) {
            return Err(anyhow!(
                "authoring loop step {step_id} cannot transition from {:?} to {:?}",
                current_status,
                next_status
            ));
        }

        let mut updated = self.clone();
        let updated_step = &mut updated.steps[step_index];
        updated_step.status = next_status;
        updated_step.status_transition = Some(AuthoringLoopStatusTransition {
            from: current_status,
            to: next_status,
        });
        updated.validate_schema()?;

        let outcome = if current_status == next_status {
            "unchanged"
        } else {
            "updated"
        };
        let summary = AuthoringLoopStepStatusUpdate {
            loop_id: updated.loop_id.clone(),
            step_id: updated.steps[step_index].id.clone(),
            kind: updated.steps[step_index].kind.as_str().to_string(),
            from: current_status.as_str().to_string(),
            to: next_status.as_str().to_string(),
            outcome: outcome.to_string(),
            boundary: "state-machine only; does not execute commands, write plan files, mutate scenes, record decisions, promote regressions, or update source code".to_string(),
        };
        Ok((updated, summary))
    }
}

impl AuthoringLoopStepKind {
    pub fn as_str(self) -> &'static str {
        match self {
            AuthoringLoopStepKind::RunScenarioPack => "run-scenario-pack",
            AuthoringLoopStepKind::CompareRuns => "compare-runs",
            AuthoringLoopStepKind::GenerateProposal => "generate-proposal",
            AuthoringLoopStepKind::RecordReviewDecision => "record-review-decision",
            AuthoringLoopStepKind::ApplyAcceptedSceneMutation => "apply-accepted-scene-mutation",
            AuthoringLoopStepKind::Rerun => "rerun",
            AuthoringLoopStepKind::PromoteRegression => "promote-regression",
            AuthoringLoopStepKind::Summarize => "summarize",
        }
    }

    fn inert_command_text(self) -> String {
        match self {
            AuthoringLoopStepKind::RunScenarioPack => "cargo run -p ouroforge-cli -- run <seed> --project <project> --scenario-pack <id>".to_string(),
            AuthoringLoopStepKind::CompareRuns => "cargo run -p ouroforge-cli -- compare <before-run> <after-run>".to_string(),
            AuthoringLoopStepKind::GenerateProposal => "cargo run -p ouroforge-cli -- evolve <run-dir>".to_string(),
            AuthoringLoopStepKind::RecordReviewDecision => "cargo run -p ouroforge-cli -- mutation review <run-or-draft> --proposal <id> --decision <accepted|rejected|deferred> --reason <text> --evidence <ref>".to_string(),
            AuthoringLoopStepKind::ApplyAcceptedSceneMutation => "cargo run -p ouroforge-cli -- mutation apply-scene <run-dir> --project <project> --operation <operation.json> --decision <id> --transaction-output <path>".to_string(),
            AuthoringLoopStepKind::Rerun => "cargo run -p ouroforge-cli -- run <seed> --project <project> --scenario-pack <id>".to_string(),
            AuthoringLoopStepKind::PromoteRegression => "cargo run -p ouroforge-cli -- scenario promote <draft> --project <project> --scenario-pack <id> --dry-run".to_string(),
            AuthoringLoopStepKind::Summarize => "cargo run -p ouroforge-cli -- journal show <run-dir>".to_string(),
        }
    }

    fn safety_gates(self) -> Vec<String> {
        let mut gates = vec!["inert command text only".to_string()];
        match self {
            AuthoringLoopStepKind::ApplyAcceptedSceneMutation => {
                gates.push(
                    "requires accepted review decision before any later execution issue may apply"
                        .to_string(),
                );
                gates.push("dry-run does not mutate scenes".to_string());
            }
            AuthoringLoopStepKind::PromoteRegression => {
                gates
                    .push("dry-run does not write scenario packs or promotion records".to_string());
            }
            AuthoringLoopStepKind::RecordReviewDecision => {
                gates.push("dry-run does not record review decisions".to_string());
            }
            _ => {}
        }
        gates
    }

    fn order_rank(self) -> u8 {
        match self {
            AuthoringLoopStepKind::RunScenarioPack => 0,
            AuthoringLoopStepKind::CompareRuns => 1,
            AuthoringLoopStepKind::GenerateProposal => 2,
            AuthoringLoopStepKind::RecordReviewDecision => 3,
            AuthoringLoopStepKind::ApplyAcceptedSceneMutation => 4,
            AuthoringLoopStepKind::Rerun => 5,
            AuthoringLoopStepKind::PromoteRegression => 6,
            AuthoringLoopStepKind::Summarize => 7,
        }
    }

    fn requires_input_artifact(self) -> bool {
        matches!(
            self,
            AuthoringLoopStepKind::CompareRuns
                | AuthoringLoopStepKind::GenerateProposal
                | AuthoringLoopStepKind::RecordReviewDecision
                | AuthoringLoopStepKind::ApplyAcceptedSceneMutation
                | AuthoringLoopStepKind::Rerun
                | AuthoringLoopStepKind::PromoteRegression
                | AuthoringLoopStepKind::Summarize
        )
    }

    fn requires_decision(self) -> bool {
        matches!(
            self,
            AuthoringLoopStepKind::RecordReviewDecision
                | AuthoringLoopStepKind::ApplyAcceptedSceneMutation
                | AuthoringLoopStepKind::PromoteRegression
        )
    }
}

impl AuthoringLoopStepStatus {
    pub fn as_str(self) -> &'static str {
        match self {
            AuthoringLoopStepStatus::Pending => "pending",
            AuthoringLoopStepStatus::Running => "running",
            AuthoringLoopStepStatus::Blocked => "blocked",
            AuthoringLoopStepStatus::Failed => "failed",
            AuthoringLoopStepStatus::Completed => "completed",
        }
    }

    pub fn can_transition_to(self, next: Self) -> bool {
        match (self, next) {
            (current, next) if current == next => true,
            (AuthoringLoopStepStatus::Pending, AuthoringLoopStepStatus::Running) => true,
            (AuthoringLoopStepStatus::Pending, AuthoringLoopStepStatus::Blocked) => true,
            (AuthoringLoopStepStatus::Running, AuthoringLoopStepStatus::Blocked) => true,
            (AuthoringLoopStepStatus::Running, AuthoringLoopStepStatus::Failed) => true,
            (AuthoringLoopStepStatus::Running, AuthoringLoopStepStatus::Completed) => true,
            (AuthoringLoopStepStatus::Blocked, AuthoringLoopStepStatus::Pending) => true,
            (AuthoringLoopStepStatus::Failed, AuthoringLoopStepStatus::Pending) => true,
            _ => false,
        }
    }
}

impl AuthoringLoopStatusTransition {
    fn validate(&self, step_id: &str, status: AuthoringLoopStepStatus) -> Result<()> {
        if self.to != status {
            return Err(anyhow!(
                "authoring loop plan step {step_id} statusTransition.to must match status"
            ));
        }
        if !self.from.can_transition_to(self.to) {
            return Err(anyhow!(
                "authoring loop plan step {step_id} invalid status transition {:?} -> {:?}",
                self.from,
                self.to
            ));
        }
        Ok(())
    }
}

impl AuthoringLoopProjectContext {
    fn validate(&self) -> Result<()> {
        validate_path_component("authoring loop plan project.projectId", &self.project_id)?;
        validate_project_manifest_path(
            "authoring loop plan project.manifestPath",
            &self.manifest_path,
        )
    }
}

impl AuthoringLoopPathRef {
    fn validate(&self, field: &str) -> Result<()> {
        validate_path_component(&format!("{field} id"), &self.id)?;
        validate_project_manifest_path(&format!("{field} path"), &self.path)
    }
}

impl AuthoringLoopStep {
    fn validate_schema(&self, index: usize) -> Result<()> {
        validate_path_component(&format!("authoring loop plan steps[{index}].id"), &self.id)?;
        for (dep_index, dependency) in self.depends_on.iter().enumerate() {
            validate_path_component(
                &format!("authoring loop plan steps[{index}].dependsOn[{dep_index}]"),
                dependency,
            )?;
        }
        for (input_index, input) in self.inputs.iter().enumerate() {
            input.validate(&format!(
                "authoring loop plan steps[{index}].inputs[{input_index}]"
            ))?;
        }
        for (artifact_index, artifact) in self.expected_artifacts.iter().enumerate() {
            artifact.validate(&format!(
                "authoring loop plan steps[{index}].expectedArtifacts[{artifact_index}]"
            ))?;
        }
        for (decision_index, decision) in self.required_decisions.iter().enumerate() {
            decision.validate(&format!(
                "authoring loop plan steps[{index}].requiredDecisions[{decision_index}]"
            ))?;
        }
        for (rollback_index, rollback_ref) in self.rollback_refs.iter().enumerate() {
            rollback_ref.validate(&format!(
                "authoring loop plan steps[{index}].rollbackRefs[{rollback_index}]"
            ))?;
        }
        if let Some(recovery) = &self.recovery {
            // Recovery metadata describes how to recover an interrupted step, so
            // it is only coherent on a blocked or failed step. Rejecting it on
            // pending/running/completed steps prevents a resumed step from being
            // serialized as completed while still advertising stale recovery
            // instructions (status updates clone the whole step and only change
            // the status field).
            if !matches!(
                self.status,
                AuthoringLoopStepStatus::Blocked | AuthoringLoopStepStatus::Failed
            ) {
                return Err(anyhow!(
                    "authoring loop plan steps[{index}].recovery is only allowed on blocked or failed steps, found {:?}",
                    self.status
                ));
            }
            recovery.validate(&format!("authoring loop plan steps[{index}].recovery"))?;
        }
        Ok(())
    }
}

impl AuthoringLoopStepRecovery {
    fn validate(&self, field: &str) -> Result<()> {
        self.failure.validate(&format!("{field}.failure"))?;
        self.manual_action
            .validate(&format!("{field}.manualAction"))?;
        for (rollback_index, rollback_ref) in self.rollback_refs.iter().enumerate() {
            rollback_ref.validate(&format!("{field}.rollbackRefs[{rollback_index}]"))?;
        }
        for (evidence_index, evidence_ref) in self.evidence_refs.iter().enumerate() {
            evidence_ref.validate(&format!("{field}.evidenceRefs[{evidence_index}]"))?;
        }
        if let Some(resume_command) = &self.resume_command {
            resume_command.validate(&format!("{field}.resumeCommand"))?;
        }
        Ok(())
    }
}

impl AuthoringLoopFailureMetadata {
    fn validate(&self, field: &str) -> Result<()> {
        require_text(&format!("{field}.reason"), &self.reason)?;
        if let Some(detail) = &self.detail {
            require_text(&format!("{field}.detail"), detail)?;
        }
        Ok(())
    }
}

impl AuthoringLoopManualAction {
    fn validate(&self, field: &str) -> Result<()> {
        require_text(&format!("{field}.description"), &self.description)
    }
}

impl AuthoringLoopResumeCommandContext {
    fn validate(&self, field: &str) -> Result<()> {
        require_text(&format!("{field}.command"), &self.command)?;
        if self.argv.is_empty() {
            return Err(anyhow!("{field}.argv must not be empty"));
        }
        for (index, arg) in self.argv.iter().enumerate() {
            require_text(&format!("{field}.argv[{index}]"), arg)?;
        }
        require_text(&format!("{field}.boundary"), &self.boundary)
    }
}

impl AuthoringLoopRetryability {
    fn as_str(self) -> &'static str {
        match self {
            AuthoringLoopRetryability::Retryable => "retryable",
            AuthoringLoopRetryability::NonRetryable => "non-retryable",
            AuthoringLoopRetryability::ManualActionRequired => "manual-action-required",
        }
    }
}

impl AuthoringLoopArtifactRef {
    fn validate(&self, field: &str) -> Result<()> {
        validate_path_component(&format!("{field} id"), &self.id)?;
        validate_project_manifest_path(&format!("{field} path"), &self.path)?;
        if let Some(description) = &self.description {
            require_text(&format!("{field} description"), description)?;
        }
        Ok(())
    }
}

impl AuthoringLoopDecisionKind {
    pub fn as_str(self) -> &'static str {
        match self {
            AuthoringLoopDecisionKind::HumanReview => "human-review",
            AuthoringLoopDecisionKind::AgentReview => "agent-review",
            AuthoringLoopDecisionKind::AcceptedMutation => "accepted-mutation",
            AuthoringLoopDecisionKind::RegressionPromotion => "regression-promotion",
        }
    }
}

impl AuthoringLoopDecisionRef {
    fn validate(&self, field: &str) -> Result<()> {
        validate_path_component(&format!("{field} id"), &self.id)?;
        if let Some(description) = &self.description {
            require_text(&format!("{field} description"), description)?;
        }
        Ok(())
    }
}

impl AuthoringLoopGeneratedStatePolicy {
    fn validate(&self) -> Result<()> {
        if self.roots.is_empty() {
            return Err(anyhow!(
                "authoring loop plan generatedState.roots must not be empty"
            ));
        }
        validate_authoring_loop_generated_roots(
            "authoring loop plan generatedState.roots",
            &self.roots,
        )
    }
}

pub const AUTHORING_LOOP_DRY_RUN_SCHEMA_VERSION: &str = "authoring-loop-dry-run-v1";

