fn canonical_json_digest(value: serde_json::Value) -> Result<String> {
    let bytes = serde_json::to_vec(&canonical_json_value(value))
        .context("failed to serialize canonical JSON for digest")?;
    Ok(format!("{:016x}", fnv1a64(&bytes)))
}

fn validate_review_gated_scene_apply_decision(
    run_dir: &Path,
    operation: &SceneOnlyMutationOperation,
) -> Result<Option<String>> {
    let Some(decision_id) = operation.review_decision_id.as_deref() else {
        return Ok(None);
    };
    require_text("scene-only mutation reviewDecisionId", decision_id)?;
    let review = read_mutation_review_artifact(run_dir)?;
    let decision = review
        .decisions
        .iter()
        .find(|decision| decision.id == decision_id)
        .ok_or_else(|| {
            anyhow!(
                "review-gated scene apply decision id not found: {}",
                decision_id
            )
        })?;
    if decision.state != MutationReviewState::Accepted
        || decision.decision_status.as_ref() != Some(&MutationReviewState::Accepted)
    {
        return Err(anyhow!(
            "review-gated scene apply requires an accepted decision; found {:?}",
            decision.decision_status.as_ref().unwrap_or(&decision.state)
        ));
    }
    if decision.proposal_id.as_deref() != Some(operation.proposal_id.as_str()) {
        return Err(anyhow!(
            "review-gated scene apply decision {} is not linked to proposal {}",
            decision_id,
            operation.proposal_id
        ));
    }
    if decision.evidence_refs.is_empty() {
        return Err(anyhow!(
            "review-gated scene apply decision {} requires evidence refs",
            decision_id
        ));
    }
    let checklist = decision.guardrail_checklist.as_ref().ok_or_else(|| {
        anyhow!(
            "review-gated scene apply decision {} requires a guardrail checklist",
            decision_id
        )
    })?;
    checklist.validate()?;
    if let Some(expected_hashes) = &decision.expected_hashes {
        if let Some(expected) = expected_hashes.proposal_index_hash.as_deref() {
            let actual = canonical_json_digest(json!(read_mutation_proposals(run_dir)?))?;
            if expected != actual {
                return Err(anyhow!(
                    "review-gated scene apply decision {} proposal index hash mismatch; expected {}, found {}",
                    decision_id, expected, actual
                ));
            }
        }
        if let Some(expected) = expected_hashes.patch_draft_hash.as_deref() {
            let actual = canonical_json_digest(json!(read_patch_draft_artifact(run_dir)?))?;
            if expected != actual {
                return Err(anyhow!(
                    "review-gated scene apply decision {} patch draft hash mismatch; expected {}, found {}",
                    decision_id, expected, actual
                ));
            }
        }
        if let Some(expected) = expected_hashes.evidence_index_hash.as_deref() {
            let actual = canonical_json_digest(json!(read_evidence_index(run_dir)?))?;
            if expected != actual {
                return Err(anyhow!(
                    "review-gated scene apply decision {} evidence index hash mismatch; expected {}, found {}",
                    decision_id, expected, actual
                ));
            }
        }
    }
    let applications = read_scene_only_mutation_applications(run_dir)?;
    if applications
        .applications
        .iter()
        .any(|application| application.review_decision_id.as_deref() == Some(decision_id))
    {
        return Err(anyhow!(
            "review-gated scene apply decision {} was already used",
            decision_id
        ));
    }
    if applications.applications.iter().any(|application| {
        application.proposal_id == operation.proposal_id && application.status == "applied"
    }) {
        return Err(anyhow!(
            "review-gated scene apply proposal {} already has an applied scene mutation",
            operation.proposal_id
        ));
    }
    Ok(Some(decision_id.to_string()))
}

fn validate_project_scene_mutation_context(
    operation: &SceneOnlyMutationOperation,
    before_scene_hash: &SceneHash,
) -> Result<Option<ProjectSceneMutationContext>> {
    let Some(project) = &operation.project else {
        return Ok(None);
    };
    require_text("scene-only mutation project projectId", &project.project_id)?;
    require_text(
        "scene-only mutation project manifestPath",
        &project.manifest_path,
    )?;
    validate_project_manifest_path("scene-only mutation project scenePath", &project.scene_path)?;
    let manifest_path = Path::new(&project.manifest_path);
    let manifest = ProjectManifest::from_path(manifest_path).with_context(|| {
        format!(
            "scene-only mutation project manifest failed validation: {}",
            manifest_path.display()
        )
    })?;
    if manifest.project.id != project.project_id {
        return Err(anyhow!(
            "scene-only mutation project id mismatch; expected {}, found {}",
            project.project_id,
            manifest.project.id
        ));
    }
    let manifest_hash = hash_project_manifest_file(manifest_path)?;
    if manifest_hash != project.manifest_hash {
        return Err(anyhow!(
            "scene-only mutation project manifest hash mismatch; expected {}, found {}",
            project.manifest_hash.value,
            manifest_hash.value
        ));
    }
    let project_root = manifest_path
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
        .unwrap_or_else(|| Path::new("."));
    let declared_scene = manifest
        .scenes
        .iter()
        .find(|scene| scene.path == project.scene_path)
        .ok_or_else(|| {
            anyhow!(
                "scene-only mutation target scene {} is not declared in project manifest scenes",
                project.scene_path
            )
        })?;
    let declared_scene_path = project_root.join(&declared_scene.path);
    let declared_scene_canonical = declared_scene_path.canonicalize().with_context(|| {
        format!(
            "failed to resolve project scene {}",
            declared_scene_path.display()
        )
    })?;
    let target_scene_path = Path::new(&operation.target_scene_path);
    let target_scene_canonical = target_scene_path.canonicalize().with_context(|| {
        format!(
            "failed to resolve scene-only mutation targetScenePath {}",
            target_scene_path.display()
        )
    })?;
    if target_scene_canonical != declared_scene_canonical {
        return Err(anyhow!(
            "scene-only mutation targetScenePath {} is not the manifest-authorized project scene {}",
            operation.target_scene_path,
            project.scene_path
        ));
    }
    if &project.scene_hash != before_scene_hash {
        return Err(anyhow!(
            "scene-only mutation project scene hash mismatch; expected {}, found {}",
            project.scene_hash.value,
            before_scene_hash.value
        ));
    }
    if &operation.expected_before_scene_hash != before_scene_hash {
        return Err(anyhow!(
            "scene-only mutation before hash mismatch; expected {}, found {}",
            operation.expected_before_scene_hash.value,
            before_scene_hash.value
        ));
    }
    Ok(Some(project.clone()))
}

pub fn validate_scene_only_mutation_operation(
    run_dir: impl AsRef<Path>,
    operation: &SceneOnlyMutationOperation,
) -> Result<SceneOnlyMutationValidation> {
    let run_dir = run_dir.as_ref();
    if operation.schema_version != "scene-only-mutation-v1" {
        return Err(anyhow!(
            "scene-only mutation schemaVersion must be scene-only-mutation-v1"
        ));
    }
    if !operation.validation_required {
        return Err(anyhow!(
            "scene-only mutation requires validationRequired=true"
        ));
    }
    require_text("scene-only mutation proposalId", &operation.proposal_id)?;
    require_text(
        "scene-only mutation targetScenePath",
        &operation.target_scene_path,
    )?;
    if !supported_scene_edit_paths().contains(&operation.edit.path.as_str()) {
        return Err(anyhow!(
            "scene-only mutation edit path is not allowed: {}",
            operation.edit.path
        ));
    }
    let proposals = read_mutation_proposals(run_dir)?;
    let proposal = proposals
        .proposals
        .iter()
        .find(|proposal| proposal.id == operation.proposal_id)
        .ok_or_else(|| {
            anyhow!(
                "scene-only mutation proposal id not found: {}",
                operation.proposal_id
            )
        })?;
    if proposal.status != "proposed" {
        return Err(anyhow!(
            "scene-only mutation requires a proposed mutation; found status {}",
            proposal.status
        ));
    }
    let scene = read_scene(&operation.target_scene_path)?;
    let before_scene_hash = hash_scene_document(&scene)?;
    let project = validate_project_scene_mutation_context(operation, &before_scene_hash)?;
    let review_decision_id = validate_review_gated_scene_apply_decision(run_dir, operation)?;
    if before_scene_hash != operation.expected_before_scene_hash {
        return Err(anyhow!(
            "scene-only mutation before hash mismatch; expected {}, found {}",
            operation.expected_before_scene_hash.value,
            before_scene_hash.value
        ));
    }
    let mut candidate_scene = scene.clone();
    apply_scene_edit(&mut candidate_scene, operation.edit.clone())?;
    validate_scene(&candidate_scene).context("scene-only mutation candidate validation failed")?;
    Ok(SceneOnlyMutationValidation {
        status: "passed".to_string(),
        proposal_id: operation.proposal_id.clone(),
        target_scene_path: operation.target_scene_path.clone(),
        before_scene_hash,
        allowed_path: true,
        review_decision_id,
        project,
    })
}

pub fn reject_generated_artifact_source_collision(
    output_path: &Path,
    artifact_label: &str,
) -> Result<()> {
    if !is_source_like_artifact_path(output_path)
        || is_documented_generated_artifact_path(output_path)
    {
        return Ok(());
    }
    Err(anyhow!(
        "{artifact_label} output must not target source-like path {}",
        output_path.display()
    ))
}

fn is_documented_generated_artifact_path(path: &Path) -> bool {
    if path
        .components()
        .any(|component| matches!(component, std::path::Component::ParentDir))
    {
        return false;
    }
    let first_normal_component = path.components().find_map(|component| match component {
        std::path::Component::Normal(value) => Some(value.to_string_lossy()),
        _ => None,
    });
    first_normal_component.is_some_and(|value| {
        matches!(
            value.as_ref(),
            "runs" | "target" | "dashboard-data" | ".omx" | ".openchrome" | ".omc" | ".claude"
        )
    }) || path.ends_with(Path::new("examples/evidence-dashboard/dashboard-data.json"))
}

fn is_source_like_artifact_path(path: &Path) -> bool {
    let has_source_component = path.components().any(|component| {
        let value = component.as_os_str().to_string_lossy();
        matches!(
            value.as_ref(),
            "assets" | "crates" | "docs" | "examples" | "scenes" | "seeds" | "src" | "tests"
        )
    });
    let source_file_name = path
        .file_name()
        .and_then(|name| name.to_str())
        .is_some_and(|name| {
            matches!(
                name,
                "Cargo.toml" | "Cargo.lock" | "README.md" | "AGENTS.md" | ".gitignore"
            )
        });
    has_source_component || source_file_name
}

pub fn reject_transaction_output_target_collision(
    transaction_output: &Path,
    target_scene_path: &Path,
) -> Result<()> {
    let direct_path_match = transaction_output == target_scene_path;
    let canonical_path_match = match (
        transaction_output.canonicalize(),
        target_scene_path.canonicalize(),
    ) {
        (Ok(output), Ok(target)) => output == target,
        _ => false,
    };
    if direct_path_match
        || canonical_path_match
        || same_existing_file(transaction_output, target_scene_path)
    {
        return Err(anyhow!(
            "transaction output must not equal target scene path {}",
            target_scene_path.display()
        ));
    }
    Ok(())
}

fn reject_scene_mutation_transaction_output_collision(
    transaction_output: &Path,
    target_scene_path: &Path,
) -> Result<()> {
    reject_transaction_output_target_collision(transaction_output, target_scene_path).map_err(
        |error| {
            let message = error.to_string();
            let suffix = message
                .strip_prefix("transaction output ")
                .unwrap_or(&message);
            anyhow!("scene-only mutation transaction output {suffix}")
        },
    )
}

#[cfg(unix)]
fn same_existing_file(left: &Path, right: &Path) -> bool {
    use std::os::unix::fs::MetadataExt;

    let (Ok(left), Ok(right)) = (std::fs::metadata(left), std::fs::metadata(right)) else {
        return false;
    };
    left.dev() == right.dev() && left.ino() == right.ino()
}

#[cfg(windows)]
fn same_existing_file(left: &Path, right: &Path) -> bool {
    use std::ffi::c_void;
    use std::mem::MaybeUninit;
    use std::os::windows::io::AsRawHandle;

    #[allow(non_snake_case)]
    #[repr(C)]
    struct FileTime {
        dwLowDateTime: u32,
        dwHighDateTime: u32,
    }

    #[allow(non_snake_case)]
    #[repr(C)]
    struct ByHandleFileInformation {
        dwFileAttributes: u32,
        ftCreationTime: FileTime,
        ftLastAccessTime: FileTime,
        ftLastWriteTime: FileTime,
        dwVolumeSerialNumber: u32,
        nFileSizeHigh: u32,
        nFileSizeLow: u32,
        nNumberOfLinks: u32,
        nFileIndexHigh: u32,
        nFileIndexLow: u32,
    }

    #[derive(PartialEq, Eq)]
    struct FileIdentity {
        volume: u32,
        index_high: u32,
        index_low: u32,
    }

    extern "system" {
        fn GetFileInformationByHandle(
            hFile: *mut c_void,
            lpFileInformation: *mut ByHandleFileInformation,
        ) -> i32;
    }

    fn identity(path: &Path) -> Option<FileIdentity> {
        let file = File::open(path).ok()?;
        let mut info = MaybeUninit::<ByHandleFileInformation>::uninit();
        let ok = unsafe { GetFileInformationByHandle(file.as_raw_handle(), info.as_mut_ptr()) };
        if ok == 0 {
            return None;
        }
        let info = unsafe { info.assume_init() };
        Some(FileIdentity {
            volume: info.dwVolumeSerialNumber,
            index_high: info.nFileIndexHigh,
            index_low: info.nFileIndexLow,
        })
    }

    let (Some(left), Some(right)) = (identity(left), identity(right)) else {
        return false;
    };
    left == right
}

#[cfg(not(any(unix, windows)))]
fn same_existing_file(_left: &Path, _right: &Path) -> bool {
    false
}

pub fn apply_scene_only_mutation_operation(
    run_dir: impl AsRef<Path>,
    operation: &SceneOnlyMutationOperation,
    transaction_output: impl AsRef<Path>,
) -> Result<SceneEditTransaction> {
    let run_dir = run_dir.as_ref();
    let transaction_output = transaction_output.as_ref();
    if operation.schema_version != "scene-only-mutation-v1" {
        return Err(anyhow!(
            "scene-only mutation schemaVersion must be scene-only-mutation-v1"
        ));
    }
    if !operation.validation_required {
        return Err(anyhow!(
            "scene-only mutation requires validationRequired=true"
        ));
    }
    if !supported_scene_edit_paths().contains(&operation.edit.path.as_str()) {
        return Err(anyhow!(
            "scene-only mutation edit path is not allowed: {}",
            operation.edit.path
        ));
    }
    let proposals = read_mutation_proposals(run_dir)?;
    let proposal = proposals
        .proposals
        .iter()
        .find(|proposal| proposal.id == operation.proposal_id)
        .ok_or_else(|| {
            anyhow!(
                "scene-only mutation proposal id not found: {}",
                operation.proposal_id
            )
        })?;
    if proposal.status != "proposed" {
        return Err(anyhow!(
            "scene-only mutation requires a proposed mutation; found status {}",
            proposal.status
        ));
    }
    let scene = read_scene(&operation.target_scene_path)?;
    let before_scene_hash = hash_scene_document(&scene)?;
    let project = validate_project_scene_mutation_context(operation, &before_scene_hash)?;
    let review_decision_id = validate_review_gated_scene_apply_decision(run_dir, operation)?;
    if before_scene_hash != operation.expected_before_scene_hash {
        return Err(anyhow!(
            "scene-only mutation before hash mismatch; expected {}, found {}",
            operation.expected_before_scene_hash.value,
            before_scene_hash.value
        ));
    }
    reject_scene_mutation_transaction_output_collision(
        transaction_output,
        Path::new(&operation.target_scene_path),
    )?;
    let transaction =
        preview_scene_edit_transaction(&operation.target_scene_path, operation.edit.clone())?;
    write_scene_edit_transaction_artifact(transaction_output, &transaction)?;
    if transaction.validation_result.status != "passed" {
        return Err(anyhow!(
            "scene-only mutation transaction failed validation; artifact written to {}",
            transaction_output.display()
        ));
    }
    edit_scene(&operation.target_scene_path, operation.edit.clone())?;
    let after_scene_hash = transaction
        .after_scene_hash
        .clone()
        .ok_or_else(|| anyhow!("passed scene-only transaction missing afterSceneHash"))?;
    let application = append_scene_only_mutation_application(
        run_dir,
        operation,
        &transaction,
        transaction_output,
        &after_scene_hash,
    )?;
    append_ledger_event(
        run_dir,
        "mutation.scene_applied",
        "mutation-cli",
        json!({
            "proposal_id": operation.proposal_id,
            "decision_id": review_decision_id,
            "application_id": application.id,
            "transaction_id": transaction.id,
            "transaction_artifact_path": transaction_output.to_string_lossy(),
            "target_scene_path": operation.target_scene_path,
            "before_scene_hash": transaction.before_scene_hash,
            "after_scene_hash": after_scene_hash,
            "project": project
        }),
    )?;
    Ok(transaction)
}

fn append_scene_only_mutation_application(
    run_dir: &Path,
    operation: &SceneOnlyMutationOperation,
    transaction: &SceneEditTransaction,
    transaction_output: &Path,
    after_scene_hash: &SceneHash,
) -> Result<SceneOnlyMutationApplicationRecord> {
    let mut index = read_scene_only_mutation_applications(run_dir)?;
    let record = SceneOnlyMutationApplicationRecord {
        id: format!(
            "scene-application-{}-{}",
            unix_millis()?,
            index.applications.len() + 1
        ),
        proposal_id: operation.proposal_id.clone(),
        transaction_id: transaction.id.clone(),
        review_decision_id: operation.review_decision_id.clone(),
        target_scene_path: operation.target_scene_path.clone(),
        project: operation.project.clone(),
        transaction_artifact_path: transaction_output.to_string_lossy().to_string(),
        before_scene_hash: transaction.before_scene_hash.clone(),
        after_scene_hash: after_scene_hash.clone(),
        rollback: Some(transaction.rollback.clone()),
        status: "applied".to_string(),
        created_at_unix_ms: unix_millis()?,
    };
    index.applications.push(record.clone());
    write_scene_only_mutation_applications(run_dir, &index)?;
    Ok(record)
}

fn read_scene_only_mutation_applications(
    run_dir: impl AsRef<Path>,
) -> Result<SceneOnlyMutationApplicationIndex> {
    let path = run_dir.as_ref().join("mutation/scene-applications.json");
    if !path.is_file() {
        return Ok(SceneOnlyMutationApplicationIndex::default());
    }
    let input = fs::read_to_string(&path)
        .with_context(|| format!("failed to read scene applications {}", path.display()))?;
    serde_json::from_str(&input)
        .with_context(|| format!("failed to parse scene applications {}", path.display()))
}

fn write_scene_only_mutation_applications(
    run_dir: impl AsRef<Path>,
    index: &SceneOnlyMutationApplicationIndex,
) -> Result<()> {
    let path = run_dir.as_ref().join("mutation/scene-applications.json");
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent).with_context(|| {
            format!(
                "failed to create scene application directory {}",
                parent.display()
            )
        })?;
    }
    write_json(&path, &json!(index))
}

pub fn read_scene_edit_transaction_artifact(
    path: impl AsRef<Path>,
) -> Result<SceneEditTransaction> {
    let path = path.as_ref();
    let value = read_json_value(path)?;
    serde_json::from_value(value)
        .with_context(|| format!("failed to parse scene edit transaction {}", path.display()))
}

pub fn run_transaction_provenance_from_artifact(
    path: impl AsRef<Path>,
) -> Result<RunTransactionProvenance> {
    let path = path.as_ref();
    let transaction = read_scene_edit_transaction_artifact(path)?;
    if transaction.validation_result.status != "passed" {
        return Err(anyhow!(
            "run transaction provenance requires a passed transaction: {}",
            transaction.id
        ));
    }
    let after_scene_hash = transaction.after_scene_hash.clone().ok_or_else(|| {
        anyhow!(
            "run transaction provenance requires afterSceneHash for transaction: {}",
            transaction.id
        )
    })?;
    Ok(RunTransactionProvenance {
        transaction_id: transaction.id,
        transaction_artifact_path: path.to_string_lossy().to_string(),
        scene_path: transaction.scene_path,
        before_scene_hash: transaction.before_scene_hash,
        after_scene_hash,
    })
}

pub fn bind_run_transaction_provenance(
    run_dir: impl AsRef<Path>,
    transaction_path: impl AsRef<Path>,
) -> Result<RunTransactionProvenance> {
    let run_dir = run_dir.as_ref();
    let provenance = run_transaction_provenance_from_artifact(&transaction_path)?;
    let scene = read_scene(&provenance.scene_path).with_context(|| {
        format!(
            "failed to read transaction source scene {}",
            provenance.scene_path
        )
    })?;
    let current_hash = hash_scene_document(&scene)?;
    if current_hash != provenance.after_scene_hash {
        return Err(anyhow!(
            "transaction source scene hash mismatch for {}; expected afterSceneHash {}, found {}",
            provenance.transaction_id,
            provenance.after_scene_hash.value,
            current_hash.value
        ));
    }
    let run_path = run_dir.join("run.json");
    let mut run = read_json_value(&run_path)?;
    let run_object = run
        .as_object_mut()
        .ok_or_else(|| anyhow!("run.json must be a JSON object"))?;
    run_object.insert(
        "transaction_provenance".to_string(),
        json!(provenance.clone()),
    );
    write_json_atomic(&run_path, &run)?;
    append_ledger_event(
        run_dir,
        "run.transaction_bound",
        "run-cli",
        json!({
            "transaction_id": provenance.transaction_id,
            "transaction_artifact_path": provenance.transaction_artifact_path,
            "scene_path": provenance.scene_path,
            "before_scene_hash": provenance.before_scene_hash,
            "after_scene_hash": provenance.after_scene_hash
        }),
    )?;
    Ok(provenance)
}

pub fn preview_scene_edit_transaction(
    scene_path: impl AsRef<Path>,
    edit: SceneEdit,
) -> Result<SceneEditTransaction> {
    let scene_path = scene_path.as_ref();
    validate_path_component("scene edit entity", &edit.entity_id)?;
    require_text("scene edit path", &edit.path)?;
    let before = read_scene(scene_path)?;
    let before_hash = hash_scene_document(&before)?;
    let mut after = before.clone();
    let validation_error = apply_scene_edit(&mut after, edit.clone())
        .and_then(|_| validate_scene(&after))
        .err()
        .map(|error| error.to_string());
    let after_hash = if validation_error.is_none() {
        Some(hash_scene_document(&after)?)
    } else {
        None
    };
    let transaction_seed = json!({
        "scenePath": scene_path.to_string_lossy(),
        "edit": edit,
        "beforeSceneHash": before_hash,
        "afterSceneHash": after_hash
    });
    let transaction_id = format!(
        "scene-edit-{}",
        fnv1a64(&serde_json::to_vec(&canonical_json_value(
            transaction_seed
        ))?)
    );
    Ok(SceneEditTransaction {
        schema_version: "ouroforge.scene-edit-transaction.v1".to_string(),
        id: transaction_id,
        scene_path: scene_path.to_string_lossy().to_string(),
        edit,
        before_scene_hash: before_hash.clone(),
        after_scene_hash: after_hash,
        validation_result: match validation_error {
            Some(error) => SceneEditValidationResult {
                status: "failed".to_string(),
                errors: vec![error],
            },
            None => SceneEditValidationResult {
                status: "passed".to_string(),
                errors: Vec::new(),
            },
        },
        rollback: SceneEditRollbackMetadata {
            scene_path: scene_path.to_string_lossy().to_string(),
            restore_hash: before_hash,
            strategy: "restore scene file content matching beforeSceneHash".to_string(),
        },
    })
}

fn canonical_json_value(value: serde_json::Value) -> serde_json::Value {
    match value {
        serde_json::Value::Array(items) => {
            serde_json::Value::Array(items.into_iter().map(canonical_json_value).collect())
        }
        serde_json::Value::Object(map) => {
            let mut sorted = serde_json::Map::new();
            let mut entries = map.into_iter().collect::<Vec<_>>();
            entries.sort_by(|left, right| left.0.cmp(&right.0));
            for (key, value) in entries {
                sorted.insert(key, canonical_json_value(value));
            }
            serde_json::Value::Object(sorted)
        }
        other => other,
    }
}

fn fnv1a64(bytes: &[u8]) -> u64 {
    let mut hash = 0xcbf29ce484222325_u64;
    for byte in bytes {
        hash ^= u64::from(*byte);
        hash = hash.wrapping_mul(0x100000001b3);
    }
    hash
}

