pub fn read_scene(scene_path: impl AsRef<Path>) -> Result<SceneDocument> {
    let scene_path = scene_path.as_ref();
    let input = fs::read_to_string(scene_path)
        .with_context(|| format!("failed to read scene {}", scene_path.display()))?;
    let scene: SceneDocument = serde_json::from_str(&input)
        .with_context(|| format!("failed to parse scene {}", scene_path.display()))?;
    validate_scene(&scene)?;
    Ok(scene)
}

#[derive(Debug, Deserialize)]
struct SceneTransitionDocument {
    #[serde(default, rename = "sceneTransitions")]
    scene_transitions: Vec<SceneTransition>,
}

fn read_scene_transitions(scene_path: impl AsRef<Path>) -> Result<Vec<SceneTransition>> {
    let scene_path = scene_path.as_ref();
    let input = fs::read_to_string(scene_path)
        .with_context(|| format!("failed to read scene {}", scene_path.display()))?;
    let scene: SceneTransitionDocument = serde_json::from_str(&input)
        .with_context(|| format!("failed to parse scene {}", scene_path.display()))?;
    validate_scene_transitions(&scene.scene_transitions)?;
    Ok(scene.scene_transitions)
}

pub fn validate_scene_reload(scene_path: impl AsRef<Path>) -> Result<SceneReloadValidationReport> {
    let scene_path = scene_path.as_ref();
    let scene = read_scene(scene_path)?;
    // read_scene only runs structural manifest validation; the reload boundary
    // must also confirm the embedded manifest's files exist relative to the
    // scene directory, otherwise it can report a scene the runtime cannot load.
    if let Some(manifest) = &scene.asset_manifest {
        let base_dir = match scene_path.parent() {
            Some(parent) if !parent.as_os_str().is_empty() => parent,
            _ => Path::new("."),
        };
        manifest.validate_files(base_dir).with_context(|| {
            format!(
                "scene asset manifest {} references invalid files",
                manifest.id
            )
        })?;
    }
    Ok(SceneReloadValidationReport {
        schema_version: "ouroforge.scene-reload.v0".to_string(),
        scene_id: scene.id.clone(),
        entity_count: scene.entities.len(),
        asset_manifest: scene.asset_manifest.as_ref().map(|manifest| {
            SceneReloadAssetManifestReport {
                id: manifest.id.clone(),
                asset_count: manifest.assets.len(),
            }
        }),
        reset_state: vec![
            "tick".to_string(),
            "entities".to_string(),
            "collisions".to_string(),
            "collisionEvents".to_string(),
            "audioEvents".to_string(),
            "snapshots".to_string(),
            "renderer".to_string(),
            "tilemaps".to_string(),
            "assetManifest".to_string(),
        ],
        preserved_state: vec![
            "runtime API".to_string(),
            "fixedDeltaMs".to_string(),
            "bounded event history".to_string(),
        ],
        unsupported: vec![
            "source code reload".to_string(),
            "live code HMR".to_string(),
            "filesystem watchers".to_string(),
            "direct browser file writes".to_string(),
            "editor persistence".to_string(),
            "native shell".to_string(),
        ],
    })
}

pub fn edit_scene(scene_path: impl AsRef<Path>, edit: SceneEdit) -> Result<SceneDocument> {
    let scene_path = scene_path.as_ref();
    validate_path_component("scene edit entity", &edit.entity_id)?;
    require_text("scene edit path", &edit.path)?;
    let mut scene = read_scene(scene_path)?;
    apply_scene_edit(&mut scene, edit)?;
    validate_scene(&scene)?;
    write_json(scene_path, &json!(scene))?;
    Ok(scene)
}

fn validate_scene(scene: &SceneDocument) -> Result<()> {
    if scene.schema_version != "1" {
        return Err(anyhow!("scene schemaVersion must be 1 for scene schema v1"));
    }
    validate_path_component("scene id", &scene.id)?;
    if scene.bounds.width <= 0 || scene.bounds.height <= 0 {
        return Err(anyhow!("scene bounds must be positive"));
    }
    if let Some(renderer) = &scene.renderer {
        validate_scene_renderer(scene, renderer)?;
    }
    if let Some(manifest) = &scene.asset_manifest {
        manifest
            .validate()
            .context("scene assetManifest is invalid")?;
    }
    let collision_layers = validate_scene_collision_rules(scene.collision_rules.as_ref())?;
    let gameplay_flags = validate_scene_gameplay_rules(scene.gameplay_rules.as_ref())?;
    validate_scene_transitions(&scene.scene_transitions)?;
    validate_scene_tilemaps(&scene.tilemaps, scene.asset_manifest.as_ref())?;
    validate_scene_metadata("scene metadata", &scene.metadata)?;
    if scene.entities.is_empty() {
        return Err(anyhow!("scene entities must not be empty"));
    }
    if let Some(defaults) = &scene.component_defaults {
        validate_scene_component_defaults(defaults, gameplay_flags.as_ref())?;
    }
    validate_scene_composition(scene)?;
    let mut ids = std::collections::BTreeSet::new();
    for entity in &scene.entities {
        validate_path_component("scene entity id", &entity.id)?;
        if let Some(parent) = &entity.parent {
            validate_path_component(&format!("scene entity {} parent", entity.id), parent)?;
        }
        if !ids.insert(entity.id.clone()) {
            return Err(anyhow!("duplicate scene entity id: {}", entity.id));
        }
        validate_scene_color(&entity.sprite.color)?;
        if let Some(asset) = &entity.sprite.asset {
            validate_scene_asset_ref(
                "scene sprite asset",
                asset,
                scene.asset_manifest.as_ref(),
                &[AssetManifestKind::Image, AssetManifestKind::Sprite],
            )?;
        }
        if let Some(layer) = &entity.sprite.layer {
            validate_path_component(&format!("scene entity {} sprite layer", entity.id), layer)?;
            if let Some(renderer) = &scene.renderer {
                if !renderer
                    .layers
                    .iter()
                    .any(|candidate| candidate.id == *layer)
                {
                    return Err(anyhow!(
                        "scene entity {} sprite layer references unknown renderer layer: {}",
                        entity.id,
                        layer
                    ));
                }
            }
        }
        if entity.components.size.width <= 0 || entity.components.size.height <= 0 {
            return Err(anyhow!("scene entity {} size must be positive", entity.id));
        }
        if let Some(collider) = &entity.components.collider {
            validate_scene_collider(&entity.id, collider, collision_layers.as_ref())?;
        }
        if let Some(trigger) = &entity.components.trigger {
            validate_scene_trigger(&entity.id, trigger, gameplay_flags.as_ref())?;
        }
        if let Some(status) = &entity.components.status {
            validate_scene_status(
                &format!("scene entity {} status", entity.id),
                status,
                gameplay_flags.as_ref(),
            )?;
        }
        if let Some(goal_flag) = &entity.components.goal_flag {
            validate_scene_goal_flag(&entity.id, goal_flag, gameplay_flags.as_ref())?;
        }
        if let Some(input) = &entity.components.input {
            validate_scene_input_controller(&format!("scene entity {} input", entity.id), input)?;
        }
        if let Some(camera_target) = &entity.components.camera_target {
            validate_scene_camera_target(&entity.id, camera_target)?;
        }
        if let Some(ui_text) = &entity.components.ui_text {
            validate_scene_ui_text(&entity.id, ui_text, gameplay_flags.as_ref())?;
        }
        if let Some(hud_value) = &entity.components.hud_value {
            validate_scene_hud_value(&entity.id, hud_value, gameplay_flags.as_ref())?;
        }
        if let Some(animation) = &entity.components.animation {
            validate_scene_animation(&entity.id, animation, scene.asset_manifest.as_ref())?;
        }
        if let Some(audio) = &entity.components.audio {
            validate_scene_audio(&entity.id, audio, scene.asset_manifest.as_ref())?;
        }
        validate_scene_tags(&entity.id, &entity.tags)?;
        validate_scene_metadata(
            &format!("scene entity {} metadata", entity.id),
            &entity.metadata,
        )?;
    }
    Ok(())
}

fn validate_scene_component_defaults(
    defaults: &SceneComponentDefaults,
    gameplay_flags: Option<&BTreeSet<String>>,
) -> Result<()> {
    if let Some(size) = &defaults.size {
        if size.width <= 0 || size.height <= 0 {
            return Err(anyhow!("scene componentDefaults size must be positive"));
        }
    }
    if let Some(status) = &defaults.status {
        validate_scene_status("scene componentDefaults status", status, gameplay_flags)?;
    }
    if let Some(input) = &defaults.input {
        validate_scene_input_controller("scene componentDefaults input", input)?;
    }
    Ok(())
}

fn validate_scene_composition(scene: &SceneDocument) -> Result<()> {
    let ids = scene
        .entities
        .iter()
        .map(|entity| entity.id.as_str())
        .collect::<BTreeSet<_>>();
    for entity in &scene.entities {
        let Some(parent) = &entity.parent else {
            continue;
        };
        if parent == &entity.id {
            return Err(anyhow!(
                "scene entity {} parent must not reference itself",
                entity.id
            ));
        }
        if !ids.contains(parent.as_str()) {
            return Err(anyhow!(
                "scene entity {} references missing parent: {}",
                entity.id,
                parent
            ));
        }
    }
    for entity in &scene.entities {
        let mut seen = BTreeSet::new();
        let mut current = entity.parent.as_deref();
        while let Some(parent_id) = current {
            if !seen.insert(parent_id) {
                return Err(anyhow!(
                    "scene composition cycle detected at entity {}",
                    entity.id
                ));
            }
            current = scene
                .entities
                .iter()
                .find(|candidate| candidate.id == parent_id)
                .and_then(|parent| parent.parent.as_deref());
        }
    }
    Ok(())
}

fn validate_scene_tilemaps(
    tilemaps: &[SceneTilemap],
    manifest: Option<&AssetManifest>,
) -> Result<()> {
    let mut tilemap_ids = std::collections::BTreeSet::new();
    for tilemap in tilemaps {
        validate_path_component("scene tilemap id", &tilemap.id)?;
        if !tilemap_ids.insert(tilemap.id.clone()) {
            return Err(anyhow!("duplicate scene tilemap id: {}", tilemap.id));
        }
        if tilemap.tile_size.width <= 0 || tilemap.tile_size.height <= 0 {
            return Err(anyhow!(
                "scene tilemap {} tileSize must be positive",
                tilemap.id
            ));
        }
        if tilemap.grid.width == 0 || tilemap.grid.height == 0 {
            return Err(anyhow!(
                "scene tilemap {} grid dimensions must be positive",
                tilemap.id
            ));
        }
        let expected_cells = tilemap
            .grid
            .width
            .checked_mul(tilemap.grid.height)
            .ok_or_else(|| anyhow!("scene tilemap {} grid dimensions overflow", tilemap.id))?;
        let mut tile_ids = std::collections::BTreeSet::new();
        for tile in &tilemap.tiles {
            validate_path_component(&format!("scene tilemap {} tile id", tilemap.id), &tile.id)?;
            if !tile_ids.insert(tile.id.clone()) {
                return Err(anyhow!(
                    "duplicate scene tilemap {} tile id: {}",
                    tilemap.id,
                    tile.id
                ));
            }
            validate_scene_color(&tile.color).with_context(|| {
                format!(
                    "scene tilemap {} tile {} color is invalid",
                    tilemap.id, tile.id
                )
            })?;
            if let Some(asset) = &tile.asset {
                validate_scene_asset_ref(
                    "scene tilemap tile asset",
                    asset,
                    manifest,
                    &[AssetManifestKind::Image, AssetManifestKind::Sprite],
                )?;
            }
        }
        if tile_ids.is_empty() {
            return Err(anyhow!(
                "scene tilemap {} tiles must not be empty",
                tilemap.id
            ));
        }
        let mut layer_ids = std::collections::BTreeSet::new();
        for layer in &tilemap.layers {
            validate_path_component(&format!("scene tilemap {} layer id", tilemap.id), &layer.id)?;
            if !layer_ids.insert(layer.id.clone()) {
                return Err(anyhow!(
                    "duplicate scene tilemap {} layer id: {}",
                    tilemap.id,
                    layer.id
                ));
            }
            if layer.data.len() != expected_cells {
                return Err(anyhow!(
                    "scene tilemap {} layer {} data length must equal grid cell count {}",
                    tilemap.id,
                    layer.id,
                    expected_cells
                ));
            }
            for tile_id in layer.data.iter().flatten() {
                if !tile_ids.contains(tile_id) {
                    return Err(anyhow!(
                        "scene tilemap {} layer {} references unknown tile id: {}",
                        tilemap.id,
                        layer.id,
                        tile_id
                    ));
                }
            }
            validate_scene_metadata(
                &format!("scene tilemap {} layer {} metadata", tilemap.id, layer.id),
                &layer.metadata,
            )?;
        }
        if tilemap.layers.is_empty() {
            return Err(anyhow!(
                "scene tilemap {} layers must not be empty",
                tilemap.id
            ));
        }
        for layer in &tilemap.layers {
            if let Some(collision_layer) = &layer.collision_layer {
                validate_path_component(
                    &format!("scene tilemap {} collision layer ref", tilemap.id),
                    collision_layer,
                )?;
                if !layer_ids.contains(collision_layer) {
                    return Err(anyhow!(
                        "scene tilemap {} layer {} references unknown collisionLayer: {}",
                        tilemap.id,
                        layer.id,
                        collision_layer
                    ));
                }
            }
        }
        validate_scene_metadata(
            &format!("scene tilemap {} metadata", tilemap.id),
            &tilemap.metadata,
        )?;
    }
    Ok(())
}

pub fn scene_tilemap_layer_order(scene: &SceneDocument) -> Vec<SceneTilemapLayerOrderEntry> {
    let mut entries = scene
        .tilemaps
        .iter()
        .flat_map(|tilemap| {
            tilemap
                .layers
                .iter()
                .filter(|layer| layer.visible)
                .map(|layer| SceneTilemapLayerOrderEntry {
                    tilemap_id: tilemap.id.clone(),
                    layer_id: layer.id.clone(),
                    order: layer.order,
                })
        })
        .collect::<Vec<_>>();
    entries.sort_by(|left, right| {
        (left.order, left.tilemap_id.as_str(), left.layer_id.as_str()).cmp(&(
            right.order,
            right.tilemap_id.as_str(),
            right.layer_id.as_str(),
        ))
    });
    entries
}

fn validate_scene_renderer(scene: &SceneDocument, renderer: &SceneRenderer) -> Result<()> {
    if renderer.version != "1" {
        return Err(anyhow!("scene renderer version must be 1"));
    }
    if renderer.viewport.width <= 0 || renderer.viewport.height <= 0 {
        return Err(anyhow!("scene renderer viewport must be positive"));
    }
    if renderer.viewport.width > scene.bounds.width
        || renderer.viewport.height > scene.bounds.height
    {
        return Err(anyhow!(
            "scene renderer viewport must fit inside scene bounds"
        ));
    }
    validate_scene_color(&renderer.background)
        .context("scene renderer background color is invalid")?;
    if renderer.layers.is_empty() {
        return Err(anyhow!("scene renderer layers must not be empty"));
    }
    let mut layer_ids = std::collections::BTreeSet::new();
    for layer in &renderer.layers {
        validate_path_component("scene renderer layer id", &layer.id)?;
        if !layer_ids.insert(layer.id.clone()) {
            return Err(anyhow!("duplicate scene renderer layer id: {}", layer.id));
        }
    }
    Ok(())
}

pub fn scene_render_order(scene: &SceneDocument) -> Vec<SceneRenderOrderEntry> {
    let layer_order = scene
        .renderer
        .as_ref()
        .map(|renderer| {
            renderer
                .layers
                .iter()
                .map(|layer| (layer.id.as_str(), layer.order))
                .collect::<std::collections::BTreeMap<_, _>>()
        })
        .unwrap_or_default();

    // Entities on a layer marked `visible: false` are not rendered. The browser
    // renderer already honors this (examples/game-runtime/renderer.js), so the
    // canonical render order must too, otherwise hidden-layer entities leak into
    // the evidence as renderable.
    let hidden_layers = scene
        .renderer
        .as_ref()
        .map(|renderer| {
            renderer
                .layers
                .iter()
                .filter(|layer| !layer.visible)
                .map(|layer| layer.id.as_str())
                .collect::<std::collections::BTreeSet<_>>()
        })
        .unwrap_or_default();

    let mut entries = scene
        .entities
        .iter()
        .filter(|entity| {
            entity.sprite.visible
                && !hidden_layers.contains(entity.sprite.layer.as_deref().unwrap_or("default"))
        })
        .map(|entity| {
            let layer = entity
                .sprite
                .layer
                .clone()
                .unwrap_or_else(|| "default".to_string());
            let layer_order = layer_order.get(layer.as_str()).copied().unwrap_or(0);
            SceneRenderOrderEntry {
                entity_id: entity.id.clone(),
                layer,
                layer_order,
                sprite_order: entity.sprite.order.unwrap_or(0),
            }
        })
        .collect::<Vec<_>>();
    entries.sort_by(|left, right| {
        (left.layer_order, left.sprite_order, left.entity_id.as_str()).cmp(&(
            right.layer_order,
            right.sprite_order,
            right.entity_id.as_str(),
        ))
    });
    entries
}

fn validate_scene_asset_ref(
    field: &str,
    value: &str,
    manifest: Option<&AssetManifest>,
    expected: &[AssetManifestKind],
) -> Result<()> {
    if let Some(manifest) = manifest {
        validate_path_component(field, value)?;
        match manifest.assets.iter().find(|asset| asset.id == value) {
            Some(asset) if expected.contains(&asset.kind) => Ok(()),
            Some(asset) => Err(anyhow!(
                "{field} references manifest asset {value} of kind {:?}, expected one of {:?}",
                asset.kind,
                expected
            )),
            None => Err(anyhow!(
                "{field} references unknown asset manifest id: {value}"
            )),
        }
    } else {
        validate_scene_local_asset_path(field, value)
    }
}

fn validate_scene_collision_rules(
    rules: Option<&SceneCollisionRules>,
) -> Result<Option<std::collections::BTreeSet<String>>> {
    let Some(rules) = rules else {
        return Ok(None);
    };
    if rules.version != "2" {
        return Err(anyhow!("scene collisionRules version must be 2"));
    }
    validate_path_component("scene collisionRules defaultLayer", &rules.default_layer)?;
    if rules.layers.is_empty() {
        return Err(anyhow!("scene collisionRules layers must not be empty"));
    }
    let mut layer_ids = std::collections::BTreeSet::new();
    for layer in &rules.layers {
        validate_path_component("scene collisionRules layer id", &layer.id)?;
        if !layer_ids.insert(layer.id.clone()) {
            return Err(anyhow!(
                "duplicate scene collisionRules layer id: {}",
                layer.id
            ));
        }
        if !layer.solid && !layer.trigger_only {
            return Err(anyhow!(
                "scene collisionRules layer {} must be solid or triggerOnly",
                layer.id
            ));
        }
    }
    if !layer_ids.contains(&rules.default_layer) {
        return Err(anyhow!(
            "scene collisionRules defaultLayer references unknown layer: {}",
            rules.default_layer
        ));
    }
    for layer in &rules.layers {
        let mut collides_with = std::collections::BTreeSet::new();
        for target in &layer.collides_with {
            validate_path_component(
                &format!("scene collisionRules layer {} collidesWith", layer.id),
                target,
            )?;
            if !layer_ids.contains(target) {
                return Err(anyhow!(
                    "scene collisionRules layer {} collidesWith references unknown layer: {}",
                    layer.id,
                    target
                ));
            }
            if !collides_with.insert(target) {
                return Err(anyhow!(
                    "duplicate scene collisionRules layer {} collidesWith: {}",
                    layer.id,
                    target
                ));
            }
        }
    }
    Ok(Some(layer_ids))
}

fn validate_scene_gameplay_rules(
    rules: Option<&SceneGameplayRules>,
) -> Result<Option<BTreeSet<String>>> {
    let Some(rules) = rules else {
        return Ok(None);
    };
    if rules.version != "1" {
        return Err(anyhow!("scene gameplayRules version must be 1"));
    }
    if rules.flags.is_empty() {
        return Err(anyhow!("scene gameplayRules flags must not be empty"));
    }
    let mut flag_ids = BTreeSet::new();
    for flag in &rules.flags {
        validate_path_component("scene gameplayRules flag id", &flag.id)?;
        if !flag_ids.insert(flag.id.clone()) {
            return Err(anyhow!(
                "duplicate scene gameplayRules flag id: {}",
                flag.id
            ));
        }
        if let Some(label) = &flag.label {
            require_bounded_display_text(
                &format!("scene gameplayRules flag {} label", flag.id),
                label,
            )?;
        }
        if let Some(description) = &flag.description {
            require_bounded_display_text(
                &format!("scene gameplayRules flag {} description", flag.id),
                description,
            )?;
        }
    }
    Ok(Some(flag_ids))
}

fn validate_scene_transitions(transitions: &[SceneTransition]) -> Result<()> {
    let mut ids = BTreeSet::new();
    for transition in transitions {
        validate_path_component("scene transition id", &transition.id)?;
        if !ids.insert(transition.id.as_str()) {
            return Err(anyhow!("duplicate scene transition id: {}", transition.id));
        }
        validate_project_manifest_path(
            &format!("scene transition {} toScene", transition.id),
            &transition.to_scene,
        )?;
        if let Some(label) = &transition.label {
            require_bounded_display_text(
                &format!("scene transition {} label", transition.id),
                label,
            )?;
        }
    }
    Ok(())
}

fn validate_scene_collider(
    entity_id: &str,
    collider: &SceneCollider,
    collision_layers: Option<&std::collections::BTreeSet<String>>,
) -> Result<()> {
    if collider.shape != "aabb" {
        return Err(anyhow!(
            "scene entity {entity_id} collider shape must be aabb"
        ));
    }
    if !matches!(collider.body.as_str(), "static" | "dynamic" | "kinematic") {
        return Err(anyhow!(
            "scene entity {entity_id} collider body must be static, dynamic, or kinematic"
        ));
    }
    if collider.size.width <= 0 || collider.size.height <= 0 {
        return Err(anyhow!(
            "scene entity {entity_id} collider size must be positive"
        ));
    }
    if let Some(group) = &collider.collision_group {
        validate_path_component(
            &format!("scene entity {entity_id} collider collisionGroup"),
            group,
        )?;
        if let Some(layers) = collision_layers {
            if !layers.contains(group) {
                return Err(anyhow!(
                    "scene entity {entity_id} collider collisionGroup references unknown collisionRules layer: {group}"
                ));
            }
        }
    }
    let mut masks = std::collections::BTreeSet::new();
    for mask in &collider.collision_mask {
        validate_path_component(
            &format!("scene entity {entity_id} collider collisionMask"),
            mask,
        )?;
        if let Some(layers) = collision_layers {
            if !layers.contains(mask) {
                return Err(anyhow!(
                    "scene entity {entity_id} collider collisionMask references unknown collisionRules layer: {mask}"
                ));
            }
        }
        if !masks.insert(mask) {
            return Err(anyhow!(
                "duplicate scene entity {entity_id} collider collisionMask: {mask}"
            ));
        }
    }
    Ok(())
}

fn validate_scene_trigger(
    entity_id: &str,
    trigger: &SceneTrigger,
    gameplay_flags: Option<&BTreeSet<String>>,
) -> Result<()> {
    validate_path_component(&format!("scene entity {entity_id} trigger id"), &trigger.id)?;
    if !matches!(trigger.kind.as_str(), "overlap" | "interact" | "enter") {
        return Err(anyhow!(
            "scene entity {entity_id} trigger kind must be overlap, interact, or enter"
        ));
    }
    if let Some(flag) = &trigger.target_flag {
        validate_scene_flag_ref(
            &format!("scene entity {entity_id} trigger targetFlag"),
            flag,
            gameplay_flags,
        )?;
    }
    let mut required_flags = BTreeSet::new();
    for flag in &trigger.required_flags {
        validate_scene_flag_ref(
            &format!("scene entity {entity_id} trigger requiredFlags"),
            flag,
            gameplay_flags,
        )?;
        if !required_flags.insert(flag) {
            return Err(anyhow!(
                "duplicate scene entity {entity_id} trigger requiredFlags: {flag}"
            ));
        }
    }
    for action in &trigger.on_enter {
        if !matches!(action.kind.as_str(), "setFlag" | "clearFlag" | "hideEntity") {
            return Err(anyhow!(
                "scene entity {entity_id} trigger onEnter kind must be setFlag, clearFlag, or hideEntity"
            ));
        }
        if let Some(flag) = &action.flag {
            validate_scene_flag_ref(
                &format!("scene entity {entity_id} trigger action flag"),
                flag,
                gameplay_flags,
            )?;
        }
        if let Some(target_entity) = &action.entity_id {
            validate_path_component(
                &format!("scene entity {entity_id} trigger action entityId"),
                target_entity,
            )?;
        }
        if matches!(action.kind.as_str(), "setFlag" | "clearFlag") && action.flag.is_none() {
            return Err(anyhow!(
                "scene entity {entity_id} trigger action {} requires a flag",
                action.kind
            ));
        }
        if action.kind == "hideEntity" && action.entity_id.is_none() {
            return Err(anyhow!(
                "scene entity {entity_id} trigger action hideEntity requires entityId"
            ));
        }
    }
    Ok(())
}

fn validate_scene_status(
    field: &str,
    status: &SceneStatus,
    gameplay_flags: Option<&BTreeSet<String>>,
) -> Result<()> {
    if let Some(hit_points) = status.hit_points {
        if hit_points < 0 {
            return Err(anyhow!("{field} hitPoints must be non-negative"));
        }
    }
    if let Some(max_hit_points) = status.max_hit_points {
        if max_hit_points <= 0 {
            return Err(anyhow!("{field} maxHitPoints must be positive"));
        }
        if let Some(hit_points) = status.hit_points {
            if hit_points > max_hit_points {
                return Err(anyhow!("{field} hitPoints must not exceed maxHitPoints"));
            }
        }
    }
    validate_unique_path_components(field, "flags", &status.flags)?;
    for flag in &status.flags {
        validate_scene_flag_ref(&format!("{field} flags"), flag, gameplay_flags)?;
    }
    validate_unique_path_components(field, "states", &status.states)?;
    Ok(())
}

fn validate_scene_goal_flag(
    entity_id: &str,
    goal_flag: &SceneGoalFlag,
    gameplay_flags: Option<&BTreeSet<String>>,
) -> Result<()> {
    validate_scene_flag_ref(
        &format!("scene entity {entity_id} goalFlag flag"),
        &goal_flag.flag,
        gameplay_flags,
    )?;
    if let Some(label) = &goal_flag.label {
        require_bounded_display_text(&format!("scene entity {entity_id} goalFlag label"), label)?;
    }
    Ok(())
}

fn validate_scene_input_controller(field: &str, input: &SceneInputController) -> Result<()> {
    if !matches!(input.scheme.as_str(), "keyboard" | "arrows" | "wasd") {
        return Err(anyhow!("{field} scheme must be keyboard, arrows, or wasd"));
    }
    if let Some(move_speed) = input.move_speed {
        if move_speed <= 0 {
            return Err(anyhow!("{field} moveSpeed must be positive"));
        }
    }
    if let Some(jump_impulse) = input.jump_impulse {
        if jump_impulse <= 0 {
            return Err(anyhow!("{field} jumpImpulse must be positive"));
        }
    }
    validate_unique_path_components(field, "allowedActions", &input.allowed_actions)?;
    Ok(())
}

fn validate_scene_camera_target(entity_id: &str, camera_target: &SceneCameraTarget) -> Result<()> {
    if camera_target.weight <= 0 {
        return Err(anyhow!(
            "scene entity {entity_id} cameraTarget weight must be positive"
        ));
    }
    if let Some(dead_zone) = &camera_target.dead_zone {
        if dead_zone.width <= 0 || dead_zone.height <= 0 {
            return Err(anyhow!(
                "scene entity {entity_id} cameraTarget deadZone must be positive"
            ));
        }
    }
    Ok(())
}

fn validate_scene_ui_text(
    entity_id: &str,
    ui_text: &SceneUiText,
    gameplay_flags: Option<&BTreeSet<String>>,
) -> Result<()> {
    require_bounded_display_text(
        &format!("scene entity {entity_id} uiText text"),
        &ui_text.text,
    )?;
    if let Some(role) = &ui_text.role {
        validate_path_component(&format!("scene entity {entity_id} uiText role"), role)?;
    }
    if let Some(flag) = &ui_text.bind_flag {
        validate_scene_flag_ref(
            &format!("scene entity {entity_id} uiText bindFlag"),
            flag,
            gameplay_flags,
        )?;
    }
    Ok(())
}

fn validate_scene_hud_value(
    entity_id: &str,
    hud_value: &SceneHudValue,
    gameplay_flags: Option<&BTreeSet<String>>,
) -> Result<()> {
    if !matches!(
        hud_value.kind.as_str(),
        "score" | "health" | "inventory" | "key_count" | "goal" | "flag" | "text"
    ) {
        return Err(anyhow!(
            "scene entity {entity_id} hudValue kind must be score, health, inventory, key_count, goal, flag, or text"
        ));
    }
    require_bounded_display_text(
        &format!("scene entity {entity_id} hudValue label"),
        &hud_value.label,
    )?;
    require_bounded_display_text(
        &format!("scene entity {entity_id} hudValue value"),
        &hud_value.value,
    )?;
    if let Some(flag) = &hud_value.bind_flag {
        validate_scene_flag_ref(
            &format!("scene entity {entity_id} hudValue bindFlag"),
            flag,
            gameplay_flags,
        )?;
    }
    Ok(())
}

fn validate_scene_flag_ref(
    field: &str,
    value: &str,
    gameplay_flags: Option<&BTreeSet<String>>,
) -> Result<()> {
    validate_path_component(field, value)?;
    if let Some(flags) = gameplay_flags {
        if !flags.contains(value) {
            return Err(anyhow!(
                "{field} references unknown gameplayRules flag: {value}"
            ));
        }
    }
    Ok(())
}

fn validate_unique_path_components(field: &str, label: &str, values: &[String]) -> Result<()> {
    let mut seen = BTreeSet::new();
    for value in values {
        validate_path_component(&format!("{field} {label}"), value)?;
        if !seen.insert(value) {
            return Err(anyhow!("duplicate {field} {label}: {value}"));
        }
    }
    Ok(())
}

fn require_bounded_display_text(field: &str, value: &str) -> Result<()> {
    require_text(field, value)?;
    if value.chars().count() > 120 {
        return Err(anyhow!("{field} must be 120 characters or fewer"));
    }
    if value.chars().any(|ch| ch.is_control()) {
        return Err(anyhow!("{field} must not contain control characters"));
    }
    Ok(())
}
fn validate_scene_animation(
    entity_id: &str,
    animation: &SceneAnimation,
    manifest: Option<&AssetManifest>,
) -> Result<()> {
    if animation.mode != "sprite_frame" {
        return Err(anyhow!(
            "scene entity {entity_id} animation mode must be sprite_frame"
        ));
    }
    if animation.frame_duration == 0 {
        return Err(anyhow!(
            "scene entity {entity_id} animation frameDuration must be greater than 0"
        ));
    }
    if animation.frames.is_empty() && animation.clips.is_empty() {
        return Err(anyhow!(
            "scene entity {entity_id} animation frames or clips must not be empty"
        ));
    }
    for frame in &animation.frames {
        validate_scene_animation_frame(entity_id, "default", frame, manifest)?;
    }

    let mut clip_ids = std::collections::BTreeSet::new();
    for clip in &animation.clips {
        validate_path_component(
            &format!("scene entity {entity_id} animation clip id"),
            &clip.id,
        )?;
        if !clip_ids.insert(clip.id.clone()) {
            return Err(anyhow!(
                "duplicate scene entity {entity_id} animation clip id: {}",
                clip.id
            ));
        }
        if clip.frame_duration == 0 {
            return Err(anyhow!(
                "scene entity {entity_id} animation clip {} frameDuration must be greater than 0",
                clip.id
            ));
        }
        if clip.frames.is_empty() {
            return Err(anyhow!(
                "scene entity {entity_id} animation clip {} frames must not be empty",
                clip.id
            ));
        }
        for frame in &clip.frames {
            validate_scene_animation_frame(entity_id, &clip.id, frame, manifest)?;
        }
    }
    if let Some(current_clip) = &animation.current_clip {
        validate_path_component(
            &format!("scene entity {entity_id} animation currentClip"),
            current_clip,
        )?;
        // `currentClip` is a clip reference, so it is invalid when the animation
        // declares no clips at all (only the legacy `frames` list).
        if !clip_ids.contains(current_clip) {
            return Err(anyhow!(
                "scene entity {entity_id} animation currentClip references unknown clip: {current_clip}"
            ));
        }
    }
    if let Some(state) = &animation.state {
        if let Some(current_clip) = &state.current_clip {
            validate_path_component(
                &format!("scene entity {entity_id} animation state currentClip"),
                current_clip,
            )?;
            if !clip_ids.contains(current_clip) {
                return Err(anyhow!(
                    "scene entity {entity_id} animation state currentClip references unknown clip: {current_clip}"
                ));
            }
        }
        // Bound frameIndex against the clip the state actually selects (falling
        // back to the top-level currentClip, then the first clip), so a state
        // pointing at a short clip can't pass by borrowing a longer clip's length.
        let frame_count = state
            .current_clip
            .as_ref()
            .or(animation.current_clip.as_ref())
            .and_then(|clip_id| animation.clips.iter().find(|clip| clip.id == *clip_id))
            .or_else(|| animation.clips.first())
            .map(|clip| clip.frames.len())
            .unwrap_or(animation.frames.len());
        if frame_count > 0 && state.frame_index >= frame_count {
            return Err(anyhow!(
                "scene entity {entity_id} animation state frameIndex must be within current frame list"
            ));
        }
    }
    Ok(())
}

fn validate_scene_animation_frame(
    entity_id: &str,
    clip_id: &str,
    frame: &SceneAnimationFrame,
    manifest: Option<&AssetManifest>,
) -> Result<()> {
    validate_scene_color(&frame.color).with_context(|| {
        format!("scene entity {entity_id} animation clip {clip_id} frame color is invalid")
    })?;
    if let Some(asset) = &frame.asset {
        validate_scene_asset_ref(
            "scene animation frame asset",
            asset,
            manifest,
            &[AssetManifestKind::Image, AssetManifestKind::Sprite],
        )?;
    }
    Ok(())
}

fn validate_scene_audio(
    entity_id: &str,
    audio: &SceneAudio,
    manifest: Option<&AssetManifest>,
) -> Result<()> {
    if audio.events.is_empty() {
        return Err(anyhow!(
            "scene entity {entity_id} audio events must not be empty"
        ));
    }
    let mut names = std::collections::BTreeSet::new();
    for event in &audio.events {
        validate_path_component(
            &format!("scene entity {entity_id} audio event name"),
            &event.name,
        )?;
        if !names.insert(event.name.clone()) {
            return Err(anyhow!(
                "duplicate scene entity {entity_id} audio event: {}",
                event.name
            ));
        }
        if event.trigger != "scene_loaded" {
            return Err(anyhow!(
                "scene entity {entity_id} audio trigger must be scene_loaded"
            ));
        }
        if !matches!(event.action.as_str(), "play" | "stop") {
            return Err(anyhow!(
                "scene entity {entity_id} audio event {} action must be play or stop",
                event.name
            ));
        }
        if event.action == "play" && event.asset.is_none() {
            return Err(anyhow!(
                "scene entity {entity_id} audio event {} play action requires an asset ref",
                event.name
            ));
        }
        if let Some(asset) = &event.asset {
            validate_scene_asset_ref(
                "scene audio asset",
                asset,
                manifest,
                &[AssetManifestKind::Audio],
            )?;
        }
    }
    Ok(())
}

fn validate_scene_tags(entity_id: &str, tags: &[String]) -> Result<()> {
    let mut seen = std::collections::BTreeSet::new();
    for tag in tags {
        validate_path_component(&format!("scene entity {entity_id} tag"), tag)?;
        if !seen.insert(tag) {
            return Err(anyhow!("duplicate scene entity {entity_id} tag: {tag}"));
        }
    }
    Ok(())
}

fn validate_scene_metadata(field: &str, metadata: &serde_json::Value) -> Result<()> {
    if metadata.is_object() {
        Ok(())
    } else {
        Err(anyhow!("{field} must be a JSON object"))
    }
}

fn validate_scene_local_asset_path(field: &str, value: &str) -> Result<()> {
    require_text(field, value)?;
    let lowered = value.to_ascii_lowercase();
    if lowered.starts_with("http://") || lowered.starts_with("https://") {
        return Err(anyhow!("{field} must be a local static asset path"));
    }
    if !value.starts_with("assets/") {
        return Err(anyhow!("{field} must start with assets/"));
    }
    if !value
        .chars()
        .all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '/' | '.' | '-' | '_'))
    {
        return Err(anyhow!(
            "{field} may only contain ASCII letters, numbers, '/', '.', '-' or '_'"
        ));
    }
    let path = Path::new(value);
    if path.is_absolute() {
        return Err(anyhow!("{field} must be relative"));
    }
    for component in path.components() {
        match component {
            Component::Normal(_) | Component::CurDir => {}
            _ => {
                return Err(anyhow!(
                    "{field} must stay inside the local scene asset tree"
                ))
            }
        }
    }
    Ok(())
}

fn apply_scene_edit(scene: &mut SceneDocument, edit: SceneEdit) -> Result<()> {
    let entity = scene
        .entities
        .iter_mut()
        .find(|entity| entity.id == edit.entity_id)
        .ok_or_else(|| anyhow!("scene entity not found: {}", edit.entity_id))?;
    match edit.path.as_str() {
        "sprite.color" => entity.sprite.color = scene_edit_string(&edit.value, &edit.path)?,
        "components.transform.x" => {
            entity.components.transform.x = scene_edit_i64(&edit.value, &edit.path)?
        }
        "components.transform.y" => {
            entity.components.transform.y = scene_edit_i64(&edit.value, &edit.path)?
        }
        "components.velocity.x" => {
            entity.components.velocity.x = scene_edit_i64(&edit.value, &edit.path)?
        }
        "components.velocity.y" => {
            entity.components.velocity.y = scene_edit_i64(&edit.value, &edit.path)?
        }
        "components.size.width" => {
            entity.components.size.width = scene_edit_i64(&edit.value, &edit.path)?
        }
        "components.size.height" => {
            entity.components.size.height = scene_edit_i64(&edit.value, &edit.path)?
        }
        "components.controllable" => {
            entity.components.controllable = scene_edit_bool(&edit.value, &edit.path)?
        }
        "components.status.hitPoints" => {
            entity
                .components
                .status
                .as_mut()
                .ok_or_else(|| {
                    anyhow!("scene edit path `{}` requires status component", edit.path)
                })?
                .hit_points = Some(scene_edit_i64(&edit.value, &edit.path)?);
        }
        "components.status.maxHitPoints" => {
            entity
                .components
                .status
                .as_mut()
                .ok_or_else(|| {
                    anyhow!("scene edit path `{}` requires status component", edit.path)
                })?
                .max_hit_points = Some(scene_edit_i64(&edit.value, &edit.path)?);
        }
        "components.input.moveSpeed" => {
            entity
                .components
                .input
                .as_mut()
                .ok_or_else(|| anyhow!("scene edit path `{}` requires input component", edit.path))?
                .move_speed = Some(scene_edit_i64(&edit.value, &edit.path)?);
        }
        "components.input.jumpImpulse" => {
            entity
                .components
                .input
                .as_mut()
                .ok_or_else(|| anyhow!("scene edit path `{}` requires input component", edit.path))?
                .jump_impulse = Some(scene_edit_i64(&edit.value, &edit.path)?);
        }
        "components.cameraTarget.weight" => {
            entity
                .components
                .camera_target
                .as_mut()
                .ok_or_else(|| {
                    anyhow!(
                        "scene edit path `{}` requires cameraTarget component",
                        edit.path
                    )
                })?
                .weight = scene_edit_i64(&edit.value, &edit.path)?;
        }
        "components.uiText.text" => {
            entity
                .components
                .ui_text
                .as_mut()
                .ok_or_else(|| {
                    anyhow!("scene edit path `{}` requires uiText component", edit.path)
                })?
                .text = scene_edit_display_string(&edit.value, &edit.path)?;
        }
        _ => {
            return Err(anyhow!(
                "unsupported scene edit path `{}`; supported paths are {}",
                edit.path,
                supported_scene_edit_paths().join(", ")
            ));
        }
    }
    Ok(())
}

fn scene_edit_i64(value: &serde_json::Value, path: &str) -> Result<i64> {
    value
        .as_i64()
        .ok_or_else(|| anyhow!("scene edit path `{path}` requires an integer value"))
}

fn scene_edit_bool(value: &serde_json::Value, path: &str) -> Result<bool> {
    value
        .as_bool()
        .ok_or_else(|| anyhow!("scene edit path `{path}` requires a boolean value"))
}

fn scene_edit_string(value: &serde_json::Value, path: &str) -> Result<String> {
    let value = scene_edit_display_string(value, path)?;
    validate_scene_color(&value)?;
    Ok(value)
}

fn scene_edit_display_string(value: &serde_json::Value, path: &str) -> Result<String> {
    let value = value
        .as_str()
        .ok_or_else(|| anyhow!("scene edit path `{path}` requires a string value"))?
        .to_string();
    require_bounded_display_text(&format!("scene edit path `{path}`"), &value)?;
    Ok(value)
}

fn validate_scene_color(color: &str) -> Result<()> {
    let Some(hex) = color.strip_prefix('#') else {
        return Err(anyhow!("scene sprite color must be a #RRGGBB hex value"));
    };
    if hex.len() != 6 || !hex.chars().all(|ch| ch.is_ascii_hexdigit()) {
        return Err(anyhow!("scene sprite color must be a #RRGGBB hex value"));
    }
    Ok(())
}

