pub fn list_dashboard_runs(runs_root: impl AsRef<Path>) -> Result<Vec<RunDashboardSummary>> {
    let runs_root = runs_root.as_ref();
    if !runs_root.exists() {
        return Ok(Vec::new());
    }
    let mut runs = Vec::new();
    for entry in fs::read_dir(runs_root)
        .with_context(|| format!("failed to read runs root {}", runs_root.display()))?
    {
        let entry = entry.context("failed to read runs root entry")?;
        let path = entry.path();
        if !path.is_dir() || !path.join("run.json").is_file() {
            continue;
        }
        runs.push(read_dashboard_run_summary(&path)?);
    }
    runs.sort_by(|left, right| {
        right
            .created_at_unix_ms
            .cmp(&left.created_at_unix_ms)
            .then_with(|| left.id.cmp(&right.id))
    });
    Ok(runs)
}

pub fn build_regression_run_matrix(runs_root: impl AsRef<Path>) -> Result<RegressionRunMatrix> {
    let mut summaries = list_dashboard_runs(runs_root)?;
    summaries.sort_by(|left, right| {
        left.created_at_unix_ms
            .cmp(&right.created_at_unix_ms)
            .then_with(|| left.id.cmp(&right.id))
    });

    let mut skipped_runs = Vec::new();
    let mut scenarios: BTreeMap<(String, String, String), RegressionMatrixScenarioBuilder> =
        BTreeMap::new();
    let mut projects: BTreeMap<String, String> = BTreeMap::new();
    let mut packs: BTreeMap<(String, String), String> = BTreeMap::new();

    for summary in summaries {
        let Some(project) = summary.project.clone() else {
            skipped_runs.push(RegressionRunMatrixSkippedRun {
                run_id: summary.id.clone(),
                run_dir: summary.run_dir.to_string_lossy().to_string(),
                reason: "missing_or_malformed_project_context".to_string(),
            });
            continue;
        };
        let Some(pack) = project.scenario_pack.clone() else {
            skipped_runs.push(RegressionRunMatrixSkippedRun {
                run_id: summary.id.clone(),
                run_dir: summary.run_dir.to_string_lossy().to_string(),
                reason: "missing_scenario_pack_context".to_string(),
            });
            continue;
        };

        projects.insert(project.id.clone(), project.name.clone());
        packs.insert((project.id.clone(), pack.id.clone()), pack.path.clone());

        let run = read_dashboard_run(&summary.run_dir)?;
        let result_observations = dashboard_scenario_result_observations(&run);
        let expected_ids = pack
            .scenario_ids
            .iter()
            .cloned()
            .chain(result_observations.keys().cloned())
            .collect::<BTreeSet<_>>();

        for scenario_id in expected_ids {
            let key = (project.id.clone(), pack.id.clone(), scenario_id.clone());
            let builder = scenarios.entry(key).or_insert_with(|| {
                RegressionMatrixScenarioBuilder::new(
                    project.id.clone(),
                    pack.id.clone(),
                    scenario_id.clone(),
                )
            });
            builder.context.mutation_ids.extend(
                run.mutations
                    .iter()
                    .map(|mutation| mutation.id.clone())
                    .collect::<Vec<_>>(),
            );
            builder.context.review_decision_ids.extend(
                read_mutation_review_artifact(&summary.run_dir)
                    .map(|artifact| {
                        artifact
                            .decisions
                            .into_iter()
                            .map(|decision| decision.id)
                            .collect::<Vec<_>>()
                    })
                    .unwrap_or_default(),
            );
            builder.context.promotion_ids.extend(
                run.regression_promotions
                    .iter()
                    .filter(|promotion| promotion.scenario_id == scenario_id)
                    .map(|promotion| promotion.id.clone())
                    .collect::<Vec<_>>(),
            );

            let observation = result_observations
                .get(&scenario_id)
                .cloned()
                .unwrap_or_else(|| RegressionRunMatrixObservation {
                    run_id: summary.id.clone(),
                    run_dir: summary.run_dir.to_string_lossy().to_string(),
                    created_at_unix_ms: summary.created_at_unix_ms,
                    status: "pending".to_string(),
                    scenario_result_path: None,
                    verdict_status: summary.verdict_status.clone(),
                    evidence_refs: Vec::new(),
                });
            builder.runs.push(observation);
        }
    }

    let mut project_builders: BTreeMap<String, BTreeMap<String, Vec<RegressionRunMatrixScenario>>> =
        BTreeMap::new();
    for ((project_id, pack_id, _scenario_id), builder) in scenarios {
        project_builders
            .entry(project_id)
            .or_default()
            .entry(pack_id)
            .or_default()
            .push(builder.finish());
    }

    let projects = project_builders
        .into_iter()
        .map(|(project_id, pack_builders)| {
            let scenario_packs = pack_builders
                .into_iter()
                .map(|(pack_id, mut scenarios)| {
                    scenarios.sort_by(|left, right| left.scenario_id.cmp(&right.scenario_id));
                    RegressionRunMatrixScenarioPack {
                        scenario_pack_path: packs
                            .get(&(project_id.clone(), pack_id.clone()))
                            .cloned()
                            .unwrap_or_default(),
                        scenario_pack_id: pack_id,
                        scenarios,
                    }
                })
                .collect();
            RegressionRunMatrixProject {
                project_name: projects.get(&project_id).cloned().unwrap_or_default(),
                project_id,
                scenario_packs,
            }
        })
        .collect();

    Ok(RegressionRunMatrix {
        schema_version: "ouroforge-regression-run-matrix-v1".to_string(),
        projects,
        skipped_runs,
    })
}

#[derive(Debug, Clone)]
struct RegressionMatrixScenarioBuilder {
    scenario_id: String,
    runs: Vec<RegressionRunMatrixObservation>,
    context: RegressionRunMatrixContext,
}

impl RegressionMatrixScenarioBuilder {
    fn new(_project_id: String, _pack_id: String, scenario_id: String) -> Self {
        Self {
            scenario_id,
            runs: Vec::new(),
            context: RegressionRunMatrixContext::default(),
        }
    }

    fn finish(mut self) -> RegressionRunMatrixScenario {
        self.runs.sort_by(|left, right| {
            left.created_at_unix_ms
                .cmp(&right.created_at_unix_ms)
                .then_with(|| left.run_id.cmp(&right.run_id))
        });
        dedupe_sorted(&mut self.context.mutation_ids);
        dedupe_sorted(&mut self.context.review_decision_ids);
        dedupe_sorted(&mut self.context.promotion_ids);
        let current_status = self
            .runs
            .last()
            .map(|observation| observation.status.clone())
            .unwrap_or_else(|| "pending".to_string());
        let last_pass = self
            .runs
            .iter()
            .rev()
            .find(|observation| observation.status == "passed")
            .cloned();
        let last_fail = self
            .runs
            .iter()
            .rev()
            .find(|observation| observation.status == "failed")
            .cloned();
        RegressionRunMatrixScenario {
            scenario_id: self.scenario_id,
            current_status,
            last_pass,
            last_fail,
            runs: self.runs,
            context: self.context,
        }
    }
}

fn dedupe_sorted(values: &mut Vec<String>) {
    values.sort();
    values.dedup();
}

fn dashboard_scenario_result_observations(
    run: &RunDashboardReadModel,
) -> BTreeMap<String, RegressionRunMatrixObservation> {
    let mut observations = BTreeMap::new();
    for artifact in &run.scenario_results {
        let Some(value) = &artifact.value else {
            // An indexed scenario result that cannot be read or parsed must still
            // be surfaced (as unknown) rather than dropped; otherwise the matrix
            // falls back to a misleading "pending" with no evidence even though a
            // broken result artifact exists. Derive the scenario id from the
            // artifact path (evidence/scenarios/<id>/scenario-result*.json).
            if let Some(scenario_id) = scenario_id_from_scenario_result_path(&artifact.path) {
                observations.insert(
                    scenario_id,
                    RegressionRunMatrixObservation {
                        run_id: run.summary.id.clone(),
                        run_dir: run.summary.run_dir.to_string_lossy().to_string(),
                        created_at_unix_ms: run.summary.created_at_unix_ms,
                        status: "unknown".to_string(),
                        scenario_result_path: Some(artifact.path.clone()),
                        verdict_status: run.summary.verdict_status.clone(),
                        evidence_refs: vec![artifact.path.clone()],
                    },
                );
            }
            continue;
        };
        let Some(scenario_id) = value
            .get("scenario_id")
            .or_else(|| value.get("scenarioId"))
            .and_then(|value| value.as_str())
        else {
            continue;
        };
        let status = value
            .get("status")
            .and_then(|value| value.as_str())
            .filter(|status| matches!(*status, "passed" | "failed" | "pending"))
            .unwrap_or("failed")
            .to_string();
        let mut evidence_refs = vec![artifact.path.clone()];
        collect_dashboard_evidence_refs(value.get("evidence"), &mut evidence_refs);
        evidence_refs.sort();
        evidence_refs.dedup();
        observations.insert(
            scenario_id.to_string(),
            RegressionRunMatrixObservation {
                run_id: run.summary.id.clone(),
                run_dir: run.summary.run_dir.to_string_lossy().to_string(),
                created_at_unix_ms: run.summary.created_at_unix_ms,
                status,
                scenario_result_path: Some(artifact.path.clone()),
                verdict_status: run.summary.verdict_status.clone(),
                evidence_refs,
            },
        );
    }
    observations
}

fn collect_dashboard_evidence_refs(value: Option<&serde_json::Value>, output: &mut Vec<String>) {
    match value {
        Some(serde_json::Value::String(path)) => output.push(path.clone()),
        Some(serde_json::Value::Array(values)) => {
            for value in values {
                collect_dashboard_evidence_refs(Some(value), output);
            }
        }
        Some(serde_json::Value::Object(map)) => {
            for value in map.values() {
                collect_dashboard_evidence_refs(Some(value), output);
            }
        }
        _ => {}
    }
}

pub fn read_dashboard_run(run_dir: impl AsRef<Path>) -> Result<RunDashboardReadModel> {
    let run_dir = run_dir.as_ref();
    let summary = read_dashboard_run_summary(run_dir)?;
    let run = read_json_value(run_dir.join("run.json"))?;
    let verdict = read_json_value(run_dir.join("verdict.json"))?;
    let evidence = read_evidence_index(run_dir)?.artifacts;
    let mutations = list_mutation_proposals(run_dir)?;
    let journal_view = read_dashboard_journal(run_dir, &evidence, &mutations);
    let journal = if journal_view.exists {
        fs::read_to_string(run_dir.join("journal.md")).unwrap_or_default()
    } else {
        String::new()
    };
    let screenshots =
        select_dashboard_artifacts(run_dir, &evidence, dashboard_artifact_is_screenshot)?;
    let console_logs =
        select_dashboard_artifacts(run_dir, &evidence, dashboard_artifact_is_console_log)?;
    let cdp_trace_summaries =
        select_dashboard_artifacts(run_dir, &evidence, dashboard_artifact_is_cdp_trace_summary)?;
    let world_states =
        select_dashboard_artifacts(run_dir, &evidence, dashboard_artifact_is_world_state)?;
    let frame_metrics =
        select_dashboard_artifacts(run_dir, &evidence, dashboard_artifact_is_frame_metric)?;
    let performance_metrics =
        select_dashboard_artifacts(run_dir, &evidence, dashboard_artifact_is_performance_metric)?;
    let scenario_results =
        select_dashboard_artifacts(run_dir, &evidence, dashboard_artifact_is_scenario_result)?;
    let mutation_artifacts = select_dashboard_mutation_artifacts(run_dir)?;
    let mutation_lifecycle = read_dashboard_mutation_lifecycle(run_dir, &mutations);
    let regression_promotions = read_regression_promotion_records(run_dir);
    let review_cockpit = dashboard_review_cockpit(&mutation_lifecycle, &regression_promotions);
    let replay = read_dashboard_replay(run_dir, &evidence)?;
    let comparison = read_dashboard_comparison(run_dir);
    let transaction_provenance = read_dashboard_transaction_provenance(&run);
    let project = read_dashboard_project_context(&run);
    let command_context = read_dashboard_command_context(&run);
    let engine_summaries = read_dashboard_engine_summaries(&world_states);
    let asset_integrity = read_dashboard_asset_integrity(run_dir, &evidence)?;
    let probe_contract_status = dashboard_probe_contract_status(
        &evidence,
        &world_states,
        &frame_metrics,
        &scenario_results,
    );
    let evidence_categories = dashboard_category_summaries(DashboardCategoryArtifacts {
        screenshots: &screenshots,
        world_states: &world_states,
        frame_metrics: &frame_metrics,
        performance_metrics: &performance_metrics,
        console_logs: &console_logs,
        cdp_trace_summaries: &cdp_trace_summaries,
        scenario_results: &scenario_results,
        mutation_artifacts: &mutation_artifacts,
    });
    let evidence_fidelity = dashboard_evidence_fidelity(DashboardEvidenceFidelityInputs {
        transaction_provenance: transaction_provenance.as_ref(),
        probe_contract_status: &probe_contract_status,
        replay: &replay,
        screenshots: &screenshots,
        console_logs: &console_logs,
        performance_metrics: &performance_metrics,
        cdp_trace_summaries: &cdp_trace_summaries,
        command_context: command_context.as_ref(),
    });
    Ok(RunDashboardReadModel {
        summary,
        run,
        project,
        command_context,
        verdict,
        journal,
        journal_view,
        evidence,
        screenshots,
        console_logs,
        cdp_trace_summaries,
        world_states,
        frame_metrics,
        performance_metrics,
        scenario_results,
        mutation_artifacts,
        mutation_lifecycle,
        review_cockpit,
        regression_promotions,
        replay,
        comparison,
        transaction_provenance,
        engine_summaries,
        asset_integrity,
        evidence_categories,
        probe_contract_status,
        evidence_fidelity,
        mutations,
    })
}

fn read_dashboard_run_summary(run_dir: &Path) -> Result<RunDashboardSummary> {
    let run = read_json_value(run_dir.join("run.json"))?;
    let evidence = read_evidence_index(run_dir)?.artifacts;
    let evidence_count = evidence.len();
    let mutations = list_mutation_proposals(run_dir)?;
    let verdict = read_json_value(run_dir.join("verdict.json"))?;
    let mutation_artifacts = select_dashboard_mutation_artifacts(run_dir)?;
    let screenshots =
        select_dashboard_artifacts(run_dir, &evidence, dashboard_artifact_is_screenshot)?;
    let console_logs =
        select_dashboard_artifacts(run_dir, &evidence, dashboard_artifact_is_console_log)?;
    let cdp_trace_summaries =
        select_dashboard_artifacts(run_dir, &evidence, dashboard_artifact_is_cdp_trace_summary)?;
    let world_states =
        select_dashboard_artifacts(run_dir, &evidence, dashboard_artifact_is_world_state)?;
    let frame_metrics =
        select_dashboard_artifacts(run_dir, &evidence, dashboard_artifact_is_frame_metric)?;
    let performance_metrics =
        select_dashboard_artifacts(run_dir, &evidence, dashboard_artifact_is_performance_metric)?;
    let scenario_results =
        select_dashboard_artifacts(run_dir, &evidence, dashboard_artifact_is_scenario_result)?;
    let evidence_categories = dashboard_category_summaries(DashboardCategoryArtifacts {
        screenshots: &screenshots,
        world_states: &world_states,
        frame_metrics: &frame_metrics,
        performance_metrics: &performance_metrics,
        console_logs: &console_logs,
        cdp_trace_summaries: &cdp_trace_summaries,
        scenario_results: &scenario_results,
        mutation_artifacts: &mutation_artifacts,
    });
    let probe_contract_status = dashboard_probe_contract_status(
        &evidence,
        &world_states,
        &frame_metrics,
        &scenario_results,
    );
    let transaction_provenance = read_dashboard_transaction_provenance(&run);
    let command_context = read_dashboard_command_context(&run);
    let replay = read_dashboard_replay(run_dir, &evidence).unwrap_or_else(|_| RunDashboardReplay {
        present: false,
        empty_state: "Replay read model unavailable.".to_string(),
        sequences: Vec::new(),
    });
    let evidence_fidelity = dashboard_evidence_fidelity(DashboardEvidenceFidelityInputs {
        transaction_provenance: transaction_provenance.as_ref(),
        probe_contract_status: &probe_contract_status,
        replay: &replay,
        screenshots: &screenshots,
        console_logs: &console_logs,
        performance_metrics: &performance_metrics,
        cdp_trace_summaries: &cdp_trace_summaries,
        command_context: command_context.as_ref(),
    });
    let id = json_string(&run, "id").unwrap_or_else(|| {
        run_dir
            .file_name()
            .and_then(|name| name.to_str())
            .unwrap_or("unknown-run")
            .to_string()
    });
    Ok(RunDashboardSummary {
        id,
        run_dir: run_dir.to_path_buf(),
        seed_id: json_string(&run, "seed_id").unwrap_or_else(|| "unknown-seed".to_string()),
        seed_title: json_string(&run, "seed_title").unwrap_or_else(|| "Untitled Seed".to_string()),
        project: read_dashboard_project_context(&run),
        command_context,
        run_status: json_string(&run, "status").unwrap_or_else(|| "unknown".to_string()),
        verdict_status: json_string(&verdict, "status").unwrap_or_else(|| "unknown".to_string()),
        scenario_status: dashboard_scenario_status(&verdict),
        created_at_unix_ms: run
            .get("created_at_unix_ms")
            .and_then(|value| value.as_u64())
            .map(u128::from)
            .unwrap_or(0),
        evidence_count,
        mutation_count: mutations.len(),
        worker_count: dashboard_worker_count(&evidence),
        evidence_categories,
        probe_contract_status,
        evidence_fidelity,
        journal_path: run_dir.join("journal.md"),
    })
}

fn select_dashboard_artifacts(
    run_dir: &Path,
    evidence: &[EvidenceArtifact],
    predicate: fn(&EvidenceArtifact) -> bool,
) -> Result<Vec<RunDashboardArtifact>> {
    evidence
        .iter()
        .filter(|artifact| predicate(artifact))
        .map(|artifact| dashboard_artifact(run_dir, artifact))
        .collect()
}

fn dashboard_artifact(run_dir: &Path, artifact: &EvidenceArtifact) -> Result<RunDashboardArtifact> {
    dashboard_artifact_from_parts(
        run_dir,
        artifact.id.clone(),
        artifact.kind.clone(),
        artifact.path.clone(),
        artifact.metadata.clone(),
    )
}

fn dashboard_artifact_from_parts(
    run_dir: &Path,
    id: String,
    kind: String,
    path: String,
    metadata: serde_json::Value,
) -> Result<RunDashboardArtifact> {
    let absolute_path = run_dir.join(&path);
    let exists = absolute_path.is_file();
    let mut read_error = None;
    let value = if exists && (kind == "application/json" || path.ends_with(".json")) {
        match read_json_value(&absolute_path) {
            Ok(value) => Some(value),
            Err(error) => {
                read_error = Some(error.to_string());
                None
            }
        }
    } else if exists {
        None
    } else {
        read_error = Some(format!("missing artifact file: {path}"));
        None
    };
    Ok(RunDashboardArtifact {
        id,
        kind,
        path,
        metadata,
        value,
        exists,
        read_error,
    })
}

fn dashboard_artifact_is_screenshot(artifact: &EvidenceArtifact) -> bool {
    artifact.kind == "image/png" || artifact.path.ends_with(".png")
}

fn dashboard_artifact_is_console_log(artifact: &EvidenceArtifact) -> bool {
    artifact
        .metadata
        .get("artifact")
        .and_then(|value| value.as_str())
        == Some("console_log")
        || artifact.id.contains("console")
        || artifact.path.contains("console")
}

fn dashboard_artifact_is_cdp_trace_summary(artifact: &EvidenceArtifact) -> bool {
    artifact
        .metadata
        .get("artifact")
        .and_then(|value| value.as_str())
        == Some("cdp_trace_summary")
        || artifact.id.contains("cdp-trace")
        || artifact.path.contains("cdp-trace")
}

fn dashboard_probe_contract_status(
    evidence: &[EvidenceArtifact],
    world_states: &[RunDashboardArtifact],
    frame_metrics: &[RunDashboardArtifact],
    scenario_results: &[RunDashboardArtifact],
) -> RunDashboardProbeContractStatus {
    let mut evidence_refs = Vec::new();
    let mut observed_count = 0usize;
    for artifact in evidence {
        if artifact
            .metadata
            .get("probe_contract")
            .and_then(|value| value.get("version"))
            .and_then(|value| value.as_str())
            == Some(RUNTIME_PROBE_CONTRACT_VERSION)
        {
            observed_count += 1;
            evidence_refs.push(artifact.path.clone());
        }
    }
    let indexed_malformed_count = evidence
        .iter()
        .filter(|artifact| {
            artifact
                .metadata
                .get("artifact")
                .and_then(|value| value.as_str())
                == Some("runtime_probe_contract_failure")
                || artifact
                    .metadata
                    .get("probe_contract_failure")
                    .and_then(|value| value.as_bool())
                    == Some(true)
        })
        .count()
        + scenario_results
            .iter()
            .filter(|artifact| {
                artifact
                    .value
                    .as_ref()
                    .is_some_and(|value| value.get("probe_contract_failure").is_some())
            })
            .count();
    let malformed_artifact_count = world_states
        .iter()
        .chain(frame_metrics.iter())
        .chain(scenario_results.iter())
        .filter(|artifact| artifact.exists && artifact.read_error.is_some())
        .count();
    let malformed_count = indexed_malformed_count + malformed_artifact_count;
    let has_world_v2 = world_states
        .iter()
        .any(dashboard_artifact_has_readable_probe_contract_v2);
    let has_frame_v2 = frame_metrics
        .iter()
        .any(dashboard_artifact_has_readable_probe_contract_v2);
    let missing_artifact_count = world_states
        .iter()
        .chain(frame_metrics.iter())
        .chain(scenario_results.iter())
        .filter(|artifact| !artifact.exists)
        .count();
    let missing_count =
        usize::from(!has_world_v2) + usize::from(!has_frame_v2) + missing_artifact_count;
    let status = if malformed_count > 0 {
        "malformed"
    } else if has_world_v2 && has_frame_v2 && missing_artifact_count == 0 {
        "present"
    } else if observed_count > 0 {
        "partial"
    } else {
        "legacy"
    };
    RunDashboardProbeContractStatus {
        status: status.to_string(),
        contract_name: RUNTIME_PROBE_CONTRACT_NAME.to_string(),
        version: RUNTIME_PROBE_CONTRACT_VERSION.to_string(),
        observed_count,
        missing_count,
        malformed_count,
        evidence_refs,
    }
}

fn dashboard_artifact_has_readable_probe_contract_v2(artifact: &RunDashboardArtifact) -> bool {
    artifact.exists
        && artifact.read_error.is_none()
        && dashboard_artifact_has_probe_contract_v2(artifact)
}

fn dashboard_artifact_has_probe_contract_v2(artifact: &RunDashboardArtifact) -> bool {
    artifact
        .metadata
        .get("probe_contract")
        .and_then(|value| value.get("version"))
        .and_then(|value| value.as_str())
        == Some(RUNTIME_PROBE_CONTRACT_VERSION)
}

fn dashboard_artifact_is_world_state(artifact: &EvidenceArtifact) -> bool {
    artifact
        .metadata
        .get("artifact")
        .and_then(|value| value.as_str())
        == Some("world_state")
        || artifact
            .metadata
            .get("probe_call")
            .and_then(|value| value.as_str())
            == Some("getWorldState")
        || artifact.id.contains("world-state")
        || artifact.path.contains("world-state")
}

fn dashboard_artifact_is_asset_reference_integrity(artifact: &EvidenceArtifact) -> bool {
    artifact
        .metadata
        .get("artifact")
        .and_then(|value| value.as_str())
        == Some("asset_reference_integrity")
        || artifact.id.contains("asset-reference-integrity")
        || artifact.path.contains("asset-reference-integrity")
}

fn read_dashboard_asset_integrity(
    run_dir: &Path,
    evidence: &[EvidenceArtifact],
) -> Result<RunDashboardAssetIntegrity> {
    let artifacts = select_dashboard_artifacts(
        run_dir,
        evidence,
        dashboard_artifact_is_asset_reference_integrity,
    )?;
    if artifacts.is_empty() {
        return Ok(RunDashboardAssetIntegrity {
            present: false,
            empty_state: "No asset reference integrity evidence is indexed for this run."
                .to_string(),
            warning_count: 0,
            stale_hash_count: 0,
            missing_ref_count: 0,
            invalid_type_count: 0,
            evidence_refs: Vec::new(),
            warnings: Vec::new(),
            artifacts,
        });
    }

    let mut warnings = Vec::new();
    let mut evidence_refs = Vec::new();
    for artifact in &artifacts {
        evidence_refs.push(artifact.path.clone());
        if let Some(value) = &artifact.value {
            if let Some(items) = value.get("warnings").and_then(|value| value.as_array()) {
                for item in items {
                    if let Ok(warning) = serde_json::from_value::<
                        ProjectAssetReferenceIntegrityWarning,
                    >(item.clone())
                    {
                        warnings.push(warning);
                    }
                }
            }
        }
    }
    warnings.sort_by(|left, right| {
        (
            left.kind.as_str(),
            left.field.as_str(),
            left.asset_id.as_str(),
        )
            .cmp(&(
                right.kind.as_str(),
                right.field.as_str(),
                right.asset_id.as_str(),
            ))
    });
    warnings.dedup_by(|left, right| {
        left.kind == right.kind && left.field == right.field && left.asset_id == right.asset_id
    });
    evidence_refs.sort();
    evidence_refs.dedup();
    let warning_count = warnings.len();
    let stale_hash_count = warnings
        .iter()
        .filter(|warning| warning.kind == "stale_asset_hash")
        .count();
    let missing_ref_count = warnings
        .iter()
        .filter(|warning| {
            matches!(
                warning.kind.as_str(),
                "missing_asset_ref" | "missing_asset_file"
            )
        })
        .count();
    let invalid_type_count = warnings
        .iter()
        .filter(|warning| warning.kind == "invalid_asset_type")
        .count();
    Ok(RunDashboardAssetIntegrity {
        present: true,
        empty_state: String::new(),
        warning_count,
        stale_hash_count,
        missing_ref_count,
        invalid_type_count,
        evidence_refs,
        warnings,
        artifacts,
    })
}

fn dashboard_artifact_is_frame_metric(artifact: &EvidenceArtifact) -> bool {
    artifact
        .metadata
        .get("probe_call")
        .and_then(|value| value.as_str())
        == Some("getFrameStats")
        || artifact.id.contains("frame-stats")
        || artifact.path.contains("frame-stats")
}

fn dashboard_artifact_is_performance_metric(artifact: &EvidenceArtifact) -> bool {
    artifact
        .metadata
        .get("artifact")
        .and_then(|value| value.as_str())
        == Some("performance_metrics")
        || artifact.id.contains("performance")
        || artifact.path.contains("metrics")
}

fn dashboard_artifact_is_scenario_result(artifact: &EvidenceArtifact) -> bool {
    artifact
        .metadata
        .get("artifact")
        .and_then(|value| value.as_str())
        == Some("scenario_result")
        || artifact.id.contains("scenario-result")
        || artifact.path.contains("scenario-result")
}

fn dashboard_artifact_is_input_replay(artifact: &EvidenceArtifact) -> bool {
    matches!(
        artifact
            .metadata
            .get("artifact")
            .and_then(|value| value.as_str()),
        Some("input_replay") | Some("scenario_input_replay")
    ) || artifact.id.contains("input-replay")
        || artifact.path.contains("input-replay")
        || artifact.id.contains("scenario-input-replay")
        || artifact.path.contains("scenario-input-replay")
}

fn read_dashboard_replay(
    run_dir: &Path,
    evidence: &[EvidenceArtifact],
) -> Result<RunDashboardReplay> {
    let replay_artifacts =
        select_dashboard_artifacts(run_dir, evidence, dashboard_artifact_is_input_replay)?;
    if replay_artifacts.is_empty() {
        return Ok(RunDashboardReplay {
            present: false,
            empty_state: "No replay evidence artifacts were found for this run.".to_string(),
            sequences: Vec::new(),
        });
    }
    let scenario_results =
        select_dashboard_artifacts(run_dir, evidence, dashboard_artifact_is_scenario_result)?;
    let mut sequences = Vec::new();
    for artifact in replay_artifacts {
        let scenario_id = dashboard_artifact_scenario_id(&artifact);
        let replay_value = artifact
            .value
            .as_ref()
            .and_then(dashboard_replay_payload_value);
        let frames = replay_value.map_or_else(Vec::new, dashboard_replay_frames);
        let replay_id = replay_value
            .and_then(|value| json_string(value, "id"))
            .unwrap_or_else(|| artifact.id.clone());
        let event_count = replay_value
            .and_then(|value| value.get("events"))
            .and_then(|value| value.as_array())
            .map_or_else(
                || {
                    usize::from(
                        replay_value
                            .and_then(|value| value.get("schemaVersion"))
                            .and_then(|value| value.as_str())
                            == Some(SCENARIO_INPUT_REPLAY_ARTIFACT_SCHEMA_VERSION),
                    )
                },
                Vec::len,
            );
        let source = dashboard_replay_source(&artifact);
        let evidence_refs = std::iter::once(artifact.path.clone())
            .chain(
                scenario_results
                    .iter()
                    .filter(|result| {
                        dashboard_artifact_matches_scenario(result, scenario_id.as_deref())
                    })
                    .map(|result| result.path.clone()),
            )
            .collect::<Vec<_>>();
        sequences.push(RunDashboardReplaySequence {
            id: replay_id,
            source,
            scenario_id: scenario_id.clone(),
            replay_path: artifact.path.clone(),
            event_count,
            first_frame: frames.first().copied(),
            last_frame: frames.last().copied(),
            frames,
            evidence_refs,
            checkpoints: dashboard_replay_checkpoints(
                run_dir,
                scenario_id.as_deref(),
                &scenario_results,
            ),
            read_error: artifact.read_error.clone(),
        });
    }
    Ok(RunDashboardReplay {
        present: sequences
            .iter()
            .any(|sequence| sequence.read_error.is_none()),
        empty_state: if sequences
            .iter()
            .any(|sequence| sequence.read_error.is_none())
        {
            String::new()
        } else {
            "Replay evidence artifacts were indexed, but no readable replay files are available."
                .to_string()
        },
        sequences,
    })
}

fn dashboard_replay_payload_value(value: &serde_json::Value) -> Option<&serde_json::Value> {
    value.get("replay").unwrap_or(value).as_object()?;
    Some(value.get("replay").unwrap_or(value))
}

fn dashboard_replay_frames(replay: &serde_json::Value) -> Vec<u64> {
    let mut frames = replay
        .get("events")
        .and_then(|value| value.as_array())
        .map(|events| {
            events
                .iter()
                .filter_map(|event| event.get("frame").and_then(|value| value.as_u64()))
                .collect::<Vec<_>>()
        })
        .unwrap_or_else(|| {
            replay
                .get("frame")
                .and_then(|value| value.as_u64())
                .into_iter()
                .collect()
        });
    frames.sort_unstable();
    frames.dedup();
    frames
}

fn dashboard_replay_source(artifact: &RunDashboardArtifact) -> String {
    artifact
        .metadata
        .get("source")
        .and_then(|value| value.as_str())
        .map(str::to_string)
        .or_else(|| {
            artifact
                .value
                .as_ref()
                .and_then(|value| value.get("action"))
                .and_then(|value| value.get("kind"))
                .and_then(|value| value.as_str())
                .map(str::to_string)
        })
        .or_else(|| {
            artifact
                .value
                .as_ref()
                .and_then(|value| value.get("reference"))
                .map(|_| "replayRef".to_string())
        })
        .unwrap_or_else(|| "inline".to_string())
}

fn dashboard_artifact_scenario_id(artifact: &RunDashboardArtifact) -> Option<String> {
    artifact
        .metadata
        .get("scenario_id")
        .and_then(|value| value.as_str())
        .map(str::to_string)
        .or_else(|| dashboard_scenario_id_from_path(&artifact.path))
}

fn dashboard_scenario_id_from_path(path: &str) -> Option<String> {
    let mut parts = path.split('/');
    while let Some(part) = parts.next() {
        if part == "scenarios" {
            return parts.next().map(str::to_string);
        }
    }
    None
}

fn dashboard_artifact_matches_scenario(
    artifact: &RunDashboardArtifact,
    scenario_id: Option<&str>,
) -> bool {
    match scenario_id {
        Some(expected) => dashboard_artifact_scenario_id(artifact).as_deref() == Some(expected),
        None => true,
    }
}

fn dashboard_replay_checkpoints(
    run_dir: &Path,
    scenario_id: Option<&str>,
    scenario_results: &[RunDashboardArtifact],
) -> Vec<RunDashboardReplayCheckpoint> {
    scenario_results
        .iter()
        .filter(|result| dashboard_artifact_matches_scenario(result, scenario_id))
        .filter_map(|result| {
            let value = result.value.as_ref()?;
            let evidence = value.get("evidence")?;
            let world_state_path = evidence
                .get("world_state")
                .and_then(|value| value.as_str())
                .map(str::to_string);
            let frame_stats_path = evidence
                .get("frame_stats")
                .and_then(|value| value.as_str())
                .map(str::to_string);
            // These refs come from scenario-result JSON, which may be external or
            // malformed; unlike evidence-index paths they are otherwise unchecked.
            // Constrain them to the run's evidence tree before reading so a value
            // like "../../secret.json" cannot disclose arbitrary files.
            let world_state = world_state_path
                .as_ref()
                .filter(|path| validate_evidence_artifact_path(path.as_str()).is_ok())
                .and_then(|path| read_json_value(run_dir.join(path)).ok());
            let frame_stats = frame_stats_path
                .as_ref()
                .filter(|path| validate_evidence_artifact_path(path.as_str()).is_ok())
                .and_then(|path| read_json_value(run_dir.join(path)).ok());
            let tick = world_state
                .as_ref()
                .and_then(|value| value.get("tick"))
                .and_then(|value| value.as_u64())
                .or_else(|| {
                    frame_stats
                        .as_ref()
                        .and_then(|value| value.get("tick"))
                        .and_then(|value| value.as_u64())
                });
            let frame = frame_stats
                .as_ref()
                .and_then(|value| value.get("frame"))
                .and_then(|value| value.as_u64())
                .or(tick);
            let checkpoint_id = format!(
                "{}-checkpoint",
                json_string(value, "scenario_id")
                    .or_else(|| dashboard_artifact_scenario_id(result))
                    .unwrap_or_else(|| result.id.clone())
            );
            Some(RunDashboardReplayCheckpoint {
                id: checkpoint_id,
                label: "Post-replay world state".to_string(),
                frame,
                tick,
                world_state_path,
                frame_stats_path,
                world_state,
            })
        })
        .collect()
}

fn dashboard_array_len(value: Option<&serde_json::Value>) -> usize {
    value
        .and_then(|candidate| candidate.as_array())
        .map_or(0, Vec::len)
}

fn dashboard_entities_with_component(world_state: &serde_json::Value, component: &str) -> usize {
    world_state
        .get("entities")
        .and_then(|entities| entities.as_array())
        .map(|entities| {
            entities
                .iter()
                .filter(|entity| {
                    entity
                        .get("components")
                        .and_then(|components| components.get(component))
                        .is_some()
                })
                .count()
        })
        .unwrap_or(0)
}

fn dashboard_component_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let mut counts = BTreeMap::<String, usize>::new();
    let mut entities = Vec::new();
    if let Some(items) = world_state
        .get("entities")
        .and_then(|value| value.as_array())
    {
        for entity in items {
            let entity_id = entity
                .get("id")
                .and_then(|value| value.as_str())
                .unwrap_or("unknown");
            let components = entity
                .get("components")
                .and_then(|value| value.as_object())
                .map(|components| {
                    let mut names = components.keys().cloned().collect::<Vec<_>>();
                    names.sort();
                    for name in &names {
                        *counts.entry(name.clone()).or_default() += 1;
                    }
                    names
                })
                .unwrap_or_default();
            entities.push(json!({ "entityId": entity_id, "components": components }));
        }
    }
    if let Some(model_counts) = world_state
        .pointer("/componentModel/counts")
        .and_then(|value| value.as_object())
    {
        for (name, count) in model_counts {
            if let Some(count) = count.as_u64() {
                counts.insert(name.clone(), count as usize);
            }
        }
    }
    json!({
        "present": !counts.is_empty() || !entities.is_empty(),
        "entityCount": entities.len(),
        "componentCounts": counts,
        "entities": entities
    })
}

fn dashboard_trigger_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let triggers = world_state
        .get("entities")
        .and_then(|entities| entities.as_array())
        .map(|entities| {
            entities
                .iter()
                .filter_map(|entity| {
                    let trigger = entity.pointer("/components/trigger")?;
                    Some(json!({
                        "entityId": entity.get("id").cloned().unwrap_or(json!(null)),
                        "id": trigger.get("id").cloned().unwrap_or(json!(null)),
                        "kind": trigger.get("kind").cloned().unwrap_or(json!(null)),
                        "targetFlag": trigger.get("targetFlag").cloned().unwrap_or(json!(null)),
                        "requiredFlags": trigger.get("requiredFlags").cloned().unwrap_or(json!([])),
                        "onEnterCount": dashboard_array_len(trigger.get("onEnter")),
                    }))
                })
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    json!({
        "present": !triggers.is_empty(),
        "triggerCount": triggers.len(),
        "triggerCollisionEventCount": world_state
            .get("collisionEvents")
            .and_then(|events| events.as_array())
            .map(|events| {
                events
                    .iter()
                    .filter(|event| {
                        event.get("type").and_then(|value| value.as_str())
                            == Some("runtime.collision.trigger")
                    })
                    .count()
            })
            .unwrap_or(0),
        "triggers": triggers
    })
}

fn dashboard_hud_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let values = world_state
        .pointer("/componentModel/hudValues")
        .and_then(|value| value.as_array())
        .cloned()
        .unwrap_or_default();
    json!({
        "present": !values.is_empty() || dashboard_entities_with_component(world_state, "hudValue") > 0,
        "hudValueCount": values.len(),
        "hudValueEntityCount": world_state.pointer("/componentModel/counts/hudValue")
            .cloned()
            .unwrap_or_else(|| json!(dashboard_entities_with_component(world_state, "hudValue"))),
        "values": values
    })
}

fn dashboard_tilemap_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let tilemaps = world_state
        .pointer("/tilemaps/tilemaps")
        .and_then(|value| value.as_array())
        .cloned()
        .unwrap_or_default();
    let mut collision_cells = 0usize;
    let mut trigger_cells = 0usize;
    let mut hazard_cells = 0usize;
    let mut goal_cells = 0usize;
    let mut summaries = Vec::new();
    for tilemap in &tilemaps {
        let authoring = tilemap.get("authoring").cloned().unwrap_or(json!({}));
        let tilemap_collision_cells = dashboard_array_len(authoring.get("collisionCells"));
        let tilemap_trigger_cells = dashboard_array_len(authoring.get("triggerCells"));
        let tilemap_hazard_cells = dashboard_array_len(authoring.get("hazardCells"));
        let tilemap_goal_cells = dashboard_array_len(authoring.get("goalCells"));
        collision_cells += tilemap_collision_cells;
        trigger_cells += tilemap_trigger_cells;
        hazard_cells += tilemap_hazard_cells;
        goal_cells += tilemap_goal_cells;
        summaries.push(json!({
            "id": tilemap.get("id").cloned().unwrap_or(json!(null)),
            "grid": tilemap.get("grid").cloned().unwrap_or(json!({})),
            "tileCount": tilemap.get("tileCount").cloned().unwrap_or(json!(0)),
            "layerCount": dashboard_array_len(tilemap.get("layers")),
            "authoring": {
                "collisionCellCount": tilemap_collision_cells,
                "triggerCellCount": tilemap_trigger_cells,
                "hazardCellCount": tilemap_hazard_cells,
                "goalCellCount": tilemap_goal_cells,
                "collisionCells": authoring.get("collisionCells").cloned().unwrap_or(json!([])),
                "triggerCells": authoring.get("triggerCells").cloned().unwrap_or(json!([])),
                "hazardCells": authoring.get("hazardCells").cloned().unwrap_or(json!([])),
                "goalCells": authoring.get("goalCells").cloned().unwrap_or(json!([]))
            }
        }));
    }
    json!({
        "present": world_state.get("tilemaps").is_some(),
        "tilemapCount": tilemaps.len(),
        "layerCount": dashboard_array_len(world_state.pointer("/tilemaps/layerOrder")),
        "authoring": {
            "present": collision_cells > 0 || trigger_cells > 0 || hazard_cells > 0 || goal_cells > 0,
            "collisionCellCount": collision_cells,
            "triggerCellCount": trigger_cells,
            "hazardCellCount": hazard_cells,
            "goalCellCount": goal_cells
        },
        "tilemaps": summaries
    })
}

fn dashboard_collision_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let rules_present = world_state.get("collisionRules").is_some();
    json!({
        "present": rules_present
            || world_state.get("collisions").is_some()
            || world_state.get("collisionEvents").is_some()
            || dashboard_entities_with_component(world_state, "collider") > 0,
        "rules": world_state.get("collisionRules").cloned().unwrap_or(json!({})),
        "colliderEntityCount": dashboard_entities_with_component(world_state, "collider"),
        "collisionCount": dashboard_array_len(world_state.get("collisions")),
        "collisionEventCount": dashboard_array_len(world_state.get("collisionEvents")),
        "events": world_state.get("collisionEvents").cloned().unwrap_or(json!([]))
    })
}

fn dashboard_transition_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let transition_events = world_state
        .get("transitionEvents")
        .cloned()
        .unwrap_or(json!([]));
    let declared_transitions = world_state
        .get("sceneTransitions")
        .cloned()
        .unwrap_or(json!([]));
    json!({
        "present": world_state.get("sceneId").is_some()
            || world_state.get("reloads").is_some()
            || transition_events.as_array().is_some_and(|events| !events.is_empty())
            || declared_transitions.as_array().is_some_and(|transitions| !transitions.is_empty()),
        "currentSceneId": world_state.get("sceneId").cloned().unwrap_or(json!(null)),
        "declaredTransitionCount": declared_transitions.as_array().map_or(0, Vec::len),
        "declaredTransitions": declared_transitions,
        "transitionEventCount": transition_events.as_array().map_or(0, Vec::len),
        "transitions": transition_events,
        "reloadCount": dashboard_array_len(world_state.get("reloads")),
        "lastReloadStatus": world_state.get("reloads")
            .and_then(|reloads| reloads.as_array())
            .and_then(|reloads| reloads.last())
            .and_then(|reload| reload.get("status"))
            .cloned()
            .unwrap_or(json!(null))
    })
}

fn dashboard_runtime_event_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let audio_events = world_state.get("audioEvents").cloned().unwrap_or(json!([]));
    let collision_events = world_state
        .get("collisionEvents")
        .cloned()
        .unwrap_or(json!([]));
    let animation_entities = world_state
        .get("entities")
        .and_then(|entities| entities.as_array())
        .map(|entities| {
            entities
                .iter()
                .filter_map(|entity| {
                    let animation = entity.pointer("/components/animation")?;
                    Some(json!({
                        "entityId": entity.get("id").cloned().unwrap_or(json!(null)),
                        "mode": animation.get("mode").cloned().unwrap_or(json!(null)),
                        "currentClip": animation
                            .get("currentClip")
                            .cloned()
                            .or_else(|| animation.pointer("/state/currentClip").cloned())
                            .unwrap_or(json!(null)),
                        "frameIndex": animation.pointer("/state/frameIndex").cloned().unwrap_or(json!(null)),
                    }))
                })
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    json!({
        "present": !animation_entities.is_empty()
            || audio_events.as_array().is_some_and(|events| !events.is_empty())
            || collision_events.as_array().is_some_and(|events| !events.is_empty()),
        "animationEntityCount": animation_entities.len(),
        "audioEventCount": audio_events.as_array().map_or(0, Vec::len),
        "collisionEventCount": collision_events.as_array().map_or(0, Vec::len),
        "animationEntities": animation_entities,
        "audioEvents": audio_events,
        "collisionEvents": collision_events
    })
}

fn read_dashboard_transaction_provenance(
    run: &serde_json::Value,
) -> Option<RunTransactionProvenance> {
    run.get("transaction_provenance")
        .cloned()
        .and_then(|value| serde_json::from_value(value).ok())
}

fn read_dashboard_command_context(run: &serde_json::Value) -> Option<RunCommandContext> {
    run.get("run_command_context")
        .cloned()
        .and_then(|value| serde_json::from_value(value).ok())
}

fn read_dashboard_project_context(run: &serde_json::Value) -> Option<ProjectRunMetadata> {
    run.get("project")
        .cloned()
        .and_then(|value| serde_json::from_value(value).ok())
}

fn read_dashboard_engine_summaries(
    world_states: &[RunDashboardArtifact],
) -> RunDashboardEngineSummaries {
    let source = world_states.iter().find(|artifact| {
        artifact.exists && artifact.read_error.is_none() && artifact.value.is_some()
    });
    let Some(artifact) = source else {
        return RunDashboardEngineSummaries {
            present: false,
            empty_state:
                "No readable world-state artifacts are available for Engine Expansion summaries."
                    .to_string(),
            source_world_state: None,
            scene: json!({}),
            components: json!({}),
            renderer: json!({}),
            tilemaps: json!({}),
            assets: json!({}),
            animation: json!({}),
            audio: json!({}),
            physics: json!({}),
            collision: json!({}),
            gameplay: json!({}),
            triggers: json!({}),
            hud: json!({}),
            transition: json!({}),
            events: json!({}),
            reload: json!({}),
            composition: json!({}),
        };
    };
    let world_state = artifact.value.as_ref().expect("checked world-state value");
    let entities = dashboard_array_len(world_state.get("entities"));
    RunDashboardEngineSummaries {
        present: true,
        empty_state: String::new(),
        source_world_state: Some(artifact.path.clone()),
        scene: json!({
            "sceneId": world_state.get("sceneId").cloned().unwrap_or(json!(null)),
            "schemaVersion": world_state.get("schemaVersion").cloned().unwrap_or(json!(null)),
            "entityCount": entities,
            "tick": world_state.get("tick").cloned().unwrap_or(json!(null))
        }),
        components: dashboard_component_summary(world_state),
        renderer: json!({
            "present": world_state.get("renderer").is_some(),
            "version": world_state.pointer("/renderer/version").cloned().unwrap_or(json!(null)),
            "renderedEntities": dashboard_array_len(world_state.pointer("/renderer/renderedEntities")),
            "camera": world_state.pointer("/renderer/camera").cloned().unwrap_or(json!(null))
        }),
        tilemaps: dashboard_tilemap_summary(world_state),
        assets: json!({
            "manifestId": world_state.pointer("/assetManifest/id").cloned().unwrap_or(json!(null)),
            "assetCount": dashboard_array_len(world_state.get("assets")),
            "manifestAssetCount": world_state.pointer("/assetManifest/assetCount").cloned().unwrap_or(json!(null))
        }),
        animation: json!({
            "animatedEntityCount": dashboard_entities_with_component(world_state, "animation")
        }),
        audio: json!({
            "audioEventCount": dashboard_array_len(world_state.get("audioEvents")),
            "audioEntityCount": dashboard_entities_with_component(world_state, "audio")
        }),
        physics: json!({
            "collisionCount": dashboard_array_len(world_state.get("collisions")),
            "collisionEventCount": dashboard_array_len(world_state.get("collisionEvents")),
            "colliderEntityCount": dashboard_entities_with_component(world_state, "collider")
        }),
        collision: dashboard_collision_summary(world_state),
        gameplay: dashboard_gameplay_summary(world_state),
        triggers: dashboard_trigger_summary(world_state),
        hud: dashboard_hud_summary(world_state),
        transition: dashboard_transition_summary(world_state),
        events: dashboard_runtime_event_summary(world_state),
        reload: json!({
            "reloadCount": dashboard_array_len(world_state.get("reloads")),
            "lastStatus": world_state.get("reloads")
                .and_then(|reloads| reloads.as_array())
                .and_then(|reloads| reloads.last())
                .and_then(|reload| reload.get("status"))
                .cloned()
                .unwrap_or(json!(null))
        }),
        composition: json!({
            "present": world_state.get("composition").is_some(),
            "entityCount": dashboard_array_len(world_state.pointer("/composition/entities")),
            "parentedEntityCount": world_state
                .pointer("/composition/entities")
                .and_then(|entities| entities.as_array())
                .map(|entities| entities.iter().filter(|entity| entity.get("parent").is_some_and(|parent| !parent.is_null())).count())
                .unwrap_or(0)
        }),
    }
}

fn dashboard_gameplay_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let flag_entries = world_state
        .get("goalFlags")
        .and_then(|value| value.as_object())
        .map(|flags| {
            let mut entries = flags
                .iter()
                .map(|(id, value)| json!({ "id": id, "value": value.as_bool().unwrap_or(false) }))
                .collect::<Vec<_>>();
            entries.sort_by(|left, right| {
                left.get("id")
                    .and_then(|value| value.as_str())
                    .cmp(&right.get("id").and_then(|value| value.as_str()))
            });
            entries
        })
        .unwrap_or_default();
    let true_flags = flag_entries
        .iter()
        .filter(|entry| entry.get("value").and_then(|value| value.as_bool()) == Some(true))
        .filter_map(|entry| entry.get("id").and_then(|value| value.as_str()))
        .map(str::to_string)
        .collect::<Vec<_>>();
    let declared_flag_count = dashboard_array_len(world_state.pointer("/gameplayRules/flags"));
    let trigger_collision_event_count = world_state
        .get("collisionEvents")
        .and_then(|events| events.as_array())
        .map(|events| {
            events
                .iter()
                .filter(|event| {
                    event.get("type").and_then(|value| value.as_str())
                        == Some("runtime.collision.trigger")
                })
                .count()
        })
        .unwrap_or(0);
    let hud_values = world_state
        .pointer("/componentModel/hudValues")
        .and_then(|value| value.as_array())
        .map(|values| {
            values
                .iter()
                .map(|value| {
                    json!({
                        "entityId": value.get("entityId").cloned().unwrap_or(json!(null)),
                        "kind": value.get("kind").cloned().unwrap_or(json!(null)),
                        "label": value.get("label").cloned().unwrap_or(json!(null)),
                        "value": value.get("value").cloned().unwrap_or(json!(null)),
                        "bindFlag": value.get("bindFlag").cloned().unwrap_or(json!(null)),
                        "flagValue": value.get("flagValue").cloned().unwrap_or(json!(null)),
                        "text": value.get("text").cloned().unwrap_or(json!(null)),
                    })
                })
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    let hud_value_entity_count = world_state
        .pointer("/componentModel/counts/hudValue")
        .cloned()
        .unwrap_or_else(|| json!(hud_values.len()));
    json!({
        "present": world_state.get("goalFlags").is_some()
            || world_state.get("gameplayRules").is_some()
            || world_state.get("componentModel").is_some(),
        "declaredFlagCount": declared_flag_count,
        "worldFlagCount": flag_entries.len(),
        "trueFlagCount": true_flags.len(),
        "falseFlagCount": flag_entries.len().saturating_sub(true_flags.len()),
        "triggerEntityCount": world_state.pointer("/componentModel/counts/trigger")
            .cloned()
            .unwrap_or_else(|| json!(dashboard_entities_with_component(world_state, "trigger"))),
        "goalFlagEntityCount": world_state.pointer("/componentModel/counts/goalFlag")
            .cloned()
            .unwrap_or_else(|| json!(dashboard_entities_with_component(world_state, "goalFlag"))),
        "hudValueEntityCount": hud_value_entity_count,
        "hudValues": hud_values,
        "triggerCollisionEventCount": trigger_collision_event_count,
        "trueFlags": true_flags,
        "flags": flag_entries
    })
}

fn read_dashboard_comparison(run_dir: &Path) -> RunDashboardComparison {
    let paths = dashboard_run_comparison_artifact_paths(run_dir);
    if paths.is_empty() {
        return RunDashboardComparison {
            present: false,
            empty_state: "No run comparison artifacts were found for this run.".to_string(),
            artifacts: Vec::new(),
        };
    }
    let artifacts = paths
        .into_iter()
        .map(|path| dashboard_comparison_artifact(run_dir, path))
        .collect::<Vec<_>>();
    RunDashboardComparison {
        present: true,
        empty_state: String::new(),
        artifacts,
    }
}

fn dashboard_run_comparison_artifact_paths(run_dir: &Path) -> Vec<String> {
    let mut paths = Vec::new();
    for dir in ["mutation", "comparisons"] {
        if let Ok(entries) = fs::read_dir(run_dir.join(dir)) {
            for entry in entries.flatten() {
                let path = entry.path();
                let Some(name) = path.file_name().and_then(|value| value.to_str()) else {
                    continue;
                };
                if name.starts_with("run-comparison-") && name.ends_with(".json") {
                    paths.push(format!("{dir}/{name}"));
                }
            }
        }
    }
    paths.sort();
    paths
}

fn dashboard_comparison_artifact(run_dir: &Path, path: String) -> RunDashboardComparisonArtifact {
    let id = Path::new(&path)
        .file_stem()
        .and_then(|value| value.to_str())
        .unwrap_or("run-comparison")
        .to_string();
    let absolute_path = run_dir.join(&path);
    if !absolute_path.is_file() {
        return RunDashboardComparisonArtifact {
            id,
            path: path.clone(),
            exists: false,
            read_error: Some(format!("missing comparison artifact file: {path}")),
            before_run_id: None,
            after_run_id: None,
            classification: None,
            deltas: serde_json::Value::Null,
            semantic: serde_json::Value::Null,
            evidence_refs: Vec::new(),
            unsupported: Vec::new(),
            value: None,
        };
    }
    match read_json_value(&absolute_path) {
        Ok(value) => RunDashboardComparisonArtifact {
            id,
            path,
            exists: true,
            read_error: None,
            before_run_id: json_string(&value, "before_run_id"),
            after_run_id: json_string(&value, "after_run_id"),
            classification: json_string(&value, "classification"),
            deltas: value
                .get("deltas")
                .cloned()
                .unwrap_or(serde_json::Value::Null),
            semantic: value
                .get("semantic")
                .cloned()
                .unwrap_or(serde_json::Value::Null),
            evidence_refs: value
                .get("evidence_refs")
                .and_then(|refs| refs.as_array())
                .map(|refs| {
                    refs.iter()
                        .filter_map(|value| value.as_str().map(str::to_string))
                        .collect::<Vec<_>>()
                })
                .unwrap_or_default(),
            unsupported: value
                .get("unsupported")
                .and_then(|items| items.as_array())
                .map(|items| {
                    items
                        .iter()
                        .filter_map(|value| value.as_str().map(str::to_string))
                        .collect::<Vec<_>>()
                })
                .unwrap_or_default(),
            value: Some(value),
        },
        Err(error) => RunDashboardComparisonArtifact {
            id,
            path,
            exists: true,
            read_error: Some(error.to_string()),
            before_run_id: None,
            after_run_id: None,
            classification: None,
            deltas: serde_json::Value::Null,
            semantic: serde_json::Value::Null,
            evidence_refs: Vec::new(),
            unsupported: Vec::new(),
            value: None,
        },
    }
}

fn select_dashboard_mutation_artifacts(run_dir: &Path) -> Result<Vec<RunDashboardArtifact>> {
    [
        ("mutation-proposals", "mutation/proposals.json"),
        ("mutation-classifications", "mutation/classifications.json"),
        ("mutation-patch-drafts", "mutation/patch-drafts.json"),
        (
            "mutation-rerun-orchestration",
            "mutation/rerun-orchestration.json",
        ),
        (
            "mutation-scene-applications",
            "mutation/scene-applications.json",
        ),
        (
            "mutation-review-decisions",
            "mutation/review-decisions.json",
        ),
        (
            "mutation-evolve-v1-demo-summary",
            "mutation/evolve-v1-demo-summary.json",
        ),
    ]
    .into_iter()
    .filter(|(_, path)| run_dir.join(path).is_file())
    .map(|(id, path)| {
        dashboard_artifact_from_parts(
            run_dir,
            id.to_string(),
            "application/json".to_string(),
            path.to_string(),
            json!({ "artifact": "mutation_artifact", "read_only": true }),
        )
    })
    .collect()
}

struct DashboardCategoryArtifacts<'a> {
    screenshots: &'a [RunDashboardArtifact],
    world_states: &'a [RunDashboardArtifact],
    frame_metrics: &'a [RunDashboardArtifact],
    performance_metrics: &'a [RunDashboardArtifact],
    console_logs: &'a [RunDashboardArtifact],
    cdp_trace_summaries: &'a [RunDashboardArtifact],
    scenario_results: &'a [RunDashboardArtifact],
    mutation_artifacts: &'a [RunDashboardArtifact],
}

struct DashboardEvidenceFidelityInputs<'a> {
    transaction_provenance: Option<&'a RunTransactionProvenance>,
    probe_contract_status: &'a RunDashboardProbeContractStatus,
    replay: &'a RunDashboardReplay,
    screenshots: &'a [RunDashboardArtifact],
    console_logs: &'a [RunDashboardArtifact],
    performance_metrics: &'a [RunDashboardArtifact],
    cdp_trace_summaries: &'a [RunDashboardArtifact],
    command_context: Option<&'a RunCommandContext>,
}

fn dashboard_evidence_fidelity(
    inputs: DashboardEvidenceFidelityInputs<'_>,
) -> RunDashboardEvidenceFidelity {
    let transaction = match inputs.transaction_provenance {
        Some(provenance) => RunDashboardEvidenceFidelityStatus {
            id: "transaction".to_string(),
            label: "Transaction provenance".to_string(),
            status: "present".to_string(),
            summary: format!(
                "Transaction {} records scene edit provenance.",
                provenance.transaction_id
            ),
            observed_count: 1,
            missing_count: 0,
            warnings: Vec::new(),
            evidence_refs: vec![provenance.transaction_artifact_path.clone()],
        },
        None => RunDashboardEvidenceFidelityStatus {
            id: "transaction".to_string(),
            label: "Transaction provenance".to_string(),
            status: "missing".to_string(),
            summary: "No transaction provenance is recorded for this run.".to_string(),
            observed_count: 0,
            missing_count: 1,
            warnings: vec!["Scene edit transaction provenance is unavailable.".to_string()],
            evidence_refs: Vec::new(),
        },
    };

    let runtime_probe = RunDashboardEvidenceFidelityStatus {
        id: "runtime_probe".to_string(),
        label: "Runtime probe contract".to_string(),
        status: inputs.probe_contract_status.status.clone(),
        summary: format!(
            "{} {} observed; {} missing; {} malformed.",
            inputs.probe_contract_status.contract_name,
            inputs.probe_contract_status.observed_count,
            inputs.probe_contract_status.missing_count,
            inputs.probe_contract_status.malformed_count
        ),
        observed_count: inputs.probe_contract_status.observed_count,
        missing_count: inputs.probe_contract_status.missing_count,
        warnings: if inputs.probe_contract_status.status == "present" {
            Vec::new()
        } else {
            vec![format!(
                "Runtime probe contract status is {}.",
                inputs.probe_contract_status.status
            )]
        },
        evidence_refs: inputs.probe_contract_status.evidence_refs.clone(),
    };

    let readable_replay_count = inputs
        .replay
        .sequences
        .iter()
        .filter(|sequence| sequence.read_error.is_none())
        .count();
    let unreadable_replay_count = inputs
        .replay
        .sequences
        .iter()
        .filter(|sequence| sequence.read_error.is_some())
        .count();
    let replay_refs = inputs
        .replay
        .sequences
        .iter()
        .flat_map(|sequence| sequence.evidence_refs.clone())
        .collect::<Vec<_>>();
    let replay_warnings = inputs
        .replay
        .sequences
        .iter()
        .filter_map(|sequence| {
            sequence.read_error.as_ref().map(|error| {
                format!(
                    "Replay evidence {} is unavailable: {error}",
                    sequence.replay_path
                )
            })
        })
        .collect::<Vec<_>>();
    let input_replay = RunDashboardEvidenceFidelityStatus {
        id: "input_replay".to_string(),
        label: "Input replay evidence".to_string(),
        status: if readable_replay_count > 0 && unreadable_replay_count == 0 {
            "present"
        } else if readable_replay_count > 0 {
            "partial"
        } else {
            "missing"
        }
        .to_string(),
        summary: if readable_replay_count > 0 {
            format!(
                "{} replay sequence(s) available; {} unavailable.",
                readable_replay_count, unreadable_replay_count
            )
        } else {
            inputs.replay.empty_state.clone()
        },
        observed_count: readable_replay_count,
        missing_count: if inputs.replay.sequences.is_empty() {
            1
        } else {
            unreadable_replay_count
        },
        warnings: if replay_warnings.is_empty() && readable_replay_count == 0 {
            vec!["Input replay evidence is unavailable.".to_string()]
        } else {
            replay_warnings
        },
        evidence_refs: replay_refs,
    };

    let cdp_counts = [
        (
            "worker screenshots",
            dashboard_readable_artifact_count(inputs.screenshots),
        ),
        (
            "console logs",
            dashboard_readable_artifact_count(inputs.console_logs),
        ),
        (
            "performance metrics",
            dashboard_readable_artifact_count(inputs.performance_metrics),
        ),
        (
            "CDP trace summaries",
            dashboard_readable_artifact_count(inputs.cdp_trace_summaries),
        ),
    ];
    let missing_cdp = cdp_counts
        .iter()
        .filter(|(_, count)| *count == 0)
        .map(|(label, _)| (*label).to_string())
        .collect::<Vec<_>>();
    let malformed_cdp = inputs
        .screenshots
        .iter()
        .chain(inputs.console_logs.iter())
        .chain(inputs.performance_metrics.iter())
        .chain(inputs.cdp_trace_summaries.iter())
        .filter(|artifact| artifact.exists && artifact.read_error.is_some())
        .count();
    let missing_cdp_artifacts = inputs
        .screenshots
        .iter()
        .chain(inputs.console_logs.iter())
        .chain(inputs.performance_metrics.iter())
        .chain(inputs.cdp_trace_summaries.iter())
        .filter(|artifact| !artifact.exists)
        .count();
    let openchrome_refs = inputs
        .screenshots
        .iter()
        .chain(inputs.console_logs.iter())
        .chain(inputs.performance_metrics.iter())
        .chain(inputs.cdp_trace_summaries.iter())
        .map(|artifact| artifact.path.clone())
        .collect::<Vec<_>>();
    let openchrome_cdp = RunDashboardEvidenceFidelityStatus {
        id: "openchrome_cdp".to_string(),
        label: "Openchrome/CDP evidence".to_string(),
        status: if malformed_cdp > 0 {
            "malformed"
        } else if missing_cdp.is_empty() && missing_cdp_artifacts == 0 {
            "present"
        } else if openchrome_refs.is_empty() {
            "missing"
        } else {
            "partial"
        }
        .to_string(),
        summary: format!(
            "{} screenshot(s), {} console log(s), {} performance metric(s), {} CDP trace summarie(s).",
            inputs.screenshots.len(),
            inputs.console_logs.len(),
            inputs.performance_metrics.len(),
            inputs.cdp_trace_summaries.len()
        ),
        observed_count: cdp_counts.iter().map(|(_, count)| *count).sum(),
        missing_count: missing_cdp.len() + missing_cdp_artifacts,
        warnings: missing_cdp
            .iter()
            .map(|label| format!("Missing {label}."))
            .chain(
                inputs
                    .screenshots
                    .iter()
                    .chain(inputs.console_logs.iter())
                    .chain(inputs.performance_metrics.iter())
                    .chain(inputs.cdp_trace_summaries.iter())
                    .filter_map(|artifact| {
                        artifact.read_error.as_ref().map(|error| {
                            format!(
                                "Openchrome/CDP evidence {} is unavailable: {error}",
                                artifact.path
                            )
                        })
                    }),
            )
            .collect(),
        evidence_refs: openchrome_refs,
    };

    let command_context = match inputs.command_context {
        Some(context) => RunDashboardEvidenceFidelityStatus {
            id: "command_context".to_string(),
            label: "Reproducible command context".to_string(),
            status: "present".to_string(),
            summary: format!("{} worker(s), seed {}.", context.workers, context.seed_path),
            observed_count: 1,
            missing_count: 0,
            warnings: Vec::new(),
            evidence_refs: Vec::new(),
        },
        None => RunDashboardEvidenceFidelityStatus {
            id: "command_context".to_string(),
            label: "Reproducible command context".to_string(),
            status: "missing".to_string(),
            summary: "No reproducible command context is recorded.".to_string(),
            observed_count: 0,
            missing_count: 1,
            warnings: vec!["Command context is unavailable for this run.".to_string()],
            evidence_refs: Vec::new(),
        },
    };

    RunDashboardEvidenceFidelity {
        transaction,
        runtime_probe,
        input_replay,
        openchrome_cdp,
        command_context,
    }
}

fn dashboard_readable_artifact_count(artifacts: &[RunDashboardArtifact]) -> usize {
    artifacts
        .iter()
        .filter(|artifact| artifact.exists && artifact.read_error.is_none())
        .count()
}

fn dashboard_category_summaries(
    artifacts: DashboardCategoryArtifacts<'_>,
) -> Vec<RunDashboardCategorySummary> {
    vec![
        dashboard_category_summary("screenshots", "Screenshots", artifacts.screenshots),
        dashboard_category_summary(
            "world_states",
            "World-state snapshots",
            artifacts.world_states,
        ),
        dashboard_category_summary(
            "frame_performance_metrics",
            "Frame/performance metrics",
            &artifacts
                .frame_metrics
                .iter()
                .chain(artifacts.performance_metrics.iter())
                .cloned()
                .collect::<Vec<_>>(),
        ),
        dashboard_category_summary(
            "console_cdp_summaries",
            "Console/CDP summaries",
            &artifacts
                .console_logs
                .iter()
                .chain(artifacts.cdp_trace_summaries.iter())
                .cloned()
                .collect::<Vec<_>>(),
        ),
        dashboard_category_summary(
            "scenario_results",
            "Scenario results",
            artifacts.scenario_results,
        ),
        dashboard_category_summary(
            "mutation_artifacts",
            "Mutation artifacts",
            artifacts.mutation_artifacts,
        ),
    ]
}

fn dashboard_category_summary(
    id: &str,
    label: &str,
    artifacts: &[RunDashboardArtifact],
) -> RunDashboardCategorySummary {
    RunDashboardCategorySummary {
        id: id.to_string(),
        label: label.to_string(),
        count: artifacts.len(),
        missing_count: artifacts.iter().filter(|artifact| !artifact.exists).count(),
        malformed_count: artifacts
            .iter()
            .filter(|artifact| artifact.exists && artifact.read_error.is_some())
            .count(),
    }
}

fn dashboard_worker_count(evidence: &[EvidenceArtifact]) -> usize {
    let mut worker_ids = BTreeSet::new();
    for artifact in evidence {
        if let Some(worker_id) = artifact
            .metadata
            .get("worker_id")
            .and_then(|value| value.as_str())
        {
            worker_ids.insert(worker_id.to_string());
        }
    }
    worker_ids.len()
}

fn dashboard_scenario_status(verdict: &serde_json::Value) -> String {
    let scenario_results = verdict
        .get("metadata")
        .and_then(|metadata| metadata.get("scenario_results"))
        .and_then(|value| value.as_u64())
        .unwrap_or(0);
    if scenario_results == 0 {
        return "pending".to_string();
    }
    // Derive the scenario status from genuine scenario outcomes, not the overall
    // verdict status. A verdict can fail purely for evidence-consistency reasons
    // (e.g. missing_scenario_evidence) while the scenarios themselves passed, and
    // the dashboard needs to distinguish "scenario passed, evidence incomplete"
    // from an actually failed scenario.
    let scenario_failed = verdict
        .get("failures")
        .and_then(|value| value.as_array())
        .map(|failures| {
            failures.iter().any(|failure| {
                matches!(
                    failure.get("kind").and_then(|value| value.as_str()),
                    Some("scenario_failed" | "assertion_failed" | "visual_checkpoint_failed")
                )
            })
        })
        .unwrap_or(false);
    if scenario_failed {
        "failed".to_string()
    } else {
        "passed".to_string()
    }
}

fn read_dashboard_journal(
    run_dir: &Path,
    evidence: &[EvidenceArtifact],
    mutations: &[MutationProposal],
) -> RunDashboardJournal {
    let path = "journal.md".to_string();
    let absolute_path = run_dir.join(&path);
    match fs::read_to_string(&absolute_path) {
        Ok(body) => parse_dashboard_journal(&path, true, None, &body, evidence, mutations),
        Err(error) if error.kind() == ErrorKind::NotFound => parse_dashboard_journal(
            &path,
            false,
            Some("missing journal artifact".to_string()),
            "",
            evidence,
            mutations,
        ),
        // The journal file is present but unreadable (e.g. invalid UTF-8 or a
        // permission error). Report it as existing with a read_error so it is
        // distinguishable from a genuinely missing journal.
        Err(error) => parse_dashboard_journal(
            &path,
            true,
            Some(format!("failed to read journal artifact: {error}")),
            "",
            evidence,
            mutations,
        ),
    }
}

fn parse_dashboard_journal(
    path: &str,
    exists: bool,
    read_error: Option<String>,
    journal: &str,
    evidence: &[EvidenceArtifact],
    mutations: &[MutationProposal],
) -> RunDashboardJournal {
    let entries = dashboard_journal_entries(journal, evidence, mutations);
    let evidence_refs = collect_entry_refs(&entries, |entry| &entry.evidence_refs);
    let verdict_refs = collect_entry_refs(&entries, |entry| &entry.verdict_refs);
    let mutation_refs = collect_entry_refs(&entries, |entry| &entry.mutation_refs);
    RunDashboardJournal {
        path: path.to_string(),
        exists,
        read_error,
        summary: dashboard_journal_summary(journal, &entries),
        entries,
        evidence_refs,
        verdict_refs,
        mutation_refs,
    }
}

fn dashboard_journal_entries(
    journal: &str,
    evidence: &[EvidenceArtifact],
    mutations: &[MutationProposal],
) -> Vec<RunDashboardJournalEntry> {
    let mut entries = Vec::new();
    let mut current_heading = String::new();
    let mut current_level = 0usize;
    let mut current_body = String::new();

    for line in journal.lines() {
        if let Some((level, heading)) = markdown_heading(line) {
            push_dashboard_journal_entry(
                &mut entries,
                &current_heading,
                current_level,
                &current_body,
                evidence,
                mutations,
            );
            current_heading = heading;
            current_level = level;
            current_body.clear();
        } else {
            current_body.push_str(line);
            current_body.push('\n');
        }
    }
    push_dashboard_journal_entry(
        &mut entries,
        &current_heading,
        current_level,
        &current_body,
        evidence,
        mutations,
    );
    entries
}

fn push_dashboard_journal_entry(
    entries: &mut Vec<RunDashboardJournalEntry>,
    heading: &str,
    level: usize,
    body: &str,
    evidence: &[EvidenceArtifact],
    mutations: &[MutationProposal],
) {
    let body = body.trim();
    if heading.trim().is_empty() && body.is_empty() {
        return;
    }
    let fallback_heading = if heading.trim().is_empty() {
        "Journal"
    } else {
        heading.trim()
    };
    let category = dashboard_journal_category(fallback_heading);
    let entry_text = format!("{fallback_heading}\n{body}");
    let index = entries.len() + 1;
    entries.push(RunDashboardJournalEntry {
        id: format!("journal-entry-{index}-{}", slug_for_id(fallback_heading)),
        heading: fallback_heading.to_string(),
        level,
        category,
        body: body.to_string(),
        evidence_refs: extract_journal_evidence_refs(&entry_text, evidence),
        verdict_refs: extract_journal_verdict_refs(&entry_text),
        mutation_refs: extract_journal_mutation_refs(&entry_text, mutations),
    });
}

fn markdown_heading(line: &str) -> Option<(usize, String)> {
    let trimmed = line.trim_start();
    let level = trimmed.chars().take_while(|ch| *ch == '#').count();
    if level == 0 || level > 6 {
        return None;
    }
    let rest = trimmed.get(level..)?.trim();
    if rest.is_empty() {
        return None;
    }
    Some((level, rest.to_string()))
}

fn dashboard_journal_category(heading: &str) -> String {
    let lowered = heading.to_ascii_lowercase();
    if lowered.contains("hypothesis") {
        "hypothesis"
    } else if lowered.contains("observation") || lowered.contains("evidence") {
        "observation"
    } else if lowered.contains("failed") || lowered.contains("failure") {
        "failure"
    } else if lowered.contains("mutation") {
        "next_mutation"
    } else if lowered.contains("verdict") {
        "verdict"
    } else {
        "summary"
    }
    .to_string()
}

fn dashboard_journal_summary(journal: &str, entries: &[RunDashboardJournalEntry]) -> String {
    for line in journal.lines() {
        let trimmed = line.trim();
        if let Some(summary) = trimmed.strip_prefix("- Summary:") {
            return summary.trim().to_string();
        }
    }
    entries
        .iter()
        .find_map(|entry| {
            entry
                .body
                .lines()
                .map(str::trim)
                .find(|line| !line.is_empty())
                .map(str::to_string)
        })
        .unwrap_or_else(|| "No journal content available.".to_string())
}

fn extract_journal_evidence_refs(text: &str, evidence: &[EvidenceArtifact]) -> Vec<String> {
    let mut refs = BTreeSet::new();
    for artifact in evidence {
        if text.contains(&artifact.path) || text.contains(&artifact.id) {
            refs.insert(artifact.path.clone());
        }
    }
    refs.into_iter().collect()
}

fn extract_journal_verdict_refs(text: &str) -> Vec<String> {
    let lowered = text.to_ascii_lowercase();
    if lowered.contains("verdict") || lowered.contains("failed criteria") {
        vec!["verdict.json".to_string()]
    } else {
        Vec::new()
    }
}

fn extract_journal_mutation_refs(text: &str, mutations: &[MutationProposal]) -> Vec<String> {
    let mut refs = BTreeSet::new();
    for mutation in mutations {
        if text.contains(&mutation.id) {
            refs.insert(mutation.id.clone());
        }
    }
    refs.into_iter().collect()
}

fn collect_entry_refs(
    entries: &[RunDashboardJournalEntry],
    selector: fn(&RunDashboardJournalEntry) -> &Vec<String>,
) -> Vec<String> {
    let mut refs = BTreeSet::new();
    for entry in entries {
        for reference in selector(entry) {
            refs.insert(reference.clone());
        }
    }
    refs.into_iter().collect()
}

fn slug_for_id(value: &str) -> String {
    let mut slug = String::new();
    for ch in value.chars() {
        if ch.is_ascii_alphanumeric() {
            slug.push(ch.to_ascii_lowercase());
        } else if !slug.ends_with('-') {
            slug.push('-');
        }
    }
    slug.trim_matches('-').to_string()
}

fn read_dashboard_mutation_lifecycle(
    run_dir: &Path,
    proposals: &[MutationProposal],
) -> RunDashboardMutationLifecycle {
    let stages = vec![
        dashboard_lifecycle_stage_from_records(
            "proposed",
            "Proposed",
            if proposals.is_empty() {
                "missing"
            } else {
                "proposed"
            },
            Some("mutation/proposals.json"),
            proposals.iter().map(|proposal| json!(proposal)).collect(),
            proposals
                .iter()
                .map(|proposal| proposal.evidence_id.clone())
                .collect(),
            None,
        ),
        dashboard_lifecycle_stage_from_json_file(
            run_dir,
            "classified",
            "Classified",
            "classified",
            "mutation/classifications.json",
            "classifications",
        ),
        dashboard_lifecycle_stage_from_json_file(
            run_dir,
            "drafted",
            "Drafted",
            "drafted",
            "mutation/patch-drafts.json",
            "drafts",
        ),
        dashboard_sandbox_stage(run_dir),
        dashboard_comparison_stage(run_dir),
        dashboard_lifecycle_stage_from_json_file(
            run_dir,
            "scene_applied",
            "Applied scene mutation",
            "applied",
            "mutation/scene-applications.json",
            "applications",
        ),
        dashboard_lifecycle_stage_from_json_file(
            run_dir,
            "reviewed",
            "Manual review",
            "pending_review",
            "mutation/review-decisions.json",
            "decisions",
        ),
    ];
    let terminal_state = dashboard_lifecycle_terminal_state(&stages);
    let command_hints = dashboard_mutation_command_hints(run_dir, &stages);
    RunDashboardMutationLifecycle {
        terminal_state,
        stages,
        command_hints,
    }
}

fn dashboard_review_cockpit(
    lifecycle: &RunDashboardMutationLifecycle,
    promotions: &[RegressionPromotionPackResult],
) -> RunDashboardReviewCockpit {
    let proposals =
        dashboard_review_cockpit_stage_from_lifecycle(lifecycle, "proposed", "Proposals");
    let decisions =
        dashboard_review_cockpit_stage_from_lifecycle(lifecycle, "reviewed", "Review decisions");
    let applications = dashboard_review_cockpit_stage_from_lifecycle(
        lifecycle,
        "scene_applied",
        "Review-gated applications",
    );
    let comparisons =
        dashboard_review_cockpit_stage_from_lifecycle(lifecycle, "compared", "Rerun comparisons");
    let promotions = dashboard_review_cockpit_promotion_stage(promotions);
    // Report the furthest lifecycle stage reached. The progression is
    // proposed -> reviewed -> scene_applied -> compared -> promoted, so a run
    // that has been promoted must surface "promoted" even when earlier
    // review/rerun artifacts are also present.
    let terminal_state = [
        &promotions,
        &comparisons,
        &applications,
        &decisions,
        &proposals,
    ]
    .into_iter()
    .find(|stage| stage.state != "missing")
    .map(|stage| stage.state.clone())
    .unwrap_or_else(|| "missing".to_string());
    RunDashboardReviewCockpit {
        schema_version: "ouroforge-studio-review-cockpit-v1".to_string(),
        terminal_state,
        proposals,
        decisions,
        applications,
        comparisons,
        promotions,
        matrix: RunDashboardReviewCockpitStage {
            id: "matrix".to_string(),
            label: "Regression matrix".to_string(),
            state: "export_level".to_string(),
            artifact_path: Some("regression_matrix".to_string()),
            record_count: 0,
            record_ids: Vec::new(),
            evidence_refs: Vec::new(),
            read_error: None,
        },
        command_hints: lifecycle.command_hints.clone(),
        boundary: "read-only exported evidence; commands are inert text only".to_string(),
    }
}

fn dashboard_review_cockpit_stage_from_lifecycle(
    lifecycle: &RunDashboardMutationLifecycle,
    stage_id: &str,
    fallback_label: &str,
) -> RunDashboardReviewCockpitStage {
    match lifecycle.stages.iter().find(|stage| stage.id == stage_id) {
        Some(stage) => RunDashboardReviewCockpitStage {
            id: stage.id.clone(),
            label: stage.label.clone(),
            state: stage.state.clone(),
            artifact_path: stage.artifact_path.clone(),
            record_count: stage.record_count,
            record_ids: stage
                .records
                .iter()
                .filter_map(dashboard_json_record_id)
                .collect(),
            evidence_refs: stage.evidence_refs.clone(),
            read_error: stage.read_error.clone(),
        },
        None => RunDashboardReviewCockpitStage {
            id: stage_id.to_string(),
            label: fallback_label.to_string(),
            state: "missing".to_string(),
            artifact_path: None,
            record_count: 0,
            record_ids: Vec::new(),
            evidence_refs: Vec::new(),
            read_error: Some("lifecycle stage missing from exported read model".to_string()),
        },
    }
}

fn dashboard_review_cockpit_promotion_stage(
    promotions: &[RegressionPromotionPackResult],
) -> RunDashboardReviewCockpitStage {
    RunDashboardReviewCockpitStage {
        id: "promotions".to_string(),
        label: "Regression promotions".to_string(),
        state: if promotions.is_empty() {
            "missing".to_string()
        } else {
            "promoted".to_string()
        },
        artifact_path: Some("regression-promotions/*.json".to_string()),
        record_count: promotions.len(),
        record_ids: promotions
            .iter()
            .map(|promotion| promotion.id.clone())
            .collect(),
        evidence_refs: promotions
            .iter()
            .flat_map(|promotion| {
                [
                    Some(promotion.source_run.verdict_path.clone()),
                    promotion.record_path.clone(),
                ]
                .into_iter()
                .flatten()
            })
            .collect::<BTreeSet<_>>()
            .into_iter()
            .collect(),
        read_error: None,
    }
}

fn dashboard_json_record_id(value: &serde_json::Value) -> Option<String> {
    value
        .get("id")
        .or_else(|| value.get("proposalId"))
        .or_else(|| value.get("decisionId"))
        .or_else(|| value.get("applicationId"))
        .and_then(|value| value.as_str())
        .map(str::to_string)
}

fn read_regression_promotion_records(run_dir: &Path) -> Vec<RegressionPromotionPackResult> {
    let dir = run_dir.join("regression-promotions");
    let mut records = Vec::new();
    let Ok(entries) = fs::read_dir(&dir) else {
        return records;
    };
    for entry in entries.flatten() {
        let path = entry.path();
        if path.extension().and_then(|value| value.to_str()) != Some("json") {
            continue;
        }
        if let Ok(value) = read_json_value(&path) {
            if let Ok(record) = serde_json::from_value::<RegressionPromotionPackResult>(value) {
                records.push(record);
            }
        }
    }
    records.sort_by(|left, right| left.id.cmp(&right.id));
    records
}

fn dashboard_lifecycle_stage_from_json_file(
    run_dir: &Path,
    id: &str,
    label: &str,
    present_state: &str,
    artifact_path: &str,
    array_field: &str,
) -> RunDashboardMutationLifecycleStage {
    let path = run_dir.join(artifact_path);
    if !path.is_file() {
        return dashboard_lifecycle_stage_from_records(
            id,
            label,
            "missing",
            Some(artifact_path),
            Vec::new(),
            Vec::new(),
            None,
        );
    }
    match read_json_value(&path) {
        Ok(value) => {
            let records = value
                .get(array_field)
                .and_then(|value| value.as_array())
                .cloned()
                .unwrap_or_else(|| vec![value]);
            let state = if id == "reviewed" {
                dashboard_review_state(&records)
            } else {
                present_state.to_string()
            };
            let evidence_refs = collect_json_evidence_refs(&records);
            dashboard_lifecycle_stage_from_records(
                id,
                label,
                &state,
                Some(artifact_path),
                records,
                evidence_refs,
                None,
            )
        }
        Err(error) => dashboard_lifecycle_stage_from_records(
            id,
            label,
            "malformed",
            Some(artifact_path),
            Vec::new(),
            Vec::new(),
            Some(error.to_string()),
        ),
    }
}

fn dashboard_lifecycle_stage_from_records(
    id: &str,
    label: &str,
    state: &str,
    artifact_path: Option<&str>,
    records: Vec<serde_json::Value>,
    evidence_refs: Vec<String>,
    read_error: Option<String>,
) -> RunDashboardMutationLifecycleStage {
    RunDashboardMutationLifecycleStage {
        id: id.to_string(),
        label: label.to_string(),
        state: state.to_string(),
        artifact_path: artifact_path.map(str::to_string),
        record_count: records.len(),
        evidence_refs,
        records,
        read_error,
    }
}

fn dashboard_sandbox_stage(run_dir: &Path) -> RunDashboardMutationLifecycleStage {
    let mut records = Vec::new();
    let sandbox_root = run_dir.join("sandbox");
    if let Ok(drafts) = fs::read_dir(&sandbox_root) {
        for draft in drafts.flatten() {
            let result_path = draft.path().join("evidence/result.json");
            if result_path.is_file() {
                if let Ok(value) = read_json_value(&result_path) {
                    records.push(value);
                }
            }
        }
    }
    let evidence_refs = collect_json_evidence_refs(&records);
    dashboard_lifecycle_stage_from_records(
        "sandboxed",
        "Sandboxed",
        if records.is_empty() {
            "missing"
        } else {
            "sandboxed"
        },
        Some("sandbox/*/evidence/result.json"),
        records,
        evidence_refs,
        None,
    )
}

fn dashboard_comparison_stage(run_dir: &Path) -> RunDashboardMutationLifecycleStage {
    let mut records = Vec::new();
    for path in dashboard_comparison_artifact_paths(run_dir) {
        if let Ok(value) = read_json_value(run_dir.join(&path)) {
            records.push(value);
        }
    }
    let evidence_refs = collect_json_evidence_refs(&records);
    dashboard_lifecycle_stage_from_records(
        "compared",
        "Compared",
        if records.is_empty() {
            "missing"
        } else {
            "compared"
        },
        Some("mutation/rerun-orchestration.json"),
        records,
        evidence_refs,
        None,
    )
}

fn dashboard_comparison_artifact_paths(run_dir: &Path) -> Vec<String> {
    let mut paths = Vec::new();
    if run_dir.join("mutation/rerun-orchestration.json").is_file() {
        paths.push("mutation/rerun-orchestration.json".to_string());
    }
    if let Ok(entries) = fs::read_dir(run_dir.join("mutation")) {
        for entry in entries.flatten() {
            let path = entry.path();
            let Some(name) = path.file_name().and_then(|value| value.to_str()) else {
                continue;
            };
            if name.starts_with("run-comparison-") && name.ends_with(".json") {
                paths.push(format!("mutation/{name}"));
            }
        }
    }
    paths.sort();
    paths
}

fn dashboard_review_state(records: &[serde_json::Value]) -> String {
    let mut has_pending = false;
    // Review decisions are append-only, so the CURRENT review outcome is the
    // latest terminal decision — scan newest-first so an accept followed by a
    // later reject reports "rejected", not the stale first decision.
    for record in records.iter().rev() {
        match record.get("state").and_then(|value| value.as_str()) {
            Some("accepted") => return "accepted".to_string(),
            Some("rejected") => return "rejected".to_string(),
            Some("pending_review") => has_pending = true,
            _ => {}
        }
    }
    if has_pending || !records.is_empty() {
        "pending_review".to_string()
    } else {
        "missing".to_string()
    }
}

fn dashboard_lifecycle_terminal_state(stages: &[RunDashboardMutationLifecycleStage]) -> String {
    stages
        .iter()
        .rev()
        .find(|stage| stage.state != "missing")
        .map(|stage| stage.state.clone())
        .unwrap_or_else(|| "missing".to_string())
}

fn dashboard_mutation_command_hints(
    run_dir: &Path,
    stages: &[RunDashboardMutationLifecycleStage],
) -> Vec<String> {
    let has_draft = stages
        .iter()
        .any(|stage| stage.id == "drafted" && stage.state != "missing");
    if !has_draft {
        return Vec::new();
    }
    let run_path = run_dir.to_string_lossy();
    vec![
        format!(
            "cargo run -p ouroforge-cli -- mutation review {run_path} --accept --reason \"manual evidence review accepted\""
        ),
        format!(
            "cargo run -p ouroforge-cli -- mutation review {run_path} --reject --reason \"manual evidence review rejected\""
        ),
    ]
}

fn collect_json_evidence_refs(values: &[serde_json::Value]) -> Vec<String> {
    let mut refs = BTreeSet::new();
    for value in values {
        collect_json_evidence_refs_inner(value, &mut refs);
    }
    refs.into_iter().collect()
}

fn collect_json_evidence_refs_inner(value: &serde_json::Value, refs: &mut BTreeSet<String>) {
    match value {
        serde_json::Value::String(text)
            if text.starts_with("evidence/")
                || text.starts_with("mutation/")
                || text.starts_with("sandbox/") =>
        {
            refs.insert(text.clone());
        }
        serde_json::Value::Array(items) => {
            for item in items {
                collect_json_evidence_refs_inner(item, refs);
            }
        }
        serde_json::Value::Object(map) => {
            for value in map.values() {
                collect_json_evidence_refs_inner(value, refs);
            }
        }
        _ => {}
    }
}

fn read_json_value(path: impl AsRef<Path>) -> Result<serde_json::Value> {
    let path = path.as_ref();
    let input = fs::read_to_string(path)
        .with_context(|| format!("failed to read JSON file {}", path.display()))?;
    serde_json::from_str(&input)
        .with_context(|| format!("failed to parse JSON file {}", path.display()))
}

fn json_string(value: &serde_json::Value, field: &str) -> Option<String> {
    value
        .get(field)
        .and_then(|value| value.as_str())
        .map(str::to_string)
}

