    #[test]
    fn review_cockpit_terminal_state_prioritizes_promoted_runs() {
        let applied_stage = RunDashboardMutationLifecycleStage {
            id: "scene_applied".to_string(),
            label: "Review-gated applications".to_string(),
            state: "applied".to_string(),
            artifact_path: None,
            record_count: 1,
            evidence_refs: Vec::new(),
            records: Vec::new(),
            read_error: None,
        };
        let lifecycle = RunDashboardMutationLifecycle {
            terminal_state: "applied".to_string(),
            stages: vec![applied_stage],
            command_hints: Vec::new(),
        };

        let draft = valid_regression_promotion_draft();
        let promotion = RegressionPromotionPackResult {
            schema_version: "regression-promotion-result-v1".to_string(),
            id: "regression-promotion-terminal".to_string(),
            draft_id: draft.id.clone(),
            scenario_id: draft.proposed_scenario.id.clone(),
            source_run: draft.source_run.clone(),
            target: draft.target.clone(),
            dry_run: false,
            created_group: false,
            before_hash: artifact_hash_from_bytes(b"before"),
            after_hash: artifact_hash_from_bytes(b"after"),
            changes: vec!["added_scenario:terminal".to_string()],
            record_path: Some(
                "regression-promotions/regression-promotion-terminal.json".to_string(),
            ),
        };

        // A promoted run surfaces "promoted" even with an earlier applied stage.
        let promoted = dashboard_review_cockpit(&lifecycle, std::slice::from_ref(&promotion));
        assert_eq!(promoted.terminal_state, "promoted");
        // Without a promotion the applied stage remains terminal.
        let not_promoted = dashboard_review_cockpit(&lifecycle, &[]);
        assert_eq!(not_promoted.terminal_state, "applied");
    }

    fn write_loop_dry_run_project(root: &Path) {
        fs::create_dir_all(root.join("seeds")).expect("seed dir");
        fs::create_dir_all(root.join("scenarios")).expect("scenario dir");
        fs::create_dir_all(root.join("scenes")).expect("scene dir");
        fs::create_dir_all(root.join("assets")).expect("asset dir");
        fs::write(
            root.join("ouroforge.project.json"),
            r#"{
  "schemaVersion": "project-manifest-v1",
  "project": { "id": "loop_project", "name": "Loop Project" },
  "scenes": [{ "id": "main", "path": "scenes/main.scene.json" }],
  "seeds": [{ "id": "smoke", "path": "seeds/smoke.yaml" }],
  "scenarioPacks": [{ "id": "regression", "path": "scenarios/regression.json" }],
  "assetRoots": ["assets"],
  "runsRoot": "runs",
  "generated": { "roots": ["runs", "target", "dashboard-data"] }
}"#,
        )
        .expect("manifest");
        fs::write(
            root.join("seeds/smoke.yaml"),
            r#"id: loop-project.smoke
title: Loop Project Smoke
goal: Validate dry-run fixture.
constraints:
  target: file-harness
acceptance:
  - Dry-run fixture validates.
scenarios:
  - id: smoke
    description: Smoke.
"#,
        )
        .expect("seed");
        fs::write(
            root.join("scenes/main.scene.json"),
            MINIMAL_2D_PROJECT_SCENE,
        )
        .expect("scene");
        fs::write(
            root.join("scenarios/regression.json"),
            r#"{
  "schemaVersion": "scenario-pack-v1",
  "id": "regression",
  "description": "Regression pack.",
  "seed": "seeds/smoke.yaml",
  "scenes": ["scenes/main.scene.json"],
  "scenarioGroups": [
    { "id": "smoke", "description": "Smoke", "scenarios": [{ "id": "smoke", "description": "Smoke" }] }
  ]
}"#,
        )
        .expect("scenario pack");
    }

    fn write_loop_dry_run_plan(root: &Path, project_id: &str) -> PathBuf {
        let plan_path = root.join("loop-plan.json");
        fs::write(
            &plan_path,
            format!(
                r#"{{
  "schemaVersion": "authoring-loop-plan-v1",
  "loopId": "temp-loop",
  "project": {{ "projectId": "{project_id}", "manifestPath": "ouroforge.project.json" }},
  "seed": {{ "id": "smoke", "path": "seeds/smoke.yaml" }},
  "scenarioPack": {{ "id": "regression", "path": "scenarios/regression.json" }},
  "steps": [
    {{ "id": "run-baseline", "kind": "run-scenario-pack", "status": "completed", "expectedArtifacts": [{{ "id": "baseline-run", "path": "runs/baseline/run.json" }}] }},
    {{ "id": "compare-runs", "kind": "compare-runs", "status": "pending", "dependsOn": ["run-baseline"], "inputs": [{{ "id": "baseline-run", "path": "runs/baseline/run.json" }}], "expectedArtifacts": [{{ "id": "comparison", "path": "runs/baseline/comparisons/run-comparison.json" }}] }},
    {{ "id": "generate-proposal", "kind": "generate-proposal", "status": "pending", "dependsOn": ["compare-runs"], "inputs": [{{ "id": "comparison", "path": "runs/baseline/comparisons/run-comparison.json" }}], "expectedArtifacts": [{{ "id": "proposal", "path": "runs/baseline/mutation/proposal.json" }}] }},
    {{ "id": "record-review", "kind": "record-review-decision", "status": "pending", "dependsOn": ["generate-proposal"], "inputs": [{{ "id": "proposal", "path": "runs/baseline/mutation/proposal.json" }}], "requiredDecisions": [{{ "id": "human-review", "kind": "human-review" }}], "expectedArtifacts": [{{ "id": "decision", "path": "runs/baseline/mutation/review-decision-ledger.json" }}] }},
    {{ "id": "apply-mutation", "kind": "apply-accepted-scene-mutation", "status": "pending", "dependsOn": ["record-review"], "inputs": [{{ "id": "decision", "path": "runs/baseline/mutation/review-decision-ledger.json" }}], "requiredDecisions": [{{ "id": "human-review", "kind": "accepted-mutation" }}], "rollbackRefs": [{{ "id": "before-scene", "path": "runs/baseline/mutation/before.scene.json" }}], "expectedArtifacts": [{{ "id": "transaction", "path": "runs/baseline/mutation/transaction.json" }}] }}
  ],
  "generatedState": {{ "roots": ["runs", "target", "dashboard-data"], "trackedFixtureOnly": true }}
}}"#
            ),
        )
        .expect("plan");
        plan_path
    }

    fn write_loop_execution_plan(root: &Path) -> PathBuf {
        let plan_path = root.join("loop-execution-plan.json");
        fs::write(
            &plan_path,
            r#"{
  "schemaVersion": "authoring-loop-plan-v1",
  "loopId": "temp-loop-execution",
  "project": { "projectId": "loop_project", "manifestPath": "ouroforge.project.json" },
  "seed": { "id": "smoke", "path": "seeds/smoke.yaml" },
  "scenarioPack": { "id": "regression", "path": "scenarios/regression.json" },
  "steps": [
    { "id": "run-baseline", "kind": "run-scenario-pack", "status": "pending", "expectedArtifacts": [{ "id": "baseline-run", "path": "runs/baseline/run.json" }] },
    { "id": "run-after", "kind": "run-scenario-pack", "status": "pending", "expectedArtifacts": [{ "id": "after-run", "path": "runs/after/run.json" }] },
    { "id": "compare-runs", "kind": "compare-runs", "status": "pending", "dependsOn": ["run-baseline", "run-after"], "inputs": [{ "id": "baseline-run", "path": "runs/baseline/run.json" }, { "id": "after-run", "path": "runs/after/run.json" }], "expectedArtifacts": [{ "id": "comparison", "path": "runs/comparisons/run-comparison.json" }] },
    { "id": "generate-proposal", "kind": "generate-proposal", "status": "pending", "dependsOn": ["run-after"], "inputs": [{ "id": "after-run", "path": "runs/after/run.json" }], "expectedArtifacts": [{ "id": "proposal", "path": "runs/after/mutation/proposals.json" }, { "id": "classification", "path": "runs/after/mutation/classifications.json" }, { "id": "patch-draft", "path": "runs/after/mutation/patch-drafts.json" }] }
  ],
  "generatedState": { "roots": ["runs", "target", "dashboard-data"], "trackedFixtureOnly": true }
}"#,
        )
        .expect("execution plan");
        plan_path
    }

    fn read_loop_plan_from_path(path: &Path) -> AuthoringLoopPlan {
        let input = fs::read_to_string(path).expect("plan file reads");
        AuthoringLoopPlan::from_json_str(&input).expect("plan validates")
    }

    #[test]
    fn loop_step_runner_executes_run_compare_and_proposal_steps() {
        let root = unique_temp_dir("loop-step-runner-execution");
        write_loop_dry_run_project(&root);
        let plan_path = write_loop_execution_plan(&root);

        let baseline = execute_authoring_loop_step_from_path(&plan_path, "run-baseline")
            .expect("baseline run step executes");
        assert_eq!(baseline.status, "completed");
        assert_eq!(baseline.generated_artifacts[0].id, "baseline-run");
        assert!(root.join(&baseline.generated_artifacts[0].path).is_file());

        let after =
            execute_authoring_loop_step_from_path(&plan_path, "run-after").expect("after run step");
        let after_run_json = root.join(&after.generated_artifacts[0].path);
        assert!(after_run_json.is_file());

        let comparison = execute_authoring_loop_step_from_path(&plan_path, "compare-runs")
            .expect("compare step executes");
        assert_eq!(comparison.status, "completed");
        assert_eq!(comparison.generated_artifacts[0].id, "comparison");
        assert!(root.join(&comparison.generated_artifacts[0].path).is_file());

        let after_run_dir = after_run_json.parent().expect("after run dir");
        let failure_rel = "evidence/scenarios/loop-failure/scenario-result.json";
        let failure_path = after_run_dir.join(failure_rel);
        fs::create_dir_all(failure_path.parent().expect("failure parent"))
            .expect("failure evidence dir");
        write_json(
            &failure_path,
            &json!({
                "schema_version": "1",
                "artifact": "scenario_result",
                "scenario_id": "loop-failure",
                "status": "failed",
                "failures": [{ "kind": "scenario_assertion_failure" }]
            }),
        )
        .expect("failure evidence");
        add_evidence_artifact(
            after_run_dir,
            "loop-failure-evidence",
            "application/json",
            failure_rel,
            json!({ "artifact": "scenario_result", "scenario_id": "loop-failure" }),
        )
        .expect("evidence artifact linked");
        write_json(
            &after_run_dir.join("verdict.json"),
            &json!({
                "status": "failed",
                "summary": "loop fixture failure",
                "failures": [{ "kind": "scenario_assertion_failure", "path": failure_rel }],
                "evidence_refs": [failure_rel]
            }),
        )
        .expect("failed verdict");

        let proposal = execute_authoring_loop_step_from_path(&plan_path, "generate-proposal")
            .expect("proposal step executes");
        assert_eq!(proposal.status, "completed");
        assert!(proposal
            .generated_artifacts
            .iter()
            .any(|artifact| artifact.kind == "mutation-proposals"));
        assert!(after_run_dir.join("mutation/proposals.json").is_file());
        assert!(after_run_dir
            .join("mutation/classifications.json")
            .is_file());
        assert!(after_run_dir.join("mutation/patch-drafts.json").is_file());

        let plan = read_loop_plan_from_path(&plan_path);
        assert!(plan.steps.iter().all(|step| {
            step.id == "generate-proposal" || step.status == AuthoringLoopStepStatus::Completed
        }));
        let after_input = plan
            .steps
            .iter()
            .find(|step| step.id == "generate-proposal")
            .expect("proposal step")
            .inputs
            .first()
            .expect("proposal input");
        assert!(after_input.path.starts_with("runs/run-"));
        assert!(root
            .join("runs/authoring-loop-ledgers/temp-loop-execution/ledger.jsonl")
            .is_file());

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn loop_step_runner_persists_failed_status_when_execution_errors() {
        let root = unique_temp_dir("loop-step-runner-failure");
        write_loop_dry_run_project(&root);
        let plan_path = write_loop_execution_plan(&root);

        // Complete the compare-runs dependencies so the step can actually start.
        execute_authoring_loop_step_from_path(&plan_path, "run-baseline")
            .expect("baseline run step executes");
        let after = execute_authoring_loop_step_from_path(&plan_path, "run-after")
            .expect("after run step executes");

        // Remove the after run's verdict.json so the comparison executor errors
        // *after* the step has started. The run.json inputs still exist, so the
        // step is not preflight-blocked and genuinely begins executing.
        let after_run_dir = root
            .join(&after.generated_artifacts[0].path)
            .parent()
            .expect("after run dir")
            .to_path_buf();
        fs::remove_file(after_run_dir.join("verdict.json")).expect("remove verdict");

        let error = execute_authoring_loop_step_from_path(&plan_path, "compare-runs")
            .expect_err("compare step errors after starting");
        assert!(!error.to_string().is_empty());

        // The plan on disk must record the started step as failed, not pending,
        // so a later invocation sees the failure instead of rerunning blindly.
        let persisted = read_loop_plan_from_path(&plan_path);
        let compare = persisted
            .steps
            .iter()
            .find(|step| step.id == "compare-runs")
            .expect("compare step present");
        assert_eq!(compare.status, AuthoringLoopStepStatus::Failed);

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn loop_step_runner_blocks_later_step_kinds_before_execution_prs() {
        let root = unique_temp_dir("loop-step-runner-blocked-kind");
        write_loop_dry_run_project(&root);
        let plan_path = write_loop_dry_run_plan(&root, "loop_project");
        for path in [
            "runs/baseline/run.json",
            "runs/baseline/comparisons/run-comparison.json",
            "runs/baseline/mutation/proposal.json",
            "runs/baseline/mutation/review-decision-ledger.json",
            "runs/baseline/mutation/before.scene.json",
        ] {
            let path = root.join(path);
            fs::create_dir_all(path.parent().expect("parent")).expect("artifact dir");
            fs::write(path, "{}\n").expect("artifact");
        }

        let summary = execute_authoring_loop_step_from_path(&plan_path, "record-review")
            .expect("unsupported kind records blocked state");
        assert_eq!(summary.status, "blocked");
        assert!(summary
            .blocked_reasons
            .iter()
            .any(|reason| reason.contains("reserved for a later #306 PR unit")));
        let plan = read_loop_plan_from_path(&plan_path);
        assert_eq!(
            plan.steps
                .iter()
                .find(|step| step.id == "record-review")
                .expect("record-review step")
                .status,
            AuthoringLoopStepStatus::Blocked
        );

        fs::remove_dir_all(root).expect("fixture removed");
    }

