    #[test]
    fn project_asset_manifest_v1_validates_paths_files_and_hashes() {
        let root = unique_temp_dir("project-asset-manifest-valid");
        fs::create_dir_all(root.join("assets/sprites")).expect("sprites dir");
        fs::create_dir_all(root.join("assets/audio")).expect("audio dir");
        fs::write(root.join("assets/sprites/player.png"), b"png fixture").expect("sprite");
        fs::write(root.join("assets/audio/pickup.ogg"), b"ogg fixture").expect("audio");
        let sprite_hash =
            hash_project_asset_file(root.join("assets/sprites/player.png")).expect("sprite hashes");
        let audio_hash =
            hash_project_asset_file(root.join("assets/audio/pickup.ogg")).expect("audio hashes");

        let manifest = ProjectAssetManifest::from_json_str(
            &json!({
                "schemaVersion": "asset-manifest-v1",
                "id": "asset_integrity_fixture",
                "assets": [
                    {
                        "id": "player_sprite",
                        "type": "image",
                        "path": "assets/sprites/player.png",
                        "contentHash": sprite_hash,
                        "classification": "source_like",
                        "dimensions": { "width": 16, "height": 16 }
                    },
                    {
                        "id": "pickup_sound",
                        "type": "audio",
                        "path": "assets/audio/pickup.ogg",
                        "contentHash": audio_hash,
                        "classification": "source_like",
                        "durationMs": 240
                    }
                ]
            })
            .to_string(),
        )
        .expect("manifest parses");

        let report = manifest
            .validate_assets(&root)
            .expect("asset integrity validates");
        assert_eq!(report.manifest_id, "asset_integrity_fixture");
        assert_eq!(report.assets, 2);
        assert_eq!(report.source_like_assets, 2);
        assert_eq!(report.generated_assets, 0);
        assert_eq!(report.asset_types.get(&ProjectAssetType::Image), Some(&1));
        assert_eq!(report.asset_types.get(&ProjectAssetType::Audio), Some(&1));

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn project_asset_manifest_resolves_scene_asset_references_by_id_and_type() {
        let manifest = ProjectAssetManifest::from_json_str(
            &json!({
                "schemaVersion": "asset-manifest-v1",
                "id": "asset_reference_integrity_fixture",
                "assets": [
                    {
                        "id": "player_sprite",
                        "type": "image",
                        "path": "assets/sprites/player.png",
                        "contentHash": { "algorithm": "fnv1a64-file-v1", "value": "1111111111111111" },
                        "classification": "source_like",
                        "dimensions": { "width": 16, "height": 16 }
                    },
                    {
                        "id": "player_atlas",
                        "type": "sprite_atlas",
                        "path": "assets/atlases/player.json",
                        "contentHash": { "algorithm": "fnv1a64-file-v1", "value": "2222222222222222" },
                        "classification": "source_like",
                        "atlas": {
                            "imageAssetId": "player_sprite",
                            "frames": [{ "id": "idle", "rect": { "x": 0, "y": 0, "width": 16, "height": 16 } }]
                        }
                    },
                    {
                        "id": "spawn_audio",
                        "type": "audio",
                        "path": "assets/audio/spawn.ogg",
                        "contentHash": { "algorithm": "fnv1a64-file-v1", "value": "3333333333333333" },
                        "classification": "source_like",
                        "durationMs": 100
                    },
                    {
                        "id": "ground_tile",
                        "type": "image",
                        "path": "assets/tiles/ground.png",
                        "contentHash": { "algorithm": "fnv1a64-file-v1", "value": "4444444444444444" },
                        "classification": "source_like",
                        "dimensions": { "width": 16, "height": 16 }
                    }
                ]
            })
            .to_string(),
        )
        .expect("manifest parses");
        let scene: SceneDocument = serde_json::from_value(json!({
            "schemaVersion": "1",
            "id": "asset-ref-scene",
            "bounds": { "width": 64, "height": 32 },
            "entities": [{
                "id": "player",
                "sprite": { "color": "#5eead4", "asset": "player_sprite" },
                "components": {
                    "transform": { "x": 0, "y": 0 },
                    "velocity": { "x": 0, "y": 0 },
                    "size": { "width": 16, "height": 16 },
                    "controllable": true,
                    "animation": {
                        "mode": "sprite_frame",
                        "frameDuration": 2,
                        "frames": [{ "color": "#5eead4", "asset": "player_atlas" }],
                        "clips": [{ "id": "idle", "frameDuration": 2, "frames": [{ "color": "#2dd4bf", "asset": "player_sprite" }] }]
                    },
                    "audio": { "events": [{ "name": "spawn", "trigger": "scene_loaded", "asset": "spawn_audio" }] }
                }
            }],
            "tilemaps": [{
                "id": "level",
                "tileSize": { "width": 16, "height": 16 },
                "grid": { "width": 1, "height": 1 },
                "tiles": [{ "id": "ground", "color": "#334155", "asset": "ground_tile" }],
                "layers": [{ "id": "terrain", "data": ["ground"] }]
            }]
        }))
        .expect("scene parses");

        let report = manifest
            .validate_scene_references(&scene)
            .expect("scene refs resolve through project manifest");

        assert_eq!(report.manifest_id, "asset_reference_integrity_fixture");
        assert_eq!(report.scene_id, "asset-ref-scene");
        assert_eq!(report.resolved_refs.len(), 5);
        assert!(report.resolved_refs.iter().any(|reference| {
            reference.field == "scene entity player sprite asset"
                && reference.asset_id == "player_sprite"
                && reference.asset_type == ProjectAssetType::Image
        }));
        assert!(report.resolved_refs.iter().any(|reference| {
            reference.field == "scene entity player audio event spawn asset"
                && reference.asset_id == "spawn_audio"
                && reference.asset_type == ProjectAssetType::Audio
        }));
        assert!(report.resolved_refs.iter().any(|reference| {
            reference.field == "scene tilemap level tile ground asset"
                && reference.asset_id == "ground_tile"
                && reference.asset_type == ProjectAssetType::Image
        }));
        let serialized = serde_json::to_string(&report).expect("report serializes");
        assert!(serialized.contains("\"resolvedRefs\""));
        assert!(serialized.contains("\"assetType\":\"sprite_atlas\""));
    }

    #[test]
    fn project_asset_manifest_rejects_unknown_type_mismatch_and_remote_scene_refs() {
        let manifest = ProjectAssetManifest::from_json_str(
            &json!({
                "schemaVersion": "asset-manifest-v1",
                "id": "asset_reference_rejection_fixture",
                "assets": [
                    {
                        "id": "player_sprite",
                        "type": "image",
                        "path": "assets/sprites/player.png",
                        "contentHash": { "algorithm": "fnv1a64-file-v1", "value": "1111111111111111" },
                        "classification": "source_like",
                        "dimensions": { "width": 16, "height": 16 }
                    },
                    {
                        "id": "spawn_audio",
                        "type": "audio",
                        "path": "assets/audio/spawn.ogg",
                        "contentHash": { "algorithm": "fnv1a64-file-v1", "value": "2222222222222222" },
                        "classification": "source_like",
                        "durationMs": 100
                    }
                ]
            })
            .to_string(),
        )
        .expect("manifest parses");
        let scene_with_sprite = |asset: &str| -> SceneDocument {
            serde_json::from_value(json!({
                "schemaVersion": "1",
                "id": "asset-ref-rejected-scene",
                "bounds": { "width": 64, "height": 32 },
                "entities": [{
                    "id": "player",
                    "sprite": { "color": "#5eead4", "asset": asset },
                    "components": {
                        "transform": { "x": 0, "y": 0 },
                        "velocity": { "x": 0, "y": 0 },
                        "size": { "width": 16, "height": 16 },
                        "controllable": true
                    }
                }]
            }))
            .expect("scene parses")
        };

        let missing = manifest
            .validate_scene_references(&scene_with_sprite("missing_sprite"))
            .expect_err("unknown scene ref rejected");
        assert!(missing.to_string().contains("unknown project asset id"));

        let wrong_type = manifest
            .validate_scene_references(&scene_with_sprite("spawn_audio"))
            .expect_err("sprite ref to audio rejected");
        assert!(wrong_type.to_string().contains("expected one of"));

        let remote = manifest
            .validate_scene_references(&scene_with_sprite("https://example.com/player.png"))
            .expect_err("remote URL-like scene ref rejected");
        assert!(remote.to_string().contains("ASCII letters"));
    }

    #[test]
    fn project_asset_reference_integrity_reports_warnings_without_remote_fetch() {
        let root = unique_temp_dir("project-asset-reference-integrity-warnings");
        fs::create_dir_all(root.join("assets/sprites")).expect("sprites dir");
        fs::create_dir_all(root.join("assets/audio")).expect("audio dir");
        fs::write(root.join("assets/sprites/player.png"), b"sprite-v1").expect("sprite");
        fs::write(root.join("assets/audio/spawn.ogg"), b"audio").expect("audio");
        let sprite_hash =
            hash_project_asset_file(root.join("assets/sprites/player.png")).expect("sprite hash");
        let audio_hash =
            hash_project_asset_file(root.join("assets/audio/spawn.ogg")).expect("audio hash");
        fs::write(root.join("assets/sprites/player.png"), b"sprite-v2").expect("stale sprite");
        let manifest = ProjectAssetManifest::from_json_str(
            &json!({
                "schemaVersion": "asset-manifest-v1",
                "id": "warning_manifest",
                "assets": [
                    {
                        "id": "player_sprite",
                        "type": "image",
                        "path": "assets/sprites/player.png",
                        "contentHash": sprite_hash,
                        "classification": "source_like",
                        "dimensions": { "width": 16, "height": 16 }
                    },
                    {
                        "id": "spawn_audio",
                        "type": "audio",
                        "path": "assets/audio/spawn.ogg",
                        "contentHash": audio_hash,
                        "classification": "source_like",
                        "durationMs": 100
                    },
                    {
                        "id": "missing_sprite",
                        "type": "image",
                        "path": "assets/sprites/missing.png",
                        "contentHash": { "algorithm": "fnv1a64-file-v1", "value": "1111111111111111" },
                        "classification": "source_like",
                        "dimensions": { "width": 16, "height": 16 }
                    }
                ]
            })
            .to_string(),
        )
        .expect("manifest parses");
        let scene: SceneDocument = serde_json::from_value(json!({
            "schemaVersion": "1",
            "id": "warning-scene",
            "bounds": { "width": 64, "height": 32 },
            "entities": [
                {
                    "id": "player",
                    "sprite": { "color": "#5eead4", "asset": "player_sprite" },
                    "components": {
                        "transform": { "x": 0, "y": 0 },
                        "velocity": { "x": 0, "y": 0 },
                        "size": { "width": 16, "height": 16 },
                        "controllable": true,
                        "audio": { "events": [{ "name": "spawn", "trigger": "scene_loaded", "asset": "missing_audio" }] }
                    }
                },
                {
                    "id": "remote",
                    "sprite": { "color": "#f97316", "asset": "https://example.com/remote.png" },
                    "components": {
                        "transform": { "x": 0, "y": 0 },
                        "velocity": { "x": 0, "y": 0 },
                        "size": { "width": 16, "height": 16 },
                        "controllable": false
                    }
                },
                {
                    "id": "wrong_type",
                    "sprite": { "color": "#facc15", "asset": "spawn_audio" },
                    "components": {
                        "transform": { "x": 0, "y": 0 },
                        "velocity": { "x": 0, "y": 0 },
                        "size": { "width": 16, "height": 16 },
                        "controllable": false
                    }
                },
                {
                    "id": "missing_file",
                    "sprite": { "color": "#94a3b8", "asset": "missing_sprite" },
                    "components": {
                        "transform": { "x": 0, "y": 0 },
                        "velocity": { "x": 0, "y": 0 },
                        "size": { "width": 16, "height": 16 },
                        "controllable": false
                    }
                }
            ]
        }))
        .expect("scene parses");

        let report = manifest
            .check_scene_reference_integrity(&scene, &root)
            .expect("warning report builds without fetching remote assets");

        assert_eq!(report.schema_version, "asset-reference-integrity-v1");
        assert_eq!(report.resolved_refs.len(), 0);
        assert!(report
            .warnings
            .iter()
            .any(|warning| warning.kind == "stale_asset_hash"));
        assert!(report
            .warnings
            .iter()
            .any(|warning| warning.kind == "missing_asset_ref"));
        assert!(report
            .warnings
            .iter()
            .any(|warning| warning.kind == "missing_asset_file"));
        assert!(report
            .warnings
            .iter()
            .any(|warning| warning.kind == "invalid_asset_type"));
        assert!(report
            .warnings
            .iter()
            .any(|warning| warning.kind == "invalid_asset_id"));
        assert!(!root.join("assets/remote.png").exists());

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn project_asset_manifest_v1_rejects_invalid_paths_roots_extensions_and_hashes() {
        let root = unique_temp_dir("project-asset-manifest-invalid");
        fs::create_dir_all(root.join("assets/sprites")).expect("sprites dir");
        fs::create_dir_all(root.join("runs/previews")).expect("runs dir");
        fs::write(root.join("assets/sprites/player.png"), b"png fixture").expect("sprite");
        fs::write(root.join("runs/previews/player.png"), b"generated fixture").expect("generated");
        let sprite_hash =
            hash_project_asset_file(root.join("assets/sprites/player.png")).expect("sprite hashes");
        let generated_hash = hash_project_asset_file(root.join("runs/previews/player.png"))
            .expect("generated hashes");

        let manifest_with_path =
            |path: &str,
             asset_type: ProjectAssetType,
             hash: ProjectAssetContentHash,
             classification: ProjectAssetClassification| {
                ProjectAssetManifest::from_json_str(
                    &json!({
                        "schemaVersion": "asset-manifest-v1",
                        "id": "invalid_asset_fixture",
                        "assets": [{
                            "id": "asset",
                            "type": asset_type,
                            "path": path,
                            "contentHash": hash,
                            "classification": classification
                        }]
                    })
                    .to_string(),
                )
                .expect("manifest parses")
            };

        let absolute = manifest_with_path(
            "/tmp/player.png",
            ProjectAssetType::Image,
            sprite_hash.clone(),
            ProjectAssetClassification::SourceLike,
        );
        let rejected = absolute
            .validate_assets(&root)
            .expect_err("absolute path rejected");
        assert!(rejected.to_string().contains("must be relative"));

        let escape = manifest_with_path(
            "../player.png",
            ProjectAssetType::Image,
            sprite_hash.clone(),
            ProjectAssetClassification::SourceLike,
        );
        let rejected = escape
            .validate_assets(&root)
            .expect_err("path escape rejected");
        assert!(rejected.to_string().contains("project root"));

        let hidden = manifest_with_path(
            ".omx/player.png",
            ProjectAssetType::Image,
            sprite_hash.clone(),
            ProjectAssetClassification::SourceLike,
        );
        let rejected = hidden
            .validate_assets(&root)
            .expect_err("hidden root rejected");
        assert!(rejected.to_string().contains("hidden"));

        let generated_source = manifest_with_path(
            "runs/previews/player.png",
            ProjectAssetType::Image,
            generated_hash.clone(),
            ProjectAssetClassification::SourceLike,
        );
        let rejected = generated_source
            .validate_assets(&root)
            .expect_err("source generated root rejected");
        assert!(rejected.to_string().contains("generated root runs"));

        let unsupported = manifest_with_path(
            "assets/sprites/player.txt",
            ProjectAssetType::Image,
            sprite_hash.clone(),
            ProjectAssetClassification::SourceLike,
        );
        let rejected = unsupported
            .validate_assets(&root)
            .expect_err("unsupported extension rejected");
        assert!(rejected.to_string().contains("unsupported extension"));

        let missing = manifest_with_path(
            "assets/sprites/missing.png",
            ProjectAssetType::Image,
            sprite_hash.clone(),
            ProjectAssetClassification::SourceLike,
        );
        let rejected = missing
            .validate_assets(&root)
            .expect_err("missing rejected");
        assert!(rejected.to_string().contains("missing file"));

        let mut stale_hash = sprite_hash.clone();
        stale_hash.value = "0000000000000000".to_string();
        let stale = manifest_with_path(
            "assets/sprites/player.png",
            ProjectAssetType::Image,
            stale_hash,
            ProjectAssetClassification::SourceLike,
        );
        let rejected = stale
            .validate_assets(&root)
            .expect_err("stale hash rejected");
        assert!(rejected.to_string().contains("contentHash mismatch"));

        let generated = manifest_with_path(
            "runs/previews/player.png",
            ProjectAssetType::Image,
            generated_hash,
            ProjectAssetClassification::Generated,
        );
        generated
            .validate_assets(&root)
            .expect("generated classified asset may live under generated root");

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn project_asset_manifest_v1_rejects_duplicate_ids_and_paths() {
        let root = unique_temp_dir("project-asset-manifest-duplicates");
        fs::create_dir_all(root.join("assets/sprites")).expect("sprites dir");
        fs::write(root.join("assets/sprites/player.png"), b"png fixture").expect("sprite");
        fs::write(root.join("assets/sprites/player-copy.png"), b"png fixture").expect("copy");
        let player_hash =
            hash_project_asset_file(root.join("assets/sprites/player.png")).expect("player hashes");
        let copy_hash = hash_project_asset_file(root.join("assets/sprites/player-copy.png"))
            .expect("copy hashes");

        let duplicate_id = ProjectAssetManifest::from_json_str(
            &json!({
                "schemaVersion": "asset-manifest-v1",
                "id": "duplicate_id_fixture",
                "assets": [
                    { "id": "player", "type": "image", "path": "assets/sprites/player.png", "contentHash": player_hash, "classification": "source_like" },
                    { "id": "player", "type": "image", "path": "assets/sprites/player-copy.png", "contentHash": copy_hash, "classification": "source_like" }
                ]
            })
            .to_string(),
        )
        .expect("manifest parses");
        let rejected = duplicate_id
            .validate_assets(&root)
            .expect_err("duplicate id rejected");
        assert!(rejected
            .to_string()
            .contains("duplicate project asset manifest asset id"));

        let path_hash =
            hash_project_asset_file(root.join("assets/sprites/player.png")).expect("path hashes");
        let duplicate_path = ProjectAssetManifest::from_json_str(
            &json!({
                "schemaVersion": "asset-manifest-v1",
                "id": "duplicate_path_fixture",
                "assets": [
                    { "id": "player", "type": "image", "path": "assets/sprites/player.png", "contentHash": path_hash, "classification": "source_like" },
                    { "id": "player_copy", "type": "image", "path": "assets/sprites/player.png", "contentHash": path_hash, "classification": "source_like" }
                ]
            })
            .to_string(),
        )
        .expect("manifest parses");
        let rejected = duplicate_path
            .validate_assets(&root)
            .expect_err("duplicate path rejected");
        assert!(rejected
            .to_string()
            .contains("duplicate project asset manifest asset path"));

        fs::remove_dir_all(root).expect("fixture removed");
    }

    fn transition_test_scene(scene_id: &str, transitions: serde_json::Value) -> serde_json::Value {
        let mut scene = json!({
            "schemaVersion": "1",
            "id": scene_id,
            "bounds": { "width": 64, "height": 64 },
            "entities": [{
                "id": "player",
                "sprite": { "color": "#5eead4" },
                "components": {
                    "transform": { "x": 0, "y": 0 },
                    "velocity": { "x": 0, "y": 0 },
                    "size": { "width": 16, "height": 16 },
                    "controllable": true
                }
            }]
        });
        scene["sceneTransitions"] = transitions;
        scene
    }

    fn write_transition_manifest_fixture(root: &Path, main_scene: serde_json::Value) {
        fs::create_dir_all(root.join("scenes")).expect("scenes dir");
        fs::create_dir_all(root.join("seeds")).expect("seeds dir");
        fs::create_dir_all(root.join("assets")).expect("assets dir");
        fs::create_dir_all(root.join("runs")).expect("runs dir");
        fs::write(
            root.join("scenes/main.scene.json"),
            serde_json::to_string_pretty(&main_scene).expect("main scene serializes"),
        )
        .expect("main scene written");
        fs::write(
            root.join("scenes/level-2.scene.json"),
            serde_json::to_string_pretty(&transition_test_scene("level-2", json!([])))
                .expect("level scene serializes"),
        )
        .expect("level scene written");
        fs::write(root.join("seeds/smoke.yaml"), "id: smoke\n").expect("seed written");
        fs::write(
            root.join(PROJECT_MANIFEST_FILE_NAME),
            serde_json::to_string_pretty(&json!({
                "schemaVersion": "project-manifest-v1",
                "project": { "id": "transition_fixture", "name": "Transition Fixture" },
                "scenes": [
                    { "id": "main", "path": "scenes/main.scene.json" },
                    { "id": "level_2", "path": "scenes/level-2.scene.json" }
                ],
                "seeds": [{ "id": "smoke", "path": "seeds/smoke.yaml" }],
                "scenarioPacks": [],
                "assetRoots": ["assets"],
                "runsRoot": "runs",
                "generated": { "roots": ["runs"] }
            }))
            .expect("manifest serializes"),
        )
        .expect("manifest written");
    }

    #[test]
    fn scene_transition_v1_validates_manifest_declared_targets() {
        let root = unique_temp_dir("scene-transition-manifest-valid");
        write_transition_manifest_fixture(
            &root,
            transition_test_scene(
                "main",
                json!([{ "id": "to_level_2", "toScene": "scenes/level-2.scene.json", "label": "Level 2" }]),
            ),
        );

        let manifest = ProjectManifest::from_path(root.join(PROJECT_MANIFEST_FILE_NAME))
            .expect("manifest with declared transition validates");
        assert_eq!(manifest.scenes.len(), 2);
        let main_scene = read_scene(root.join("scenes/main.scene.json")).expect("scene validates");
        assert_eq!(main_scene.scene_transitions[0].id, "to_level_2");
        assert_eq!(
            main_scene.scene_transitions[0].to_scene,
            "scenes/level-2.scene.json"
        );
    }

    #[test]
    fn scene_transition_v1_rejects_undeclared_manifest_targets() {
        let root = unique_temp_dir("scene-transition-manifest-undeclared");
        write_transition_manifest_fixture(
            &root,
            transition_test_scene(
                "main",
                json!([{ "id": "to_secret", "toScene": "scenes/secret.scene.json" }]),
            ),
        );
        fs::write(
            root.join("scenes/secret.scene.json"),
            serde_json::to_string_pretty(&transition_test_scene("secret", json!([])))
                .expect("secret scene serializes"),
        )
        .expect("secret scene written");

        let rejected = ProjectManifest::from_path(root.join(PROJECT_MANIFEST_FILE_NAME))
            .expect_err("undeclared transition target rejected");
        let rejected = format!("{rejected:#}");
        assert!(rejected.contains("transition to_secret toScene scenes/secret.scene.json"));
        assert!(rejected.contains("not declared in project manifest scenes"));
    }

    #[test]
    fn scene_transition_v1_rejects_unsafe_target_paths() {
        let scene: SceneDocument = serde_json::from_value(transition_test_scene(
            "main",
            json!([{ "id": "escape", "toScene": "../secret.scene.json" }]),
        ))
        .expect("unsafe transition scene parses");
        let rejected = validate_scene(&scene).expect_err("unsafe transition path rejected");
        assert!(rejected
            .to_string()
            .contains("scene transition escape toScene must stay inside the project root"));
    }

