    #[test]
    fn rejects_invalid_scenario_assertion() {
        let invalid = r#"
id: platformer.v0
title: Platformer Harness Seed
goal: Prove the initial Ouroforge run artifact contract.
constraints:
  target: file-harness
acceptance:
  - Validate the seed schema.
scenarios:
  - id: probe-smoke
    description: Invalid assertion.
    assertions:
      - world_state:
          path: tick > 0
          equals: true
"#;

        let error = Seed::from_yaml_str(invalid).expect_err("invalid assertion fails");
        assert!(error.to_string().contains("path is invalid"));
    }

    #[test]
    fn parses_bounded_richer_assertion_schema() {
        let valid = r#"
id: assertion-model.v1
title: Assertion Model Fixture
goal: Validate bounded assertion schema.
constraints:
  target: file-harness
acceptance:
  - Validate richer assertions.
scenarios:
  - id: assertion-smoke
    description: Valid richer assertions.
    assertions:
      - world_state:
          path: player.health
          greaterThan: 0
      - runtime_events:
          path: events
          countGreaterThan: 0
      - world_flags:
          path: coin_collected
          equals: true
      - physics_evidence:
          path: grounded.player
          equals: true
      - frame_stats:
          path: fixedDeltaMs
          lessThan: 33
      - performance_metrics:
          path: ScriptDuration
          exists: true
      - console_errors:
          path: logs
          countEquals: 0
      - collision_evidence:
          path: pairs
          contains: goal:player
      - audio_evidence:
          path: events.0.kind
          notEquals: missing
      - animation_evidence:
          path: tracks.idle
          equals: true
"#;

        let seed = Seed::from_yaml_str(valid).expect("richer assertion schema parses");

        assert_eq!(seed.scenarios[0].assertions.len(), 10);
    }

    #[test]
    fn rejects_unbounded_or_ambiguous_assertion_schema() {
        let arbitrary_expression = r#"
id: assertion-model.v1
title: Assertion Model Fixture
goal: Reject arbitrary assertion schema.
constraints:
  target: file-harness
acceptance:
  - Reject arbitrary assertions.
scenarios:
  - id: assertion-smoke
    description: Invalid expression assertion.
    assertions:
      - world_state:
          path: player.health
          expression: player.health > 0
"#;
        let error = Seed::from_yaml_str(arbitrary_expression).expect_err("expression field fails");
        assert!(error.to_string().contains("failed to parse Seed YAML"));

        let multiple_operators = r#"
id: assertion-model.v1
title: Assertion Model Fixture
goal: Reject ambiguous assertion schema.
constraints:
  target: file-harness
acceptance:
  - Reject ambiguous assertions.
scenarios:
  - id: assertion-smoke
    description: Invalid multi-operator assertion.
    assertions:
      - world_state:
          path: player.health
          equals: 1
          greaterThan: 0
"#;
        let error = Seed::from_yaml_str(multiple_operators).expect_err("multiple operators fail");
        assert!(error
            .to_string()
            .contains("must define exactly one bounded assertion operator"));
    }

    #[test]
    fn accepts_contains_type_event_assertion_and_rejects_empty() {
        let valid = r#"
id: assertion-model.v1
title: Assertion Model Fixture
goal: Accept a typed event assertion.
constraints:
  target: file-harness
acceptance:
  - Accept containsType assertions.
scenarios:
  - id: assertion-smoke
    description: Assert a concrete runtime event type.
    assertions:
      - runtime_events:
          path: events
          containsType: runtime.animation.state
"#;
        let seed = Seed::from_yaml_str(valid).expect("containsType assertion validates");
        let assertion = &seed.scenarios[0].assertions[0];
        let ScenarioAssertion::RuntimeEvents { runtime_events } = assertion else {
            panic!("expected runtime_events assertion");
        };
        assert_eq!(
            runtime_events.contains_type.as_deref(),
            Some("runtime.animation.state")
        );

        let empty = r#"
id: assertion-model.v1
title: Assertion Model Fixture
goal: Reject an empty typed event assertion.
constraints:
  target: file-harness
acceptance:
  - Reject empty containsType assertions.
scenarios:
  - id: assertion-smoke
    description: Reject an empty event type.
    assertions:
      - runtime_events:
          path: events
          containsType: "  "
"#;
        let error = Seed::from_yaml_str(empty).expect_err("empty containsType fails");
        assert!(error.to_string().contains("containsType must not be empty"));
    }

    #[test]
    fn parses_visual_checkpoint_step_schema() {
        let valid = r#"
id: visual-hooks.v1
title: Visual Hooks Fixture
goal: Validate visual checkpoint step schema.
constraints:
  target: file-harness
acceptance:
  - Capture named visual checkpoints.
scenarios:
  - id: visual-smoke
    description: Visual checkpoint fixture.
    steps:
      - visualCheckpoint:
          id: after-load
          baseline:
            id: baseline-a
            width: 320
            height: 180
          threshold:
            maxDimensionDelta: 0
"#;

        let seed = Seed::from_yaml_str(valid).expect("visual checkpoint seed parses");

        assert!(matches!(
            &seed.scenarios[0].steps[0],
            ScenarioStep::VisualCheckpoint {
                visual_checkpoint
            } if visual_checkpoint.id == "after-load" && visual_checkpoint.threshold.is_some()
        ));
    }

