    #[test]
    fn run_transaction_provenance_reads_passed_transaction_artifact() {
        let temp = unique_temp_dir("ouroforge-run-provenance-model-test");
        fs::create_dir_all(&temp).expect("temp dir exists");
        let scene_path = temp.join("scene.json");
        fs::write(
            &scene_path,
            include_str!("../../../examples/game-runtime/scene.json"),
        )
        .expect("scene written");
        let transaction = preview_scene_edit_transaction(
            &scene_path,
            SceneEdit {
                entity_id: "player".to_string(),
                path: "components.transform.x".to_string(),
                value: json!(48),
            },
        )
        .expect("transaction previews");
        let transaction_path = temp.join("transaction.json");
        write_scene_edit_transaction_artifact(&transaction_path, &transaction)
            .expect("transaction written");
        let provenance =
            run_transaction_provenance_from_artifact(&transaction_path).expect("provenance reads");
        assert_eq!(provenance.transaction_id, transaction.id);
        assert_eq!(provenance.scene_path, scene_path.to_string_lossy());
        assert_eq!(provenance.before_scene_hash, transaction.before_scene_hash);
        assert_eq!(
            provenance.after_scene_hash,
            transaction.after_scene_hash.expect("after hash exists")
        );
        fs::remove_dir_all(temp).ok();
    }

    #[test]
    fn run_transaction_provenance_rejects_failed_transaction_artifact() {
        let temp = unique_temp_dir("ouroforge-run-provenance-failed-test");
        fs::create_dir_all(&temp).expect("temp dir exists");
        let scene_path = temp.join("scene.json");
        fs::write(
            &scene_path,
            include_str!("../../../examples/game-runtime/scene.json"),
        )
        .expect("scene written");
        let transaction = preview_scene_edit_transaction(
            &scene_path,
            SceneEdit {
                entity_id: "player".to_string(),
                path: "components.size.width".to_string(),
                value: json!(0),
            },
        )
        .expect("transaction previews");
        let transaction_path = temp.join("failed-transaction.json");
        write_scene_edit_transaction_artifact(&transaction_path, &transaction)
            .expect("transaction written");
        let error = run_transaction_provenance_from_artifact(&transaction_path)
            .expect_err("failed transaction rejected");
        assert!(error.to_string().contains("requires a passed transaction"));
        fs::remove_dir_all(temp).ok();
    }

    #[test]
    fn project_run_metadata_records_manifest_scene_hashes_and_pack_context() {
        let root = unique_temp_dir("project-run-metadata");
        let project = root.join("project");
        create_minimal_2d_project_scaffold(&project).expect("project scaffolded");
        let seed_path = project.join("seeds/platformer.yaml");
        let runs_root = root.join("runs");
        let artifacts = create_run(&seed_path, &runs_root).expect("legacy run created first");
        let metadata = project_run_metadata_from_manifest(
            project.join("ouroforge.project.json"),
            &seed_path,
            Some("smoke"),
        )
        .expect("metadata resolves");
        assert_eq!(metadata.id, "minimal_2d");
        assert_eq!(metadata.seed_path, "seeds/platformer.yaml");
        assert_eq!(metadata.scenes.len(), 1);
        assert_eq!(metadata.scenes[0].path, "scenes/main.scene.json");
        assert_eq!(
            metadata.scenes[0].hash.algorithm,
            "fnv1a64-canonical-json-v1"
        );
        assert_eq!(metadata.manifest_hash.algorithm, "fnv1a64-file-v1");
        assert_eq!(
            metadata.scenario_pack.as_ref().unwrap().scenario_ids,
            vec!["scaffold-smoke".to_string()]
        );

        bind_run_project_metadata(&artifacts.run_dir, metadata).expect("metadata bound");
        let run = read_json_value(artifacts.run_dir.join("run.json")).expect("run reads");
        assert_eq!(run["project"]["id"], "minimal_2d");
        assert_eq!(run["project"]["scenarioPack"]["id"], "smoke");
        assert!(
            run["project"]["manifestHash"]["value"]
                .as_str()
                .unwrap()
                .len()
                == 16
        );
        let ledger = read_ledger_events(&artifacts.run_dir).expect("ledger reads");
        assert!(ledger
            .iter()
            .any(|event| event["event"] == "run.project_bound"));

        fs::remove_dir_all(root).ok();
    }

    #[test]
    fn run_command_context_model_records_legacy_run_defaults() {
        let (root, artifacts) = create_test_run("run-command-context-legacy");
        let run = read_json_value(artifacts.run_dir.join("run.json")).expect("run reads");
        let context: RunCommandContext = serde_json::from_value(
            run.get("run_command_context")
                .cloned()
                .expect("command context present"),
        )
        .expect("command context parses");

        assert_eq!(context.schema_version, "run-command-context-v1");
        assert_eq!(context.workers, 1);
        assert!(context.seed_path.ends_with("seed.yaml"));
        assert!(context.runs_root.ends_with("runs"));
        assert_eq!(context.project_root, None);
        assert_eq!(context.manifest_path, None);
        assert_eq!(context.scenario_pack_id, None);
        assert_eq!(context.runtime_target, "local-static-browser");
        assert_eq!(context.browser_boundary, "openchrome_cdp");
        assert_eq!(context.cdp_transport, "chrome_devtools_protocol");
        assert!(context.argv.contains(&"--workers".to_string()));
        assert!(context
            .command
            .contains("cargo run -p ouroforge-cli -- run"));
        assert!(!serde_json::to_string(&context)
            .expect("context serializes")
            .to_ascii_lowercase()
            .contains("secret"));

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn run_command_context_model_updates_project_runs_without_secret_env() {
        let root = unique_temp_dir("run-command-context-project");
        let project = root.join("project");
        create_minimal_2d_project_scaffold(&project).expect("project scaffolded");
        let manifest_path = project.join("ouroforge.project.json");
        let seed_path = project.join("seeds/platformer.yaml");
        let runs_root = root.join("runs");
        fs::create_dir_all(&runs_root).expect("runs root created");
        let artifacts = create_run(&seed_path, &runs_root).expect("run created");
        let metadata =
            project_run_metadata_from_manifest(&manifest_path, &seed_path, Some("smoke"))
                .expect("project metadata created");
        bind_run_project_metadata(&artifacts.run_dir, metadata.clone()).expect("project bound");
        let context = run_command_context_for_run(
            &seed_path,
            &runs_root,
            3,
            Some(&metadata),
            Some(Path::new("runs/manual/transactions/scene-edit.json")),
        );
        bind_run_command_context(&artifacts.run_dir, context.clone()).expect("context bound");

        let run = read_json_value(artifacts.run_dir.join("run.json")).expect("run reads");
        let stored: RunCommandContext = serde_json::from_value(
            run.get("run_command_context")
                .cloned()
                .expect("command context present"),
        )
        .expect("command context parses");
        assert_eq!(stored.workers, 3);
        assert_eq!(
            stored.project_root.as_deref(),
            Some(metadata.project_root.as_str())
        );
        assert_eq!(
            stored.manifest_path.as_deref(),
            Some(metadata.manifest_path.as_str())
        );
        assert_eq!(stored.scenario_pack_id.as_deref(), Some("smoke"));
        assert_eq!(
            stored.transaction_path.as_deref(),
            Some("runs/manual/transactions/scene-edit.json")
        );
        assert!(stored.command.contains("--project"));
        assert!(stored.command.contains("--scenario-pack smoke"));
        assert!(stored
            .command
            .contains("--transaction runs/manual/transactions/scene-edit.json"));
        assert!(stored.environment_hints.iter().all(|hint| {
            let lower = hint.to_ascii_lowercase();
            !lower.contains("token") && !lower.contains("password") && !lower.contains("secret")
        }));
        let events = read_ledger_events(&artifacts.run_dir).expect("ledger reads");
        assert!(events.iter().any(|event| {
            event["event"] == "run.command_context_recorded"
                && event["payload"]["workers"] == json!(3)
                && event["payload"]["scenario_pack_id"] == json!("smoke")
        }));

        fs::remove_dir_all(root).expect("fixture removed");
    }

