        assert_eq!(
            scene
                .component_defaults
                .as_ref()
                .and_then(|defaults| defaults.status.as_ref())
                .and_then(|status| status.hit_points),
            Some(1)
        );

        let player = &scene.entities[0].components;
        assert_eq!(
            player.status.as_ref().expect("player status").states,
            vec!["grounded".to_string()]
        );
